import { useState } from "react"
import JSZip from "jszip"
import { AIImageProcessor, PHOTO_SIZE_PRESETS, type PhotoSize } from "../services/aiImageProcessor"

const MM_PER_INCH = 25.4;

export default function BulkProcessing() {
    const [files, setFiles] = useState<File[]>([])
    const [processedFiles, setProcessedFiles] = useState<{ original: File, processed: Blob, name: string }[]>([])
    const [progress, setProgress] = useState(0)
    const [isProcessing, setIsProcessing] = useState(false)
    const [hasProcessed, setHasProcessed] = useState(false)

    // Photo size state
    const [selectedPresetIdx, setSelectedPresetIdx] = useState(0)
    const [customWidthMm, setCustomWidthMm] = useState(35)
    const [customHeightMm, setCustomHeightMm] = useState(45)
    const [useCustom, setUseCustom] = useState(false)
    const [unit, setUnit] = useState<"mm" | "inch">("mm")

    const getPhotoSize = (): PhotoSize => {
        if (useCustom) {
            return {
                label: "Custom",
                widthMm: customWidthMm,
                heightMm: customHeightMm,
                widthInch: parseFloat((customWidthMm / MM_PER_INCH).toFixed(2)),
                heightInch: parseFloat((customHeightMm / MM_PER_INCH).toFixed(2)),
            }
        }
        return PHOTO_SIZE_PRESETS[selectedPresetIdx]
    }

    const handleUpload = (e: any) => {
        if (e.target.files) {
            setFiles(Array.from(e.target.files))
            setProcessedFiles([])
            setHasProcessed(false)
            setProgress(0)
        }
    }

    const processImages = async () => {
        if (files.length === 0) return;

        setIsProcessing(true);
        const results = [];
        const photoSize = getPhotoSize();

        const processor = new AIImageProcessor();
        await processor.initialize();

        for (let i = 0; i < files.length; i++) {
            const file = files[i];

            try {
                const processedBlob = await processor.processImage(file, photoSize);
                results.push({ original: file, processed: processedBlob, name: file.name });
            } catch (err) {
                console.error(`Failed to process ${file.name}:`, err);
                results.push({ original: file, processed: file, name: file.name });
            }

            setProgress(((i + 1) / files.length) * 100)
        }

        setProcessedFiles(results);
        setHasProcessed(true);
        setIsProcessing(false);
    }

    const downloadZip = async () => {
        const zip = new JSZip();

        processedFiles.forEach(({ name, processed }) => {
            zip.file(name, processed);
        });

        const content = await zip.generateAsync({ type: "blob" })
        const url = URL.createObjectURL(content)

        const a = document.createElement("a")
        a.href = url
        a.download = "processed-images.zip"
        a.click()
    }

    const displayW = (size: PhotoSize) => unit === "mm" ? `${size.widthMm}mm` : `${size.widthInch}"`
    const displayH = (size: PhotoSize) => unit === "mm" ? `${size.heightMm}mm` : `${size.heightInch}"`

    return (
        <div className="p-10 max-w-4xl mx-auto">
            <h1 className="text-3xl font-bold mb-6 text-gray-800">
                Bulk Image Processor
            </h1>

            <div className="bg-white p-6 rounded-lg shadow-sm border border-gray-200">
                <p className="text-gray-600 mb-4">
                    Upload multiple photos to automatically remove backgrounds, adjust lighting, and crop to your chosen size. Preview before downloading. Facial features are strictly preserved.
                </p>

                {/* ── Photo Size Selector ── */}
                <div className="mb-6 border rounded-lg p-4 bg-gray-50">
                    <div className="flex items-center justify-between mb-3">
                        <h4 className="text-sm font-semibold text-gray-700">Photo Size</h4>
                        <div className="flex items-center border rounded-md overflow-hidden text-xs">
                            <button
                                onClick={() => setUnit("mm")}
                                className={`px-3 py-1 font-medium transition-colors ${unit === "mm" ? "bg-blue-600 text-white" : "bg-white text-gray-700 hover:bg-gray-100"}`}
                            >mm</button>
                            <button
                                onClick={() => setUnit("inch")}
                                className={`px-3 py-1 font-medium transition-colors ${unit === "inch" ? "bg-blue-600 text-white" : "bg-white text-gray-700 hover:bg-gray-100"}`}
                            >inch</button>
                        </div>
                    </div>

                    <div className="grid grid-cols-3 gap-2 mb-3">
                        {PHOTO_SIZE_PRESETS.map((preset, idx) => (
                            <button
                                key={idx}
                                onClick={() => { setSelectedPresetIdx(idx); setUseCustom(false); }}
                                className={`p-2 rounded-md border text-center text-xs transition-all
                                    ${!useCustom && selectedPresetIdx === idx
                                        ? "border-blue-500 bg-blue-50 ring-1 ring-blue-500 font-semibold"
                                        : "hover:bg-gray-100 border-gray-200"}`}
                            >
                                <span className="block font-medium text-gray-800">{preset.label}</span>
                                <span className="text-gray-500">{displayW(preset)} × {displayH(preset)}</span>
                            </button>
                        ))}
                    </div>

                    <div className="pt-2 border-t border-gray-200">
                        <button
                            onClick={() => setUseCustom(true)}
                            className={`text-xs font-medium mb-2 ${useCustom ? "text-blue-600" : "text-gray-500 hover:text-gray-800"}`}
                        >
                            ✏️ Custom Size
                        </button>
                        {useCustom && (
                            <div className="flex items-center gap-2">
                                <div className="flex-1">
                                    <label className="text-[10px] uppercase text-gray-400 tracking-wider">Width ({unit})</label>
                                    <input
                                        type="number"
                                        min={10}
                                        value={unit === "mm" ? customWidthMm : parseFloat((customWidthMm / MM_PER_INCH).toFixed(2))}
                                        onChange={(e) => {
                                            const v = parseFloat(e.target.value) || 10;
                                            setCustomWidthMm(unit === "mm" ? v : Math.round(v * MM_PER_INCH));
                                        }}
                                        className="w-full border rounded px-2 py-1 text-sm"
                                    />
                                </div>
                                <span className="text-gray-400 mt-4">×</span>
                                <div className="flex-1">
                                    <label className="text-[10px] uppercase text-gray-400 tracking-wider">Height ({unit})</label>
                                    <input
                                        type="number"
                                        min={10}
                                        value={unit === "mm" ? customHeightMm : parseFloat((customHeightMm / MM_PER_INCH).toFixed(2))}
                                        onChange={(e) => {
                                            const v = parseFloat(e.target.value) || 10;
                                            setCustomHeightMm(unit === "mm" ? v : Math.round(v * MM_PER_INCH));
                                        }}
                                        className="w-full border rounded px-2 py-1 text-sm"
                                    />
                                </div>
                            </div>
                        )}
                    </div>
                </div>

                {/* ── File input ── */}
                <div className="mb-6">
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                        Select Images
                    </label>
                    <input
                        type="file"
                        multiple
                        accept="image/*"
                        onChange={handleUpload}
                        className="block w-full text-sm text-gray-500
              file:mr-4 file:py-2 file:px-4
              file:rounded-md file:border-0
              file:text-sm file:font-semibold
              file:bg-blue-50 file:text-blue-700
              hover:file:bg-blue-100"
                    />
                </div>

                {files.length > 0 && !hasProcessed && !isProcessing && (
                    <div className="mb-6">
                        <p className="text-sm text-gray-600 mb-2">{files.length} files selected.</p>
                        <button
                            onClick={processImages}
                            className="px-6 py-2 bg-blue-600 text-white rounded-md font-medium hover:bg-blue-700 transition-colors"
                        >
                            Process {files.length} Images
                        </button>
                    </div>
                )}

                {isProcessing && (
                    <div className="mt-6">
                        <div className="flex justify-between mb-1">
                            <span className="text-sm font-medium text-blue-700">Processing...</span>
                            <span className="text-sm font-medium text-blue-700">{progress.toFixed(0)}%</span>
                        </div>
                        <div className="w-full bg-gray-200 rounded-full h-2.5">
                            <div
                                className="bg-blue-600 h-2.5 rounded-full transition-all duration-300"
                                style={{ width: `${progress}%` }}
                            ></div>
                        </div>
                    </div>
                )}

                {hasProcessed && processedFiles.length > 0 && (
                    <div className="mt-8 space-y-6">
                        <div className="flex items-center justify-between border-b pb-4">
                            <div>
                                <h3 className="text-xl font-semibold text-gray-800">Preview Processed Images</h3>
                                <p className="text-xs text-gray-500">
                                    Size: {displayW(getPhotoSize())} × {displayH(getPhotoSize())} ({getPhotoSize().label})
                                </p>
                            </div>
                            <button
                                onClick={downloadZip}
                                className="px-6 py-2 bg-green-600 text-white rounded-md font-medium hover:bg-green-700 transition-colors"
                            >
                                Download ZIP Archive
                            </button>
                        </div>

                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 max-h-[600px] overflow-y-auto pr-2">
                            {processedFiles.map((pf, index) => (
                                <div key={index} className="border rounded-lg p-4 bg-gray-50 space-y-3 shadow-sm">
                                    <p className="font-medium text-sm text-gray-700 truncate" title={pf.name}>{pf.name}</p>
                                    <div className="flex items-center justify-between gap-4">
                                        <div className="flex-1 space-y-2">
                                            <p className="text-xs text-gray-500 text-center uppercase tracking-wider font-semibold">Before</p>
                                            <div className="aspect-[3/4] rounded bg-white border border-gray-200 shadow-sm flex items-center justify-center overflow-hidden">
                                                <img
                                                    src={URL.createObjectURL(pf.original)}
                                                    alt={`Original ${pf.name}`}
                                                    className="w-full h-full object-contain"
                                                />
                                            </div>
                                        </div>
                                        <div className="flex-1 space-y-2">
                                            <p className="text-xs text-blue-600 text-center uppercase tracking-wider font-semibold">After</p>
                                            <div className="aspect-[3/4] rounded bg-white border-2 border-blue-100 shadow-sm flex items-center justify-center overflow-hidden">
                                                <img
                                                    src={URL.createObjectURL(pf.processed)}
                                                    alt={`Processed ${pf.name}`}
                                                    className="w-full h-full object-contain"
                                                />
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    )
}

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Canvas, FabricImage, IText, Rect, Group } from 'fabric';
import { loadPDFPageAsImage } from '@/utils/pdfHandler';
import { exportCanvasToPDF } from '@/utils/exportPDF';
// @ts-ignore
import { Toolbar } from './Toolbar';
// @ts-ignore
import { LayerManager } from './LayerManager';
import { Card } from '@/components/ui/card';
import { toast } from 'sonner';

export const AdvancedPDFEditor = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fabricRef = useRef<any>(null);
  const [isLoaded, setIsLoaded] = useState(false);
  const [history, setHistory] = useState<string[]>([]);
  const [redoStack, setRedoStack] = useState<string[]>([]);

  useEffect(() => {
    if (!canvasRef.current || fabricRef.current) return;

    fabricRef.current = new Canvas(canvasRef.current, {
      width: 600,
      height: 800,
      backgroundColor: '#f1f5f9',
    });

    fabricRef.current.on('object:added', () => saveState());
    fabricRef.current.on('object:modified', () => saveState());
    fabricRef.current.on('object:removed', () => saveState());

    return () => {
      fabricRef.current?.dispose();
      fabricRef.current = null;
    };
  }, []);

  const saveState = useCallback(() => {
    if (!fabricRef.current) return;
    const json = JSON.stringify(fabricRef.current.toObject());
    setHistory(prev => [...prev.slice(-49), json]); // Support up to 50 undo steps
    setRedoStack([]);
  }, []);

  const handleUndo = () => {
    if (history.length <= 1 || !fabricRef.current) return;
    const newHistory = [...history];
    const current = newHistory.pop();
    if (!current) return;

    setRedoStack(prev => [...prev, current]);
    setHistory(newHistory);

    const last = newHistory[newHistory.length - 1];
    fabricRef.current.loadFromJSON(JSON.parse(last)).then(() => {
      fabricRef.current?.requestRenderAll();
    });
  };

  const handleRedo = () => {
    if (redoStack.length === 0 || !fabricRef.current) return;
    const newRedo = [...redoStack];
    const next = newRedo.pop();
    if (!next) return;

    setHistory(prev => [...prev, next]);
    setRedoStack(newRedo);

    fabricRef.current.loadFromJSON(JSON.parse(next)).then(() => {
      fabricRef.current?.requestRenderAll();
    });
  };

  const handlePDFUpload = async (file: File) => {
    try {
      const dataUrl = await loadPDFPageAsImage(file);
      if (!fabricRef.current) return;

      const img = await FabricImage.fromURL(dataUrl);

      const canvasWidth = 600;
      const scale = canvasWidth / img.width;
      const canvasHeight = img.height * scale;

      fabricRef.current.setDimensions({ width: canvasWidth, height: canvasHeight });

      img.set({
        scaleX: scale,
        scaleY: scale,
        selectable: false,
        evented: false,
        name: 'pdf-background'
      });

      // Fabric 6 background image assignment
      fabricRef.current.backgroundImage = img;
      fabricRef.current.requestRenderAll();

      setIsLoaded(true);
      toast.success('PDF Loaded successfully as background');
      saveState();
    } catch (error) {
      console.error(error);
      toast.error('Failed to load PDF');
    }
  };

  const addPlaceholderText = (tag: string = '{{name}}') => {
    if (!fabricRef.current) return;
    const text = new IText(tag, {
      left: 100,
      top: 100,
      fontSize: 20,
      fontFamily: 'Inter',
      fill: '#000000',
    });
    fabricRef.current.add(text);
    fabricRef.current.setActiveObject(text);
    fabricRef.current.requestRenderAll();
  };

  const addImagePlaceholder = (tag: string = '{{photo}}') => {
    if (!fabricRef.current) return;
    const rect = new Rect({
      width: 120,
      height: 140,
      fill: 'rgba(59, 130, 246, 0.1)',
      stroke: '#3b82f6',
      strokeDashArray: [5, 5],
      strokeWidth: 2,
    });

    const label = new IText(tag, {
       fontSize: 12,
       fill: '#3b82f6',
       left: 10,
       top: 10,
       selectable: false
    });

    const group = new Group([rect, label], {
      left: 100,
      top: 150,
    });

    // Custom property for placeholder tracking
    (group as any).name = `Photo Placeholder (${tag})`;
    (group as any).placeholder = tag;

    fabricRef.current.add(group);
    fabricRef.current.setActiveObject(group);
    fabricRef.current.requestRenderAll();
  };

  const handleExport = async () => {
    if (!fabricRef.current) return;
    // Export at 2x resolution for better quality
    const dataUrl = fabricRef.current.toDataURL({ multiplier: 2 });
    await exportCanvasToPDF(dataUrl, fabricRef.current.width * 2, fabricRef.current.height * 2);
    toast.success('PDF Exported successfully');
  };

  const handleAIDetect = () => {
    if (!fabricRef.current || !isLoaded) return;
    toast.loading('Analyzing template layers...', { duration: 1500 });

    setTimeout(() => {
      addPlaceholderText('{{name}}');
      addPlaceholderText('{{id_number}}');
      addImagePlaceholder('{{photo}}');
      toast.success('AI Detection complete: 3 placeholders added');
    }, 1500);
  };

  return (
    <div className="flex flex-col h-full bg-[#f8fafc] overflow-hidden">
      <Toolbar 
        onUpload={handlePDFUpload}
        onAddText={() => addPlaceholderText()}
        onAddImage={() => addImagePlaceholder()}
        onUndo={handleUndo}
        onRedo={handleRedo}
        onExport={handleExport}
        onAIDetect={handleAIDetect}
        isLoaded={isLoaded}
      />

      <div className="flex flex-1 overflow-hidden p-6 gap-6">
        <div className="flex-1 flex justify-center items-start overflow-auto bg-slate-200/50 rounded-2xl border-2 border-dashed border-slate-300 p-8 shadow-inner">
          <Card className="shadow-2xl overflow-hidden bg-white">
            <canvas id="fabric-canvas" ref={canvasRef} />
          </Card>
        </div>

        <div className="w-80 flex flex-col gap-6">
          <LayerManager canvas={fabricRef.current} />

          <Card className="p-4 bg-indigo-50 border-indigo-100">
            <h3 className="text-xs font-bold text-indigo-700 uppercase tracking-wider mb-2">Instructions</h3>
            <ul className="text-[11px] text-indigo-600 space-y-2 list-disc pl-4">
              <li>Upload a PDF to start editing.</li>
              <li>Use <b>{"{{tag}}"}</b> for dynamic fields.</li>
              <li>Placeholders will be replaced during bulk generation.</li>
              <li>Drag items to reposition them on the template.</li>
            </ul>
          </Card>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import * as fabric from 'fabric';
import { Card } from '@/components/ui/card';
import { Layers, Lock, Unlock, Eye, EyeOff } from 'lucide-react';
import { Button } from '@/components/ui/button';

export const LayerManager = ({ canvas }: { canvas: fabric.Canvas | null }) => {
  const [layers, setLayers] = useState<any[]>([]);

  useEffect(() => {
    if (!canvas) return;

    const updateLayers = () => {
      // Fabric 6 getObjects() returns all items
      const objects = canvas.getObjects().reverse();
      setLayers(objects.map((obj: any, index: number) => ({
        id: obj.name || `Layer ${layers.length - index}`,
        type: obj.type,
        locked: !obj.selectable,
        visible: obj.visible,
        ref: obj
      })));
    };

    canvas.on('object:added', updateLayers);
    canvas.on('object:removed', updateLayers);
    canvas.on('selection:created', updateLayers);
    canvas.on('selection:cleared', updateLayers);

    updateLayers();
    return () => {
      canvas.off('object:added', updateLayers);
      canvas.off('object:removed', updateLayers);
    };
  }, [canvas]);

  const toggleLock = (layer: any) => {
    layer.ref.set({ selectable: !layer.locked, evented: !layer.locked });
    canvas?.renderAll();
    // Trigger update
    setLayers([...layers]);
  };

  const toggleVisibility = (layer: any) => {
    layer.ref.set({ visible: !layer.visible });
    canvas?.renderAll();
    setLayers([...layers]);
  };

  return (
    <Card className="flex-1 flex flex-col overflow-hidden bg-white shadow-sm border-slate-200">
      <div className="p-3 bg-slate-50 border-b border-slate-200 flex items-center justify-between">
        <h3 className="text-xs font-bold text-slate-700 uppercase tracking-wider flex items-center gap-2">
          <Layers size={14} /> Layer Management
        </h3>
        <span className="text-[10px] bg-slate-200 text-slate-600 px-1.5 py-0.5 rounded-full font-bold">
          {layers.length}
        </span>
      </div>

      <div className="flex-1 overflow-auto p-2 space-y-1">
        {layers.length === 0 ? (
          <div className="text-[11px] text-slate-400 text-center py-8">No layers yet</div>
        ) : (
          layers.map((layer, index) => (
            <div 
              key={index} 
              className={`flex items-center justify-between p-2 rounded-lg text-[11px] border transition-all ${layer.locked ? 'bg-slate-50/50 border-transparent text-slate-400' : 'bg-white border-slate-100 text-slate-700 shadow-sm'}`}
            >
              <div className="flex items-center gap-2">
                <div className={`w-2 h-2 rounded-full ${layer.locked ? 'bg-slate-300' : 'bg-indigo-400'}`} />
                <span className="font-semibold capitalize truncate max-w-[120px]">
                  {layer.type === 'itext' ? (layer.ref.text?.substring(0, 15) || 'Text') : layer.type}
                </span>
              </div>

              <div className="flex items-center gap-1">
                <Button 
                  variant="ghost" 
                  size="icon" 
                  className="h-6 w-6 text-slate-400 hover:text-indigo-600"
                  onClick={() => toggleVisibility(layer)}
                >
                  {layer.visible ? <Eye size={12} /> : <EyeOff size={12} />}
                </Button>
                <Button 
                  variant="ghost" 
                  size="icon" 
                  className="h-6 w-6 text-slate-400 hover:text-amber-600"
                  onClick={() => toggleLock(layer)}
                >
                  {layer.locked ? <Lock size={12} /> : <Unlock size={12} />}
                </Button>
              </div>
            </div>
          ))
        )}
      </div>
    </Card>
  );
};

import React, { useState, useCallback, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
