import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Badge } from '@/components/ui/badge';
import { 
  Save, 
  Download, 
  Upload, 
  Undo, 
  Redo, 
  Settings, 
  Layers, 
  Palette,
  Move,
  Type,
  Square,
  Circle as CircleIcon,
  Image as ImageIcon,
  Grid3X3,
  ZoomIn,
  ZoomOut,
  RotateCw,
  Trash2,
  Copy,
  Lock,
  Unlock,
  Eye,
  EyeOff,
  Plus,
