// ─── Production proof panel ──────────────────────────────────────────────────
function FlatStrap({ x, y, w, h, color, pattern, patternOpacity, children }: any) {
  const bc = baseColor(color);
  const sh = shadeHex(bc, -55);
  return (
    <Group x={x} y={y}>
      <Rect width={w} height={h} stroke={sh} strokeWidth={0.8} {...gradFill(color, { x: 0, y: 0 }, { x: w, y: 0 })} />
      <StrapPatternRenderer clipPoints={[0,0,w,0,w,h,0,h]} pattern={pattern} strapW={w} opacity={patternOpacity} />
      {children}
    </Group>
  );
}

function DimLine({ x1, y1, x2, y2, label }: any) {
  const isVert = x1 === x2;
  return (
    <Group opacity={0.55}>
      <Line points={[x1, y1, x2, y2]} stroke="#888" strokeWidth={0.8} dash={[4, 4]} />
      {isVert ? (<><Line points={[x1-5, y1, x1+5, y1]} stroke="#888" strokeWidth={0.8} /><Line points={[x1-5, y2, x1+5, y2]} stroke="#888" strokeWidth={0.8} /><Text text={label} x={x1-38} y={(y1+y2)/2 - 6} fontSize={10} fill="#666" align="right" width={30} /></>) : (<><Line points={[x1, y1-5, x1, y1+5]} stroke="#888" strokeWidth={0.8} /><Line points={[x2, y1-5, x2, y1+5]} stroke="#888" strokeWidth={0.8} /><Text text={label} x={(x1+x2)/2 - 15} y={y1-16} fontSize={10} fill="#666" align="center" width={30} /></>)}
    </Group>
  );
}

// ─── INDEPENDENT Content with Independent Drills ──────────────────────────
function UnifiedStrapContent({ x1, y1, x2, y2, design, logoImg, strapW, forceNoLogo, forceNoText, onUpdateText, onUpdateLogo, onRemoveText, onRemoveLogo, showControls, zone }: any) {
  const { lanyardDesignStyle, customText, customTextSecondary, predefinedWord, fontColor, fontFamily, fontSize, textSpacing, logoScale, logoRotation, textOffset, logoOffset, copyMode, customTextLeft, customTextCenter, customTextRight } = design;

  const dx = x2 - x1, dy = y2 - y1;
  const dist = Math.hypot(dx, dy);
  const angle = Math.atan2(dy, dx) * (180 / Math.PI);
  let mainText = lanyardDesignStyle === 'predefined' ? predefinedWord : (forceNoText ? '' : (copyMode === 'synchronized' ? customTextCenter : (zone === 'left' ? customTextLeft : (zone === 'right' ? customTextRight : customTextCenter))));
  let subText = lanyardDesignStyle === 'stacked-text' ? customTextSecondary : null;

  if (!mainText && !logoImg) return null;

  const fs = Math.min(fontSize, Math.max(6, strapW * 0.7));
  const hasLogo = logoImg && (lanyardDesignStyle === 'repeated' || (lanyardDesignStyle === 'central-logo' && forceNoLogo === false)) && !forceNoLogo;
  const hasSubText = subText && lanyardDesignStyle === 'stacked-text';

  const tOffset = copyMode === 'synchronized' ? (textOffset || 0) : (zone === 'left' ? (design.textOffsetLeft || 0) : (zone === 'right' ? (design.textOffsetRight || 0) : (design.textOffsetCenter || 0)));
  const lOffset = copyMode === 'synchronized' ? (logoOffset || 0) : (zone === 'left' ? (design.logoOffsetLeft || 0) : (zone === 'right' ? (design.logoOffsetRight || 0) : (design.logoOffsetCenter || 0)));

  const textW = mainText ? mainText.length * fs * 0.55 : 0;
  const lgW = hasLogo ? (strapW * 0.8 * (logoImg.width / logoImg.height) * logoScale) : 0;

  const gap = Math.max(30, (textSpacing || 60) * 2 + textW + lgW);
  const count = Math.max(0, Math.floor(dist / gap));
  if (count === 0 && !hasLogo) return null;

  const items = [];
  for (let i = 0; i < count; i++) {
    const baseT = (gap * i) / dist;
    const textT = baseT + (tOffset) / dist;
    const logoT = baseT + (lOffset) / dist + (textW + 15) / dist;

    if (zone === 'center') {
       if (textT >= 0 && textT <= 1) {
         if (mainText) items.push({ type: 'text', t: textT, i });
       }
       if (logoT >= 0 && logoT <= 1) {
         if (hasLogo) items.push({ type: 'logo', t: logoT, i });
       }
    } else {
      if (mainText) items.push({ type: 'text', t: textT, i });
      if (hasLogo) items.push({ type: 'logo', t: logoT, i });
    }
  }

  return (
    <Group>
      {items.map((item, idx) => {
        const px = x1 + dx * item.t, py = y1 + dy * item.t;
        if (item.t < -0.1 || item.t > 1.1) return null;

        if (item.type === 'text') {
          const totalHeight = hasSubText ? fs + fs * 0.55 : fs;
              return (
                <Group
                  key={`${item.type}-${item.i}`}
                  x={px}
                  y={py}
                  rotation={angle}
                  draggable={showControls}
                  onDragEnd={(e: any) => {
                    if (design.snapToGrid) {
                      const node = e.target;
                      const newX = Math.round(node.x() / (design.gridSize || 20)) * (design.gridSize || 20);
                      const newY = Math.round(node.y() / (design.gridSize || 20)) * (design.gridSize || 20);
                      node.position({ x: newX, y: newY });
                      onUpdateText(newX - px, newY - py, zone);
                    } else {
                      onUpdateText(e.target.x() - px, e.target.y() - py, zone);
                    }
                  }}
                  onTransformEnd={(e: any) => {
                    const node = e.target;
                    const scaleX = node.scaleX();
                    const rotation = node.rotation();
                    onUpdateText(node.x() - px, node.y() - py, zone, scaleX, rotation);
                    node.scaleX(1);
                    node.scaleY(1);
                  }}
                  onMouseEnter={(e: any) => {
                    if (showControls) e.target.getStage().container().style.cursor = 'grab';
                  }}
                  onMouseLeave={(e: any) => {
                    e.target.getStage().container().style.cursor = 'default';
                  }}
                >
                  <Text
                    text={mainText}
                    fontSize={fs}
                    fontFamily={fontFamily}
                    fontStyle="bold"
                    fill={fontColor}
                    align="center"
                    width={textW}
                    offsetX={textW / 2}
                    offsetY={totalHeight / 2}
                  />
                  {hasSubText && (
                    <Text
                      text={subText}
                      fontSize={fs * 0.55}
                      fontFamily={fontFamily}
                      fill={fontColor}
                      opacity={0.8}
                      align="center"
                      width={textW}
                      x={0}
                      y={fs * 0.8}
                      offsetX={textW / 2}
                      offsetY={totalHeight / 2}
                    />
                  )}
                  {showControls &&
                    item.i === 0 && (
                      <Group x={textW / 2 + 8} y={-fs / 2}>
                        <Circle radius={6} fill="#ef4444" onClick={() => onRemoveText(zone)} cursor="pointer" />
                        <Text
                          text="✕"
                          x={-3}
                          y={-3.5}
                          fontSize={7}
                          fill="#fff"
                          fontStyle="bold"
                          listening={false}
                        />
                      </Group>
                    )}
                </Group>
              );
            }

        return (
          <Group 
            key={`${item.type}-${item.i}`} x={px} y={py} rotation={angle}
            draggable={showControls} onDragMove={(e: any) => onUpdateLogo(e.target.x() - px, e.target.y() - py, zone)}
            onMouseEnter={(e: any) => { if (showControls) e.target.getStage().container().style.cursor = 'grab'; }}
            onMouseLeave={(e: any) => { e.target.getStage().container().style.cursor = 'default'; }}
          >
            <Image image={logoImg} width={lgW} height={strapW*0.8*logoScale} offsetY={(strapW*0.8*logoScale)/2} offsetX={lgW/2} rotation={logoRotation || 0} />
            {showControls && item.i === 0 && (
              <Group x={lgW/2 + 8} y={-(strapW*0.8*logoScale)/2}>
                 <Circle radius={6} fill="#ef4444" onClick={() => onRemoveLogo(zone)} cursor="pointer" />
                 <Text text="✕" x={-3} y={-3.5} fontSize={7} fill="#fff" fontStyle="bold" listening={false} />
              </Group>
            )}
          </Group>
        );
      })}
    </Group>
  );
}

export default function LanyardStage({ zoom = 1, stageRef, currentStep, showIdCard = false }: { zoom?: number; stageRef: any; currentStep: number; showIdCard?: boolean }) {
  const showControls = currentStep === 2;
  const design = useConfiguratorStore((s) => (s as any).design);
  const setField = useConfiguratorStore((s) => (s as any).setField);
  const [containerRef, containerWidth] = useContainerWidth();
  const logoImg = useCanvasImage(design.logoUrl);
  const strapColor = design.lanyardColor || '#cc1111';
  const scale = Math.max(0.35, (Math.min(containerWidth - 32, BASE_WIDTH) / BASE_WIDTH) * zoom);
  const activePattern = getPatternById(design.strapPattern);
  const patternOpacity = design.strapPatternOpacity ?? 0.85;

  const strapW = useMemo(() => {
    const mmStr = design.width || '20mm';
    const mm = parseInt(mmStr.replace('mm', ''), 10);
    return Math.max(14, (mm / 20) * 36);
  }, [design.width]);

  const CX = 305, TOP_Y = 100, HALF_W = 190, TIP_Y = 615, LX = CX - HALF_W, RX = CX + HALF_W;
  const CRIMP_H = 32, CRIMP_Y = TIP_Y - 55;

  const idCardSize = design.idCard.size;
  const isHorizontal = idCardSize === '100x70';
  const cardW = isHorizontal ? 283 : (idCardSize === '70x100' ? 198 : 153);
  const cardH = isHorizontal ? 198 : (idCardSize === '70x100' ? 283 : 244);
  const cardScale = 0.7;
  const barPts = [LX + strapW, TOP_Y, RX - strapW, TOP_Y, RX - strapW, TOP_Y + strapW, LX + strapW, TOP_Y + strapW];
  const leftStrap = [LX, TOP_Y + strapW, LX + strapW, TOP_Y + strapW, CX+strapW/2, CRIMP_Y, CX-strapW/2, CRIMP_Y];
  const rightStrap = [RX, TOP_Y + strapW, CX+strapW/2, CRIMP_Y, CX-strapW/2, CRIMP_Y, RX-strapW, TOP_Y + strapW];
  const connectorPts = [CX-strapW/2, CRIMP_Y+CRIMP_H-2, CX+strapW/2, CRIMP_Y+CRIMP_H-2, CX+strapW/2, TIP_Y, CX-strapW/2, TIP_Y];

  const leftCL = { x1: LX + strapW * 0.5, y1: TOP_Y + strapW * 1.5, x2: CX - strapW * 0.3, y2: CRIMP_Y - 20 };
  const rightCL = { x1: RX - strapW * 0.5, y1: TOP_Y + strapW * 1.5, x2: CX + strapW * 0.3, y2: CRIMP_Y - 20 };

  const onUpdateText = (dx: number, dy: number, zone: string, scale?: number, rotation?: number) => {
    if (design.copyMode === 'synchronized') {
      setField('textOffset', (design.textOffset || 0) + dx);
    } else {
      const fieldPath = zone === 'left' ? 'textOffsetLeft' : (zone === 'right' ? 'textOffsetRight' : 'textOffsetCenter');
      setField(fieldPath, (design[fieldPath] || 0) + dx);
    }
    setField('fontSize', design.fontSize * (scale || 1));
    setField('textAngle', (design.textAngle || 0) + (rotation || 0));
  };
  const onUpdateLogo = (dx: number, dy: number, zone: string, scale?: number, rotation?: number) => {
    if (design.copyMode === 'synchronized') {
      setField('logoOffset', (design.logoOffset || 0) + dx);
    } else {
      const fieldPath = zone === 'left' ? 'logoOffsetLeft' : (zone === 'right' ? 'logoOffsetRight' : 'logoOffsetCenter');
      setField(fieldPath, (design[fieldPath] || 0) + dx);
    }
    setField('logoScale', design.logoScale * (scale || 1));
    setField('logoRotation', (design.logoRotation || 0) + (rotation || 0));
  };
  const onRemoveText = (zone: string) => {
    if (design.copyMode === 'synchronized') {
      setField('customTextLeft', '');
      setField('customTextCenter', '');
      setField('customTextRight', '');
    } else {
      const fieldPath = zone === 'left' ? 'customTextLeft' : (zone === 'right' ? 'customTextRight' : 'customTextCenter');
      setField(fieldPath, '');
    }
  };
  const onRemoveLogo = () => {
    setField('logoUrl', '');
  };

  const [selectedShape, setSelectedShape] = useState<any>(null);
  const trRef = useRef<any>(null);
  const layerRef = useRef<any>(null);

  useEffect(() => {
    if (trRef.current) {
      trRef.current.nodes(selectedShape ? [selectedShape] : []);
      trRef.current.getLayer().batchDraw();
    }
  }, [selectedShape]);

  const onSelect = (e: any) => {
    if (e.target === e.target.getStage()) {
      setSelectedShape(null);
      return;
    }
    if (e.target.attrs.draggable) {
      setSelectedShape(e.target);
    } else {
      setSelectedShape(null);
    }
  };

  return (
    <div ref={containerRef} className="flex h-full w-full items-center justify-center overflow-hidden bg-white">
      <Stage ref={stageRef} width={BASE_WIDTH * scale} height={BASE_HEIGHT * scale} scaleX={scale} scaleY={scale} onClick={onSelect}>
        <Layer ref={layerRef}>
          {design.showGrid && (
            <Group>
              {
                Array.from(Array(Math.floor(BASE_WIDTH / design.gridSize)).keys()).map((i) => (
                  <Line
                    key={`v-${i}`}
                    points={[i * design.gridSize, 0, i * design.gridSize, BASE_HEIGHT]}
                    stroke="#e0e0e0"
                    strokeWidth={0.5}
                  />
                ))
              }
              {
                Array.from(Array(Math.floor(BASE_HEIGHT / design.gridSize)).keys()).map((i) => (
                  <Line
                    key={`h-${i}`}
                    points={[0, i * design.gridSize, BASE_WIDTH, i * design.gridSize]}
                    stroke="#e0e0e0"
                    strokeWidth={0.5}
                  />
                ))
              }
            </Group>
          )}
          <Rect x={0} y={0} width={BASE_WIDTH} height={BASE_HEIGHT} fill="#ffffff" />
          <DimLine x1={LX - 25} y1={TOP_Y} x2={LX - 25} y2={TOP_Y + strapW} label={design.width || '20mm'} />
          <Group>
            <ProStrap points={rightStrap} color={strapColor} strapW={strapW} pattern={activePattern} patternOpacity={patternOpacity} />
            <UnifiedStrapContent {...rightCL} design={design} logoImg={logoImg} strapW={strapW} onUpdateText={onUpdateText} onUpdateLogo={onUpdateLogo} onRemoveText={onRemoveText} onRemoveLogo={onRemoveLogo} showControls={showControls} zone="right" />

            <ProStrap points={barPts} color={strapColor} strapW={strapW} pattern={activePattern} patternOpacity={patternOpacity} />
            {design.lanyardDesignStyle === 'central-logo' ? (
              <StaticLogo cx={CX} cy={TOP_Y + strapW/2} angle={0} logo={logoImg} strapW={strapW} logoScale={design.logoScale} logoOffset={design.copyMode === 'synchronized' ? design.logoOffset : design.logoOffsetCenter} logoRotation={design.logoRotation} onRemove={onRemoveLogo} onDrag={onUpdateLogo} showControls={showControls} design={design} />
            ) : (
              <UnifiedStrapContent x1={LX+strapW+10} y1={TOP_Y+strapW/2} x2={RX-strapW-10} y2={TOP_Y+strapW/2} design={design} logoImg={logoImg} strapW={strapW} onUpdateText={onUpdateText} onUpdateLogo={onUpdateLogo} onRemoveText={onRemoveText} onRemoveLogo={onRemoveLogo} showControls={showControls} zone="center" />
            )}

            <ProStrap points={leftStrap} color={strapColor} strapW={strapW} pattern={activePattern} patternOpacity={patternOpacity} />
            <UnifiedStrapContent {...leftCL} design={design} logoImg={logoImg} strapW={strapW} onUpdateText={onUpdateText} onUpdateLogo={onUpdateLogo} onRemoveText={onRemoveText} onRemoveLogo={onRemoveLogo} showControls={showControls} zone="left" />

            <CornerFold side="left" ox={LX} oy={TOP_Y} strapW={strapW} color={strapColor} />
            <CornerFold side="right" ox={RX} oy={TOP_Y} strapW={strapW} color={strapColor} />
            <ProStrap points={connectorPts} color={strapColor} strapW={strapW} pattern={activePattern} patternOpacity={patternOpacity} />
            <MetalCrimp x={CX} y={CRIMP_Y} strapW={strapW} />

            {(() => {
              const props = { x: CX, y: TIP_Y, strapW };
              switch (design.clipType) {
                case 'Plastic Hook': return <PlasticHook {...props} />;
                case 'Crocodile Clip': return <CrocodileClip {...props} />;
                case 'Ski Reel': return <SkiReel {...props} />;
                default: return <SwivelHook {...props} />;
              }
            })()}
            {design.accessories?.includes('Quick Release Buckle') && <SideReleaseBuckle x={CX} y={TIP_Y - 90} strapW={strapW} strapColor={strapColor} />}

            {showIdCard && (
              <Group 
                x={CX} 
                y={TIP_Y + 20} 
                scaleX={cardScale} 
                scaleY={cardScale} 
                offsetX={cardW / 2}
              >
                <Rect 
                  x={cardW / 2 - 15} 
                  y={5} 
                  width={30} 
                  height={10} 
                  cornerRadius={5} 
                  fill="#f3f4f6" 
                  stroke="#eef2f6" 
                  strokeWidth={1} 
                />
                <IdCardPreview isReviewStep={true} forceSide="front" />
              </Group>
            )}
          </Group>

          <Group x={656} y={62}>
            <Text text="PRODUCTION FLAT LAYOUT" y={-22} fontSize={7.5} fontStyle="bold" fill="#bbb" fontFamily="Arial" letterSpacing={1.2} />
            <FlatStrap x={0} y={0} w={strapW} h={620} color={strapColor} pattern={activePattern} patternOpacity={patternOpacity}>
               <UnifiedStrapContent x1={strapW/2} y1={40} x2={strapW/2} y2={580} design={design} logoImg={logoImg} strapW={strapW} onUpdateText={onUpdateText} onUpdateLogo={onUpdateLogo} onRemoveText={onRemoveText} onRemoveLogo={onRemoveLogo} showControls={false} zone="left" />
            </FlatStrap>
            <FlatStrap x={strapW+16} y={0} w={strapW} h={620} color={strapColor} pattern={activePattern} patternOpacity={patternOpacity}>
               <UnifiedStrapContent x1={strapW/2} y1={580} x2={strapW/2} y2={40} design={design} logoImg={logoImg} strapW={strapW} onUpdateText={onUpdateText} onUpdateLogo={onUpdateLogo} onRemoveText={onRemoveText} onRemoveLogo={onRemoveLogo} showControls={false} zone="right" />
            </FlatStrap>
          </Group>

          <Transformer
            ref={trRef}
            boundBoxFunc={(oldBox, newBox) => {
              if (newBox.width < 5 || newBox.height < 5) {
                return oldBox;
              }
              return newBox;
            }}
          />
        </Layer>
      </Stage>
    </div>
  );
}

import { createPortal } from 'react-dom';
import {
  Expand,
  Undo2,
  Redo2,
  ZoomIn,
  ZoomOut,
  X,
  CreditCard,
  LayoutTemplate,
  Move,
  MousePointer2,
  Database,
  Eye,
} from 'lucide-react';

import { useEffect, useState, useRef } from 'react';
import { useConfiguratorStore } from '../../store/useConfiguratorStore';
import IdCardPreview from './IdCardPreview';
import { Group, Layer, Stage } from 'react-konva';

interface PreviewPanelProps {
  stageRef: React.RefObject<any>;
  idCardStageRef: React.RefObject<any>;
  zoom: number;
  setZoom: (zoom: number) => void;
  currentStep: number;
}

export default function PreviewPanel({ stageRef, idCardStageRef, zoom, setZoom, currentStep }: PreviewPanelProps) {
  const [isExpanded, setIsExpanded] = useState(false);
  const [isBlurred, setIsBlurred] = useState(false);

  const design = useConfiguratorStore((s: any) => s.design);
  const { size } = design.idCard;

  const isHorizontal = size === '100x70';
  const cardW = isHorizontal ? 283 : (size === '70x100' ? 198 : 153);
  const cardH = isHorizontal ? 198 : (size === '70x100' ? 283 : 244);
  const baseCardW = cardW;
  const baseCardH = cardH;

  // Expanded View zoom and pan
  const [fullZoom, setFullZoom] = useState(1);
  const [fullPan, setFullPan] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const dragStartInfo = useRef({ x: 0, y: 0, px: 0, py: 0 });

  const handleFullWheel = (e: React.WheelEvent) => {
    e.stopPropagation();
    const scaleBy = 1.05;
    const newZoom = e.deltaY > 0 ? fullZoom / scaleBy : fullZoom * scaleBy;
    setFullZoom(Math.min(Math.max(0.2, newZoom), 5));
  };

  const handleFullPointerDown = (e: React.PointerEvent) => {
    if (e.button !== 0) return;
    setIsDragging(true);
    dragStartInfo.current = {
      x: e.clientX,
      y: e.clientY,
      px: fullPan.x,
      py: fullPan.y,
    };
  };

  const handleFullPointerMove = (e: React.PointerEvent) => {
    if (!isDragging) return;
    setFullPan({
      x: dragStartInfo.current.px + (e.clientX - dragStartInfo.current.x),
      y: dragStartInfo.current.py + (e.clientY - dragStartInfo.current.y),
    });
  };

  const handleFullPointerUp = () => {
    setIsDragging(false);
  };

  const undo = useConfiguratorStore((state: any) => state.undo);
  const redo = useConfiguratorStore((state: any) => state.redo);
  const canUndo = useConfiguratorStore((state: any) => state.past.length > 0);
  const canRedo = useConfiguratorStore((state: any) => state.future.length > 0);

  const isMappingStep = currentStep === 1;
  const isConfirmationStep = currentStep === 2;
  const isFinalReviewStep = currentStep === 4;
  const isIdCardStep = currentStep >= 0 && currentStep <= 4;
  const idCardState = useConfiguratorStore((state: any) => state.design.idCard);

  // Editing functionality
  const [editingText, setEditingText] = useState<any>(null);
  const [activeImageUpload, setActiveImageUpload] = useState<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [mappingPopover, setMappingPopover] = useState<{ id: string; side: string; x: number; y: number } | null>(null);
  const COLUMNS = ['ID', 'Full Name', 'Email', 'Department', 'Job Title', 'Photo URL'];

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !activeImageUpload) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const dataUrl = event.target?.result as string;
      const { id, sideName } = activeImageUpload;
      const side = sideName || (useConfiguratorStore.getState() as any).design.idCard.activeSide;
      const elements = (useConfiguratorStore.getState() as any).design.idCard[side].elements;
      const newElements = elements.map((el: any) => el.id === id ? { ...el, src: dataUrl } : el);
      (useConfiguratorStore.getState() as any).setField(`idCard.${side}.elements`, newElements);
      setActiveImageUpload(null);
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsDataURL(file);
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (
        e.key === 'PrintScreen' || 
        (e.ctrlKey && (e.key === 'p' || e.key === 'P' || e.key === 's' || e.key === 'S')) ||
        (e.ctrlKey && e.shiftKey && (e.key === 's' || e.key === 'S'))
      ) {
        e.preventDefault();
        alert('SECURITY ALERT: This design environment is secured. Screenshots and downloads are disabled.');
      }

      if (e.key === 'Delete' || e.key === 'Backspace') {
        if (['INPUT', 'TEXTAREA'].includes(document.activeElement?.tagName || '')) return;
        const { selected, activeSide } = (useConfiguratorStore.getState() as any).design.idCard;
        if (selected) {
          const elements = (useConfiguratorStore.getState() as any).design.idCard[activeSide].elements;
          (useConfiguratorStore.getState() as any).setField(`idCard.${activeSide}.elements`, elements.filter((el: any) => el.id !== selected));
          (useConfiguratorStore.getState() as any).setField('idCard.selected', null);
        }
      }
    };

    const handleFocus = () => setIsBlurred(false);
    const handleBlur = () => setIsBlurred(true);

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('focus', handleFocus);
    window.addEventListener('blur', handleBlur);
    const handleContextMenu = (e: MouseEvent) => { e.preventDefault(); };
    window.addEventListener('contextmenu', handleContextMenu);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('focus', handleFocus);
      window.removeEventListener('blur', handleBlur);
      window.removeEventListener('contextmenu', handleContextMenu);
    };
  }, []);

  const cardCount = idCardState.showBothSides ? 2 : 1;
  const gap = 40;

  const totalW = isHorizontal ? baseCardW : ((baseCardW * cardCount) + (gap * (cardCount - 1)));
  const totalH = (isHorizontal && idCardState.showBothSides) ? ((baseCardH * 2) + gap) : baseCardH;
  const cardScale = Math.min(Math.min(750 / totalW, 600 / totalH), 2.2); 

  const cx = (800 / zoom - totalW * cardScale) / 2;
  const cy = (700 / zoom - totalH * cardScale) / 2;

  useEffect(() => {
    if (!isMappingStep) setMappingPopover(null);
  }, [isMappingStep, currentStep]);

  return (
    <div className={`flex h-full flex-col ${isBlurred ? 'blur-md' : ''} transition-all duration-300 no-print`}>
      <input type="file" accept="image/*" ref={fileInputRef} onChange={handleImageUpload} className="hidden" />

      <div 
        className={`h-[700px] w-full rounded-[32px] bg-[#ffffff] relative overflow-hidden shrink-0 border border-[#eef2f6] shadow-sm select-none ${isMappingStep ? 'ring-2 ring-transparent transition-all' : ''}`}
        onDragOver={(e) => {
          if (!isMappingStep) return;
          e.preventDefault();
          e.currentTarget.classList.add('ring-blue-400', 'bg-blue-50/10');
        }}
        onDragLeave={(e) => {
          if (!isMappingStep) return;
          e.currentTarget.classList.remove('ring-blue-400', 'bg-blue-50/10');
        }}
        onDrop={(e) => {
          if (!isMappingStep) return;
          e.preventDefault();
          e.currentTarget.classList.remove('ring-blue-400', 'bg-blue-50/10');
          const colName = e.dataTransfer.getData('text/plain');
          if (!colName || !idCardStageRef.current) return;

          idCardStageRef.current.setPointersPositions(e);
          const pos = idCardStageRef.current.getPointerPosition();
          if (pos) {
            const shape = idCardStageRef.current.getIntersection(pos);
            if (shape && shape.id()) {
               const hitId = shape.id();
               const allEls = [...design.idCard.front.elements, ...design.idCard.back.elements];
               if (allEls.find((el:any) => el.id === hitId)) {
                   // Valid drop!
                   let newMapping = { ...design.idCard.bulkWorkflow.mapping, [hitId]: colName };

                   // Auto-map the rest if this is the first item mapped manually
                   if (Object.keys(design.idCard.bulkWorkflow.mapping).length === 0) {
                      const columns = design.idCard.bulkWorkflow.datasetColumns;
                      allEls.forEach(el => {
                         if (el.id !== hitId) {
                            if(el.type === 'text') {
                               const match = columns.find((c: string) => c.toLowerCase().includes(el.content.toLowerCase().split(' ')[0]) || el.content.toLowerCase().includes(c.toLowerCase()));
                               if(match) newMapping[el.id] = match;
                            } else if(el.type === 'image') {
                               const match = columns.find((c: string) => c.toLowerCase().includes('photo') || c.toLowerCase().includes('image') || c.toLowerCase().includes('pic'));
                               if(match) newMapping[el.id] = match;
                            }
                         }
                      });
                   }

                   (useConfiguratorStore.getState() as any).setField('idCard.bulkWorkflow.mapping', newMapping);
               }
            }
          }
        }}
      >
        <div className={`absolute inset-0 flex items-center justify-center z-0 transition-all duration-500 ${isBlurred ? 'blur-sm grayscale opacity-50' : ''}`}>
          <div className="relative z-10" style={{ width: 800, height: 700 }}>
            <div className="absolute inset-0 z-40 bg-transparent pointer-events-none" onContextMenu={(e) => e.preventDefault()} />
            <Stage width={800} height={700} scaleX={zoom} scaleY={zoom} ref={idCardStageRef}>
              <Layer>
                <Group x={cx} y={cy} scaleX={cardScale} scaleY={cardScale}>
                  <IdCardPreview 
                    isReviewStep={currentStep > 0}
                    isMappingStep={isMappingStep}
                    record={isMappingStep || isConfirmationStep || isFinalReviewStep ? (idCardState.bulkWorkflow.datasetRecords?.[idCardState.bulkWorkflow.sampleRecordIndex || 0] || null) : null}
                    mapping={isMappingStep || isConfirmationStep || isFinalReviewStep ? idCardState.bulkWorkflow.mapping : undefined}
                    onMappingClick={(id, side, e) => {
                      const stage = e.target.getStage();
                      const pointer = stage.getPointerPosition();
                      setMappingPopover({ id, side, x: pointer.x, y: pointer.y });
                    }}
                    onSelectElement={(id: string, sideName: string) => {
                      if (isMappingStep) return; 
                      (useConfiguratorStore.getState() as any).setField('idCard.selected', id);
                      if (sideName) (useConfiguratorStore.getState() as any).setField('idCard.activeSide', sideName);
                    }}  
                    onUpdateElement={(id: string, pos: any, sideName: string) => {
                      const side = sideName || idCardState.activeSide;
                      const elements = idCardState[side].elements;
                      (useConfiguratorStore.getState() as any).setField(`idCard.${side}.elements`, elements.map((el: any) => el.id === id ? { ...el, ...pos } : el));
                    }} 
                    onDblClickElement={(id: string, sideName: string, e: any) => {
                      if (currentStep > 0) return;
                      const side = sideName || idCardState.activeSide;
                      const el = idCardState[side].elements.find((el: any) => el.id === id);
                      if (!el) return;
                      if (el.type === 'text') {
                        const node = e.target;
                        const textPosition = node.absolutePosition();
                        const scaleY = node.getAbsoluteScale().y;
                        setEditingText({
                          id, side, value: el.content, fontStyle: el.fontStyle, color: el.fill, align: el.align || 'left',
                          fontSize: (el.fontSize || 12) * scaleY, x: textPosition.x, y: textPosition.y,
                          width: node.width() * node.getAbsoluteScale().x + 10, height: node.height() * scaleY + 10,
                        });
                      } else if (el.type === 'image') {
                        setActiveImageUpload({ id, sideName: side });
                        if (fileInputRef.current) fileInputRef.current.click();
                      }
                    }}
                  />
                </Group>
              </Layer>
            </Stage>
            {editingText && (
              <textarea
                value={editingText.value}
                onChange={(e) => setEditingText({ ...editingText, value: e.target.value })}
                onBlur={() => {
                  const elements = idCardState[editingText.side].elements;
                  (useConfiguratorStore.getState() as any).setField(`idCard.${editingText.side}.elements`, elements.map((el: any) => el.id === editingText.id ? { ...el, content: editingText.value } : el));
                  setEditingText(null);
                }}
                autoFocus
                style={{
                  position: 'absolute', top: editingText.y, left: editingText.x, width: editingText.width, height: editingText.height,
                  fontSize: editingText.fontSize, fontFamily: 'sans-serif', fontWeight: editingText.fontStyle?.includes('bold') ? 'bold' : 'normal',
                  color: editingText.color, background: 'rgba(255, 255, 255, 0.8)', border: '2px solid #5d5fef', zIndex: 100,
                }}
              />
            )}

            {mappingPopover && (
              <div 
                className="absolute bg-white rounded-2xl shadow-2xl border border-blue-100 p-3 z-[200] w-56 animate-in fade-in zoom-in duration-200"
                style={{ top: mappingPopover.y + 10, left: mappingPopover.x + 10 }}
              >
                <div className="flex items-center justify-between mb-2 pb-2 border-b border-gray-50">
                  <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest flex items-center gap-1">
                    <Database size={10} /> Map Element
                  </span>
                  <button onClick={() => setMappingPopover(null)} className="text-gray-300 hover:text-gray-500"><X size={14} /></button>
                </div>
                <div className="space-y-1">
                  {COLUMNS.map(col => (
                    <button 
                      key={col}
                      onClick={() => {
                        const newMapping = { ...design.idCard.bulkWorkflow.mapping, [mappingPopover.id]: col };
                        (useConfiguratorStore.getState() as any).setField('idCard.bulkWorkflow.mapping', newMapping);
                        setMappingPopover(null);
                      }}
                      className={`w-full text-left px-3 py-2 rounded-lg text-[12px] font-bold transition-all ${design.idCard.bulkWorkflow.mapping[mappingPopover.id] === col ? 'bg-blue-500 text-white' : 'text-gray-600 hover:bg-blue-50 hover:text-blue-600'}`}
                    >
                      {col}
                    </button>
                  ))}
                  <button 
                      onClick={() => {
                        const newMapping = { ...design.idCard.bulkWorkflow.mapping };
                        delete newMapping[mappingPopover.id];
                        (useConfiguratorStore.getState() as any).setField('idCard.bulkWorkflow.mapping', newMapping);
                        setMappingPopover(null);
                      }}
                      className="w-full text-left px-3 py-2 rounded-lg text-[12px] font-bold text-red-400 hover:bg-red-50 hover:text-red-600 transition-all mt-1"
                  >
                    Remove Mapping
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>

        <div className="absolute inset-0 z-50 pointer-events-none">
          {!isExpanded && (
            <div className="absolute top-4 right-4 flex items-center gap-2 pointer-events-auto">
              <div className="flex items-center bg-white/90 backdrop-blur-sm border border-[#eef2f6] rounded-[14px] p-1 shadow-md">
                <button type="button" onClick={undo} disabled={!canUndo} className="p-1.5 rounded-[10px] text-[#1a1a1a] hover:bg-[#5d5fef] hover:text-white disabled:opacity-30 transition-all"><Undo2 size={14} /></button>
                <button type="button" onClick={redo} disabled={!canRedo} className="p-1.5 rounded-[10px] text-[#1a1a1a] hover:bg-[#5d5fef] hover:text-white disabled:opacity-30 transition-all"><Redo2 size={14} /></button>
                <div className="w-[1px] h-4 bg-[#eef2f6] mx-1" />
                <div className="flex items-center gap-2 px-2">
                  <ZoomIn size={14} className="text-[#5d5fef]" />
                  <input type="range" min="0.5" max="1.5" step="0.05" value={zoom} onChange={(e) => setZoom(Number(e.target.value))} className="w-16 h-1 bg-slate-100 rounded-lg appearance-none cursor-pointer accent-[#5d5fef]" />
                  <ZoomOut size={14} className="text-[#919191]" />
                </div>
              </div>
              <button type="button" onClick={() => setIsExpanded(true)} className="p-2 bg-[#5d5fef] text-white rounded-[12px] shadow-md hover:bg-[#4a4cd9] transition-all flex items-center justify-center"><Expand size={16} /></button>
            </div>
          )}

          {!isExpanded && (
            <div className="absolute bottom-6 left-6 flex items-center gap-2 px-4 py-2 bg-white/80 backdrop-blur-md border border-[#eef2f6] rounded-full shadow-md text-[11px] font-bold text-[#1a1a1a] uppercase">
              <div className="w-2 h-2 rounded-full bg-[#10b981] animate-pulse" />
              ID Card Proof
            </div>
          )}
        </div>
      </div>

      <div className="mt-6 grid grid-cols-1 sm:grid-cols-3 gap-4">
        {[
          { icon: MousePointer2, label: 'Technical Accuracy', sub: 'Production Ready' },
          { icon: Move, label: 'Real-time Sync', sub: 'Instant updates' },
          { icon: CreditCard, label: 'Secured Design', sub: 'Protected Proof', onClick: () => alert('This design is secured.') },
        ].map((item: any, i) => (
          <div key={i} onClick={item.onClick} className="flex items-center gap-4 p-4 rounded-[24px] bg-[#f8faff] border border-[#eef2f6] hover:bg-white transition-all cursor-pointer">
            <div className="flex h-10 w-10 items-center justify-center rounded-[12px] bg-white text-[#5d5fef] shadow-sm"><item.icon size={18} /></div>
            <div><p className="text-[14px] font-bold text-[#1a1a1a]">{item.label}</p><p className="text-[12px] text-[#919191]">{item.sub}</p></div>
          </div>
        ))}
      </div>

      {isExpanded && createPortal(
        <div className={`fixed inset-0 z-[999999] flex items-center justify-center bg-[#0f172a] select-none p-4 ${isBlurred ? 'blur-2xl' : ''}`}>
          <div className="w-full h-full bg-white rounded-[40px] shadow-2xl flex flex-col overflow-hidden relative border border-white/20">
            <div className="px-6 py-4 flex items-center justify-between border-b border-slate-100 bg-white/80 backdrop-blur-md z-[100] shrink-0">
              <div className="flex flex-col"><h3 className="text-[20px] font-extrabold text-[#1a1a1a]">Production Proof Review</h3><p className="text-[13px] text-slate-500 font-medium">Technical verification · Scroll to Zoom, Drag to Pan</p></div>
              <div className="flex items-center gap-4">
                <div className="flex items-center bg-slate-50 border border-slate-200 rounded-2xl p-1.5 shadow-sm">
                  <button onClick={() => setFullZoom(Math.max(0.2, fullZoom - 0.2))} className="p-2 text-slate-500 hover:text-indigo-600 rounded-xl"><ZoomOut size={18} /></button>
                  <span className="text-[13px] font-bold text-slate-700 w-16 text-center">{Math.round(fullZoom * 100)}%</span>
                  <button onClick={() => setFullZoom(Math.min(5, fullZoom + 0.2))} className="p-2 text-slate-500 hover:text-indigo-600 rounded-xl"><ZoomIn size={18} /></button>
                  <div className="w-[1px] h-6 bg-slate-200 mx-2"></div>
                  <button onClick={() => { setFullZoom(1); setFullPan({x:0, y:0}); }} className="px-4 py-2 text-[12px] font-bold text-slate-600 rounded-xl hover:bg-white transition-all">Reset</button>
                </div>
                <button onClick={() => setIsExpanded(false)} className="p-2.5 bg-red-50 text-red-500 hover:bg-red-500 hover:text-white rounded-2xl transition-all shadow-sm"><X size={20} /></button>
              </div>
            </div>

            <div className="flex-1 relative bg-[#fafafa] overflow-hidden cursor-grab active:cursor-grabbing" onWheel={handleFullWheel} onPointerDown={handleFullPointerDown} onPointerMove={handleFullPointerMove} onPointerUp={handleFullPointerUp} onPointerLeave={handleFullPointerUp}>
              <div className="absolute inset-0 z-50 bg-transparent pointer-events-none" onContextMenu={(e) => e.preventDefault()} />
              <div className="absolute inset-0 flex items-center justify-center transition-transform duration-75 ease-out" style={{ transform: `translate(${fullPan.x}px, ${fullPan.y}px) scale(${fullZoom})` }}>
                <div className="flex items-center justify-center p-20 select-none">
                  <div className="bg-white rounded-[40px] border border-slate-100 p-12 shadow-[0_10px_40px_rgba(0,0,0,0.04)]">
                    <Stage width={800} height={800} scaleX={1} scaleY={1}>
                      <Layer>
                        <Group x={(800 - (totalW * cardScale)) / 2} y={(800 - (totalH * cardScale)) / 2} scaleX={cardScale} scaleY={cardScale}>
                          <IdCardPreview isReviewStep={true} onSelectElement={() => {}} onUpdateElement={() => {}} />
                        </Group>
                      </Layer>
                    </Stage>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>,
        document.body
      )}
    </div>
  );
}

import { Group, Line, Rect, Circle, RegularPolygon, Shape } from 'react-konva';
import { useMemo } from 'react';
import { StrapPattern } from '../data/strapPatterns';

interface Bounds {
  minX: number;
  minY: number;
  maxX: number;
  maxY: number;
  w: number;
  h: number;
}

interface PatternProps {
  minX: number;
  minY: number;
  maxX: number;
  maxY: number;
  w: number;
  h: number;
  strapW: number;
  colors: string[];
}

/**
 * Renders decorative patterns on the lanyard strap inside a clipping region.
 * Each pattern type has its own procedural drawing routine using Konva shapes.
 */
export default function StrapPatternRenderer({ clipPoints, pattern, strapW, opacity = 0.9 }: {
  clipPoints: number[];
  pattern: StrapPattern | null;
  strapW: number;
  opacity?: number;
}) {
  const bounds = useMemo(() => {
    if (!clipPoints || clipPoints.length < 6) return { minX: 0, minY: 0, maxX: 0, maxY: 0, w: 0, h: 0 };
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    for (let i = 0; i < clipPoints.length; i += 2) {
      const x = clipPoints[i], y = clipPoints[i + 1];
      if (x < minX) minX = x;
      if (x > maxX) maxX = x;
      if (y < minY) minY = y;
      if (y > maxY) maxY = y;
    }
    return { minX, minY, maxX, maxY, w: maxX - minX, h: maxY - minY };
  }, [clipPoints]);

  const clipFunc = useMemo(() => {
    if (!clipPoints || clipPoints.length < 6) return undefined;
    return (ctx: any) => {
      ctx.beginPath();
      ctx.moveTo(clipPoints[0], clipPoints[1]);
      for (let i = 2; i < clipPoints.length; i += 2) { 
        ctx.lineTo(clipPoints[i], clipPoints[i + 1]); 
      }
      ctx.closePath();
    };
  }, [clipPoints]);

  if (!pattern || !clipPoints || clipPoints.length < 6) return null;

  const colors = pattern.patternColors || ['rgba(255,255,255,0.15)'];

  return (
    <Group clipFunc={clipFunc} opacity={opacity} listening={false}>
      <PatternShapes render={pattern.render} bounds={bounds} strapW={strapW} colors={colors} />
    </Group>
  );
}

function PatternShapes({ render, bounds, strapW, colors }: {
  render: string;
  bounds: Bounds;
  strapW: number;
  colors: string[];
}) {
  const props = { ...bounds, strapW, colors };
  switch (render) {
    case 'geometric-diamonds': return <DiamondPattern {...props} />;
    case 'geometric-chevrons': return <ChevronPattern {...props} />;
    case 'geometric-hexagons': return <HexagonPattern {...props} />;
    case 'tribal-lines': return <TribalPattern {...props} />;
    case 'racing-stripes': return <RacingStripePattern {...props} />;
    case 'polka-dots': return <PolkaDotPattern {...props} />;
    case 'stars': return <StarsPattern {...props} />;
    case 'bubbles': return <BubblesPattern {...props} />;
    case 'zigzag': return <ZigzagPattern {...props} />;
    case 'hearts': return <HeartsPattern {...props} />;
    case 'confetti': return <ConfettiPattern {...props} />;
    case 'waves': return <WavesPattern {...props} />;
    case 'marble-swirl': return <MarbleSwirlPattern {...props} />;
    case 'flames': return <FlamesPattern {...props} />;
    case 'circuit': return <CircuitPattern {...props} />;
    case 'seigaiha': return <SeigaihaPattern {...props} />;
    case 'mandala': return <MandalaPattern {...props} />;
    case 'grid-lines': return <GridLinesPattern {...props} />;
    case 'diagonal-shift': return <DiagonalShiftPattern {...props} />;
    case 'triangles': return <TrianglesPattern {...props} />;
    case 'clouds': return <CloudsPattern {...props} />;
    case 'floral': return <FloralPattern {...props} />;
    case 'ink': return <InkPattern {...props} />;
    case 'carbon-fiber': return <CarbonFiberPattern {...props} />;
    case 'herringbone': return <HerringbonePattern {...props} />;
    case 'topographic': return <TopographicPattern {...props} />;
    case 'speckle': return <SpecklePattern {...props} />;
    case 'micro-grid': return <MicroGridPattern {...props} />;
    default: return null;
  }
}

function seededRandom(seed: number) {
  let s = seed;
  return () => { s = (s * 16807 + 0) % 2147483647; return (s - 1) / 2147483646; };
}

// ═══════════════════════════════════════════════════════════════════════════════
// PATTERN IMPLEMENTAIONS
// ═══════════════════════════════════════════════════════════════════════════════

function DiamondPattern({ minX, minY, maxX, maxY, strapW, colors }: PatternProps) {
  const size = Math.max(12, strapW * 0.35);
  const items = []; let idx = 0;
  for (let y = minY - size; y < maxY + size; y += size) {
    for (let x = minX - size; x < maxX + size; x += size) {
      const cx = x + size/2, cy = y + size/2, hs = size * 0.42;
      items.push(<Line key={idx++} points={[cx, cy - hs, cx + hs, cy, cx, cy + hs, cx - hs, cy]} closed stroke={colors[0]} strokeWidth={1.2} fill={colors[1] || 'transparent'} />);
    }
  }
  return <Group>{items}</Group>;
}

function ChevronPattern({ minX, minY, maxX, maxY, w, h, strapW, colors }: PatternProps) {
  const spacing = Math.max(14, strapW * 0.5);
  const items = []; let idx = 0;
  const isHoriz = w > h * 1.5;
  if (isHoriz) {
    for (let x = minX; x < maxX + spacing; x += spacing) {
      const midY = (minY + maxY) / 2;
      items.push(<Line key={idx++} points={[x, minY - 5, x - spacing * 0.4, midY, x, maxY + 5]} stroke={colors[0]} strokeWidth={2} lineCap="round" />);
    }
  } else {
    for (let y = minY; y < maxY + spacing; y += spacing) {
      const midX = (minX + maxX) / 2;
      items.push(<Line key={idx++} points={[minX - 5, y, midX, y - spacing * 0.4, maxX + 5, y]} stroke={colors[0]} strokeWidth={2} lineCap="round" />);
    }
  }
  return <Group>{items}</Group>;
}

function HexagonPattern({ minX, minY, maxX, maxY, strapW, colors }: PatternProps) {
  const r = Math.max(8, strapW * 0.28);
  const items = []; let idx = 0;
  const dx = r * 1.75, dy = r * 1.52;
  let row = 0;
  for (let y = minY - r; y < maxY + r; y += dy) {
    const offsetX = (row % 2) * (dx / 2);
    for (let x = minX - r + offsetX; x < maxX + r; x += dx) {
      const pts: number[] = [];
      for (let a = 0; a < 6; a++) {
        const angle = (Math.PI / 3) * a - Math.PI / 6;
        pts.push(x + r * 0.75 * Math.cos(angle), y + r * 0.75 * Math.sin(angle));
      }
      items.push(<Line key={idx++} points={pts} closed stroke={colors[0]} strokeWidth={1} fill={colors[1] || 'transparent'} />);
    }
    row++;
  }
  return <Group>{items}</Group>;
}

function TribalPattern({ minX, minY, maxX, maxY, w, h, strapW, colors }: PatternProps) {
  const spacing = Math.max(18, strapW * 0.65);
  const items = []; let idx = 0;
  const isHoriz = w > h * 1.5;

  if (isHoriz) {
    const midY = (minY + maxY) / 2;
    for (let x = minX; x < maxX; x += spacing) {
      items.push(<Line key={idx++} points={[x, midY, x + spacing, midY]} stroke={colors[0]} strokeWidth={2} />);
      const ds = spacing * 0.25;
      items.push(<Line key={idx++} points={[x + spacing * 0.5 - ds, midY, x + spacing * 0.5, midY + ds, x + spacing * 0.5 + ds, midY, x + spacing * 0.5, midY - ds]} closed stroke={colors[0]} strokeWidth={1.5} fill={colors[1] || 'transparent'} />);
    }
  } else {
    const midX = (minX + maxX) / 2;
    for (let y = minY; y < maxY; y += spacing) {
      items.push(<Line key={idx++} points={[midX, y, midX, y + spacing]} stroke={colors[0]} strokeWidth={2} />);
      const ds = spacing * 0.25;
      items.push(<Line key={idx++} points={[midX, y + spacing * 0.5 - ds, midX + ds, y + spacing * 0.5, midX, y + spacing * 0.5 + ds, midX - ds, y + spacing * 0.5]} closed stroke={colors[0]} strokeWidth={1.5} fill={colors[1] || 'transparent'} />);
    }
  }
  return <Group>{items}</Group>;
}

function RacingStripePattern({ minX, minY, maxX, maxY, w, h, strapW, colors }: PatternProps) {
  const sw = Math.max(2, strapW * 0.08), gap = sw * 1.5;
  const isHoriz = w > h * 1.5;
  if (isHoriz) {
    const midY = (minY + maxY) / 2;
    return (
      <Group>
        <Line points={[minX - 10, midY - gap, maxX + 10, midY - gap]} stroke={colors[0]} strokeWidth={sw} />
        <Line points={[minX - 10, midY, maxX + 10, midY]} stroke={colors[1] || colors[0]} strokeWidth={sw * 0.6} />
        <Line points={[minX - 10, midY + gap, maxX + 10, midY + gap]} stroke={colors[0]} strokeWidth={sw} />
      </Group>
    );
  }
  const midX = (minX + maxX) / 2;
  return (
    <Group>
      <Line points={[midX - gap, minY - 10, midX - gap, maxY + 10]} stroke={colors[0]} strokeWidth={sw} />
      <Line points={[midX, minY - 10, midX, maxY + 10]} stroke={colors[1] || colors[0]} strokeWidth={sw * 0.6} />
      <Line points={[midX + gap, minY - 10, midX + gap, maxY + 10]} stroke={colors[0]} strokeWidth={sw} />
    </Group>
  );
}

function PolkaDotPattern({ minX, minY, maxX, maxY, strapW, colors }: PatternProps) {
  const spacing = Math.max(12, strapW * 0.45), r = Math.max(2, strapW * 0.08);
  const items = []; let idx = 0, row = 0;
  for (let y = minY; y < maxY + spacing; y += spacing) {
    const offset = (row % 2) * (spacing / 2);
    for (let x = minX + offset; x < maxX + spacing; x += spacing) { items.push(<Circle key={idx++} x={x} y={y} radius={r} fill={colors[0]} />); }
    row++;
  }
  return <Group>{items}</Group>;
}

function GridLinesPattern({ minX, minY, maxX, maxY, colors }: PatternProps) {
  const spacing = 12; // Adjusted spacing
  const items = []; let idx = 0;
  for (let x = minX; x < maxX; x += spacing) { items.push(<Line key={idx++} points={[x, minY, x, maxY]} stroke={colors[0]} strokeWidth={1} />); }
  for (let y = minY; y < maxY; y += spacing) { items.push(<Line key={idx++} points={[minX, y, maxX, y]} stroke={colors[1] || colors[0]} strokeWidth={1} />); }
  return <Group>{items}</Group>;
}

function DiagonalShiftPattern({ minX, minY, maxX, maxY, w, h, strapW, colors }: PatternProps) {
  const spacing = Math.max(12, strapW * 0.5);
  const items = []; let idx = 0;
  const isHoriz = w > h * 1.5;
  if (isHoriz) {
    for (let x = minX - 100; x < maxX + 100; x += spacing) {
      items.push(<Line key={idx++} points={[x, minY - 20, x + strapW, maxY + 20]} stroke={colors[0]} strokeWidth={3} lineCap="round" />);
    }
  } else {
    for (let y = minY - 100; y < maxY + 100; y += spacing) {
      items.push(<Line key={idx++} points={[minX - 20, y, maxX + 20, y + strapW]} stroke={colors[0]} strokeWidth={3} lineCap="round" />);
    }
  }
  return <Group>{items}</Group>;
}

function ZigzagPattern({ minX, minY, maxX, maxY, w, h, strapW, colors }: PatternProps) {
  const amp = Math.max(4, strapW * 0.2), period = Math.max(10, strapW * 0.35);
  const items = []; let idx = 0;
  const isHoriz = w > h * 1.5;
  const stripeCount = Math.max(2, Math.floor(strapW / (amp * 1.8)));

  if (isHoriz) {
    for (let s = 0; s < stripeCount; s++) {
      const offsetY = minY + ((maxY - minY) / (stripeCount + 1)) * (s + 1);
      const color = colors[s % colors.length], pts: number[] = [];
      for (let x = minX - period; x < maxX + period; x += period) {
        const zy = ((Math.floor((x - minX) / period)) % 2 === 0) ? offsetY - amp : offsetY + amp;
        pts.push(x, zy);
      }
      items.push(<Line key={idx++} points={pts} stroke={color} strokeWidth={2} lineCap="round" lineJoin="round" />);
    }
  } else {
    for (let s = 0; s < stripeCount; s++) {
      const offsetX = minX + ((maxX - minX) / (stripeCount + 1)) * (s + 1);
      const color = colors[s % colors.length], pts: number[] = [];
      for (let y = minY - period; y < maxY + period; y += period) {
        const zx = ((Math.floor((y - minY) / period)) % 2 === 0) ? offsetX - amp : offsetX + amp;
        pts.push(zx, y);
      }
      items.push(<Line key={idx++} points={pts} stroke={color} strokeWidth={2} lineCap="round" lineJoin="round" />);
    }
  }
  return <Group>{items}</Group>;
}

function WavesPattern({ minX, minY, maxX, maxY, w, h, strapW, colors }: PatternProps) {
  const waveHeight = Math.max(8, strapW * 0.35), waveSpacing = waveHeight * 2;
  const items = []; let idx = 0;
  const isHoriz = w > h * 1.5;

  if (isHoriz) {
    for (let x = minX - waveSpacing; x < maxX + waveSpacing; x += waveSpacing) {
      for (let layer = 0; layer < 3; layer++) {
        const pts: number[] = [], layerOffset = layer * waveHeight * 0.3;
        for (let y = minY - 20; y < maxY + 20; y += 4) {
          const waveX = x + layerOffset + Math.sin(((y - minY) / (strapW * 0.8)) * Math.PI) * waveHeight * 0.5;
          pts.push(waveX, y);
        }
        items.push(<Line key={idx++} points={pts} stroke={colors[layer % colors.length]} strokeWidth={1.5} tension={0.4} lineCap="round" />);
      }
    }
  } else {
    for (let y = minY - waveSpacing; y < maxY + waveSpacing; y += waveSpacing) {
      for (let layer = 0; layer < 3; layer++) {
        const pts: number[] = [], layerOffset = layer * waveHeight * 0.3;
        for (let x = minX - 20; x < maxX + 20; x += 4) {
          const waveY = y + layerOffset + Math.sin(((x - minX) / (strapW * 0.8)) * Math.PI) * waveHeight * 0.5;
          pts.push(x, waveY);
        }
        items.push(<Line key={idx++} points={pts} stroke={colors[layer % colors.length]} strokeWidth={1.5} tension={0.4} lineCap="round" />);
      }
    }
  }
  return <Group>{items}</Group>;
}

function MarbleSwirlPattern({ minX, minY, maxX, maxY, w, h, strapW, colors }: PatternProps) {
  const items = []; let idx = 0;
  const length = Math.max(w, h);
  const count = Math.floor(length / (strapW * 1.5));
  const isHoriz = w > h * 1.5;

  for (let i = 0; i < count; i++) {
    const pts: number[] = [], progress = i / count;
    if (isHoriz) {
      const x = minX + progress * w;
      for (let t = 0; t <= 20; t++) {
        const p = t/20;
        pts.push(x + p * strapW * 1.2, (minY + maxY)/2 + Math.sin(p * Math.PI * 3 + i) * strapW * 0.35);
      }
    } else {
      const y = minY + progress * h;
      for (let t = 0; t <= 20; t++) {
        const p = t/20;
        pts.push((minX + maxX)/2 + Math.sin(p * Math.PI * 3 + i) * strapW * 0.35, y + p * strapW * 1.2);
      }
    }
    items.push(<Line key={idx++} points={pts} stroke={colors[i % colors.length]} strokeWidth={1.5} tension={0.5} lineCap="round" />);
  }
  return <Group>{items}</Group>;
}

function StarsPattern({ minX, minY, maxX, maxY, w, h, strapW, colors }: PatternProps) {
  const rand = seededRandom(42), length = Math.max(w, h), count = Math.floor((length / strapW) * 4);
  const items = [];
  for (let i = 0; i < count; i++) {
    const x = minX + rand() * w, y = minY + rand() * h;
    const size = 3 + rand() * Math.max(4, strapW * 0.18);
    const rotation = rand() * 360;
    items.push(<StarShape key={i} x={x} y={y} size={size} fill={colors[Math.floor(rand() * colors.length)]} rotation={rotation} />);
  }
  return <Group>{items}</Group>;
}
function StarShape({ x, y, size, fill, rotation = 0 }: { x: number; y: number; size: number; fill: string; rotation?: number }) {
  const pts: number[] = [];
  for (let i = 0; i < 5; i++) {
    const outerAngle = (Math.PI / 2.5) * i - Math.PI / 2;
    const innerAngle = outerAngle + Math.PI / 5;
    pts.push(Math.cos(outerAngle) * size, Math.sin(outerAngle) * size);
    pts.push(Math.cos(innerAngle) * size * 0.4, Math.sin(innerAngle) * size * 0.4);
  }
  return <Line x={x} y={y} points={pts} closed fill={fill} rotation={rotation} />;
}

function BubblesPattern({ minX, minY, maxX, maxY, w, h, strapW, colors }: PatternProps) {
  const rand = seededRandom(77), length = Math.max(w, h), count = Math.floor((length / strapW) * 3);
  const items = [];
  for (let i = 0; i < count; i++) {
    const x = minX + rand() * w, y = minY + rand() * h;
    const r = 2 + rand() * Math.max(4, strapW * 0.2), color = colors[Math.floor(rand() * colors.length)];
    items.push(<Group key={i}><Circle x={x} y={y} radius={r} fill={color} opacity={0.45} /><Circle x={x} y={y} radius={r} stroke={color} strokeWidth={1} opacity={0.7} /><Circle x={x - r * 0.25} y={y - r * 0.25} radius={r * 0.2} fill="rgba(255,255,255,0.6)" /></Group>);
  }
  return <Group>{items}</Group>;
}

function HeartsPattern({ minX, minY, maxX, maxY, w, h, strapW, colors }: PatternProps) {
  const rand = seededRandom(14), length = Math.max(w, h), count = Math.floor((length / strapW) * 3);
  const items = [];
  for (let i = 0; i < count; i++) {
    const x = minX + rand() * w, y = minY + rand() * h;
    const size = 3 + rand() * Math.max(3, strapW * 0.15), rotation = -15 + rand() * 30;
    items.push(<HeartShape key={i} x={x} y={y} size={size} fill={colors[Math.floor(rand() * colors.length)]} rotation={rotation} />);
  }
  return <Group>{items}</Group>;
}
function HeartShape({ x, y, size, fill, rotation = 0 }: { x: number; y: number; size: number; fill: string; rotation?: number }) {
  return <Shape x={x} y={y} rotation={rotation} sceneFunc={(ctx: any, shape: any) => { ctx.beginPath(); ctx.moveTo(0, size * 0.35); ctx.bezierCurveTo(-size, -size * 0.3, -size * 0.05, -size, 0, -size * 0.4); ctx.bezierCurveTo(size * 0.05, -size, size, -size * 0.3, 0, size * 0.35); ctx.closePath(); ctx.fillStrokeShape(shape); }} fill={fill} />;
}

function ConfettiPattern({ minX, minY, maxX, maxY, w, h, strapW, colors }: PatternProps) {
  const rand = seededRandom(33), length = Math.max(w, h), count = Math.floor((length / strapW) * 5);
  const items = [];
  for (let i = 0; i < count; i++) {
    const x = minX + rand() * w, y = minY + rand() * h, sw = 2 + rand() * 4, sh = 5 + rand() * 8, rotation = rand() * 360;
    items.push(<Rect key={i} x={x} y={y} width={sw} height={sh} fill={colors[Math.floor(rand() * colors.length)]} rotation={rotation} cornerRadius={1} opacity={0.6 + rand() * 0.4} />);
  }
  return <Group>{items}</Group>;
}

function TrianglesPattern({ minX, minY, maxX, maxY, w, h, strapW, colors }: PatternProps) {
  const rand = seededRandom(111), length = Math.max(w, h), count = Math.floor((length / strapW) * 4);
  const items = [];
  for (let i = 0; i < count; i++) {
    const x = minX + rand() * w, y = minY + rand() * h, size = 6 + rand() * 8, rotation = rand() * 360;
    items.push(<Line key={i} x={x} y={y} points={[0, -size, size, size, -size, size]} closed fill={colors[Math.floor(rand() * colors.length)]} rotation={rotation} />);
  }
  return <Group>{items}</Group>;
}

function CloudsPattern({ minX, minY, maxX, maxY, w, h, strapW, colors }: PatternProps) {
  const rand = seededRandom(222), length = Math.max(w, h), count = Math.floor((length / strapW) * 2);
  const items = [];
  for (let i = 0; i < count; i++) {
    const x = minX + rand() * w, y = minY + rand() * h, scale = 0.5 + rand() * 0.5;
    items.push(<Group key={i} x={x} y={y} scaleX={scale} scaleY={scale}><Circle x={0} y={0} radius={8} fill={colors[0]} /><Circle x={8} y={-4} radius={10} fill={colors[0]} /><Circle x={16} y={1} radius={7} fill={colors[0]} /><Rect x={0} y={2} width={16} height={6} fill={colors[0]} /></Group>);
  }
  return <Group>{items}</Group>;
}

function CarbonFiberPattern({ minX, minY, maxX, maxY, colors }: PatternProps) {
  const size = 4;
  const items = []; let idx = 0;
  for (let y = minY - size; y < maxY + size; y += size) {
    for (let x = minX - size; x < maxX + size; x += size) {
      const fill = ((Math.floor(x/size) + Math.floor(y/size)) % 2 === 0) ? colors[0] : (colors[1] || 'rgba(0,0,0,0.1)');
      items.push(<Rect key={idx++} x={x} y={y} width={size-0.5} height={size-0.5} fill={fill} opacity={0.6} />);
    }
  }
  return <Group>{items}</Group>;
}

function HerringbonePattern({ minX, minY, maxX, maxY, w, h, colors }: PatternProps) {
  const size = 10;
  const items = []; let idx = 0;
  const isHoriz = w > h * 1.5;
  if (isHoriz) {
    for (let x = minX - 50; x < maxX + 50; x += size) {
      for (let y = minY - 50; y < maxY + 50; y += size * 2) {
        const isAlt = (Math.floor(x/size)) % 2 === 0;
        const pts = isAlt ? [x, y, x + size, y + size] : [x, y + size, x + size, y];
        items.push(<Line key={idx++} points={pts} stroke={colors[0]} strokeWidth={1} />);
      }
    }
  } else {
    for (let y = minY - 50; y < maxY + 50; y += size) {
      for (let x = minX - 50; x < maxX + 50; x += size * 2) {
        const isAlt = (Math.floor(y/size)) % 2 === 0;
        const pts = isAlt ? [x, y, x + size, y + size] : [x + size, y, x, y + size];
        items.push(<Line key={idx++} points={pts} stroke={colors[0]} strokeWidth={1} />);
      }
    }
  }
  return <Group>{items}</Group>;
}

function TopographicPattern({ minX, minY, maxX, maxY, strapW, colors }: PatternProps) {
  const rand = seededRandom(444);
  const items = []; let idx = 0;
  for (let i = 0; i < 8; i++) {
    const cx = minX + rand() * (maxX - minX), cy = minY + rand() * (maxY - minY), rad = strapW * 0.8;
    for (let r = 0; r < 4; r++) { items.push(<Circle key={idx++} x={cx} y={cy} radius={rad * (r+1) * 0.25} stroke={colors[r % colors.length]} strokeWidth={0.8} opacity={0.3} />); }
  }
  return <Group>{items}</Group>;
}

function SpecklePattern({ minX, minY, maxX, maxY, w, h, colors }: PatternProps) {
  const rand = seededRandom(555), length = Math.max(w, h), count = Math.floor(length * 2);
  const items = [];
  for (let i = 0; i < count; i++) { items.push(<Circle key={i} x={minX + rand() * w} y={minY + rand() * h} radius={0.5 + rand() * 1} fill={colors[i % colors.length]} opacity={0.6} />); }
  return <Group>{items}</Group>;
}

function MicroGridPattern({ minX, minY, maxX, maxY, colors }: PatternProps) {
  const spacing = 4;
  const items = []; let idx = 0;
  for (let x = minX; x < maxX; x += spacing) { items.push(<Line key={idx++} points={[x, minY, x, maxY]} stroke={colors[0]} strokeWidth={0.3} opacity={0.4} />); }
  for (let y = minY; y < maxY; y += spacing) { items.push(<Line key={idx++} points={[minX, y, maxX, y]} stroke={colors[1] || colors[0]} strokeWidth={0.3} opacity={0.4} />); }
  return <Group>{items}</Group>;
}

function SeigaihaPattern({ minX, minY, maxX, maxY, strapW, colors }: PatternProps) {
  const r = Math.max(8, strapW * 0.35);
  const items = []; let idx = 0, dx = r * 2, dy = r, row = 0;
  for (let y = minY - r; y < maxY + r; y += dy) {
    const offsetX = (row % 2) * r;
    for (let x = minX - r + offsetX; x < maxX + r; x += dx) {
      for (let ring = 3; ring >= 1; ring--) {
        const arcR = r * (ring / 3) * 0.9;
        items.push(<Shape key={idx++} sceneFunc={(ctx: any, shape: any) => { ctx.beginPath(); ctx.arc(x, y, arcR, 0, Math.PI, false); ctx.strokeShape(shape); }} stroke={colors[ring % colors.length]} strokeWidth={0.8} />);
      }
    }
    row++;
  }
  return <Group>{items}</Group>;
}

function MandalaPattern({ minX, minY, maxX, maxY, w, h, strapW, colors }: PatternProps) {
  const spacing = Math.max(30, strapW * 1.2), r = spacing * 0.4;
  const items = []; let idx = 0;
  const isHoriz = w > h * 1.5;
  const count = Math.floor(Math.max(w, h) / spacing);

  for (let i = 0; i < count; i++) {
    const cx = isHoriz ? minX + (i+0.5)*spacing : (minX+maxX)/2;
    const cy = isHoriz ? (minY+maxY)/2 : minY + (i+0.5)*spacing;
    items.push(<Circle key={idx++} x={cx} y={cy} radius={r} stroke={colors[0]} strokeWidth={1.2} />);
    items.push(<Circle key={idx++} x={cx} y={cy} radius={r * 0.6} stroke={colors[1] || colors[0]} strokeWidth={0.8} />);
    for (let a = 0; a < 8; a++) {
      const angle = (Math.PI / 4) * a;
      items.push(<Line key={idx++} points={[cx + Math.cos(angle) * r*0.3, cy + Math.sin(angle) * r*0.3, cx + Math.cos(angle) * r, cy + Math.sin(angle)*r]} stroke={colors[0]} strokeWidth={0.8} />);
    }
  }
  return <Group>{items}</Group>;
}

function FloralPattern({ minX, minY, maxX, maxY, w, h, strapW, colors }: PatternProps) {
  const spacing = Math.max(25, strapW), r = spacing * 0.35;
  const items = []; let idx = 0;
  const isHoriz = w > h * 1.5;
  const count = Math.floor(Math.max(w, h) / spacing);

  for (let i = 0; i < count; i++) {
    const cx = isHoriz ? minX + (i+0.5)*spacing : (minX+maxX)/2;
    const cy = isHoriz ? (minY+maxY)/2 : minY + (i+0.5)*spacing;
    for (let a = 0; a < 6; a++) {
      const angle = (Math.PI / 3) * a;
      items.push(<Circle key={idx++} x={cx + Math.cos(angle)*r} y={cy + Math.sin(angle)*r} radius={r*0.6} fill={colors[0]} opacity={0.6} />);
    }
    items.push(<Circle key={idx++} x={cx} y={cy} radius={r*0.4} fill={colors[1] || colors[0]} />);
  }
  return <Group>{items}</Group>;
}

function InkPattern({ minX, minY, maxX, maxY, w, h, strapW, colors }: PatternProps) {
  const rand = seededRandom(999), length = Math.max(w, h), count = Math.floor(length / (strapW * 0.8));
  const items = [];
  for (let i = 0; i < count; i++) {
    const tx = rand(), ty = rand();
    const cx = minX + tx * w, cy = minY + ty * h;
    const rad = strapW * (0.2 + rand() * 0.4), color = colors[Math.floor(rand() * colors.length)];
    const pts: number[] = [];
    for (let a = 0; a < 8; a++) {
      const angle = (Math.PI/4)*a, dist = rad*(0.6 + rand()*0.6);
      pts.push(cx + Math.cos(angle)*dist, cy + Math.sin(angle)*dist);
    }
    items.push(<Line key={i} points={pts} closed fill={color} tension={0.5} opacity={0.7} />);
  }
  return <Group>{items}</Group>;
}

import { useState, useEffect } from 'react';
import { X, Info, CheckCircle, AlertCircle } from 'lucide-react';

interface Toast {
  id: string;
  message: string;
  type: 'success' | 'error' | 'info';
  title: string;
}

export default function ToastContainer() {
  const [toasts, setToasts] = useState<Toast[]>([]);

  useEffect(() => {
    const handleToast = (event: any) => {
      const { message, type = 'info', title = 'Notification' } = event.detail;
      const id = Math.random().toString(36).substr(2, 9);

      setToasts((prev) => [...prev, { id, message, type, title }]);

      setTimeout(() => {
        setToasts((prev) => prev.filter((t) => t.id !== id));
      }, 5000);
    };

    window.addEventListener('show-toast', handleToast);
    return () => window.removeEventListener('show-toast', handleToast);
  }, []);

  const removeToast = (id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  };

  return (
    <div className="fixed bottom-6 right-6 z-[200] flex flex-col gap-3 max-w-sm w-full">
      {toasts.map((toast) => (
        <div
          key={toast.id}
          className="bg-white rounded-2xl shadow-2xl border border-[#eef2f6] p-4 flex gap-4 animate-slide-in-right group relative overflow-hidden"
        >
          {/* Progress bar */}
          <div className="absolute bottom-0 left-0 h-1 bg-gradient-to-r from-[#5d5fef] to-[#82e9ff] animate-progress-shrink" />

          <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 ${
            toast.type === 'success' ? 'bg-emerald-100 text-emerald-600' :
            toast.type === 'error' ? 'bg-red-100 text-red-600' :
            'bg-blue-100 text-blue-600'
          }`}>
            {toast.type === 'success' ? <CheckCircle size={20} /> :
             toast.type === 'error' ? <AlertCircle size={20} /> :
             <Info size={20} />}
          </div>

          <div className="flex-1 min-w-0">
            <h4 className="text-sm font-bold text-[#1a1a1a]">{toast.title}</h4>
            <p className="text-xs text-[#919191] mt-0.5 line-clamp-2">{toast.message}</p>
          </div>

          <button
            onClick={() => removeToast(toast.id)}
            className="text-[#b2b2b2] hover:text-[#1a1a1a] p-1 rounded-lg transition-colors"
          >
            <X size={16} />
          </button>
        </div>
      ))}
    </div>
  );
}

// Helper to show toast
export const showToast = (message: string, type: 'success' | 'error' | 'info' = 'info', title: string = 'Notification') => {
  window.dispatchEvent(new CustomEvent('show-toast', { detail: { message, type, title } }));
};

