export default function DesignMode({ stageRef, idCardStageRef, zoom, setZoom }: any) {
  const design = useConfiguratorStore(state => state.design);
  const setField = useConfiguratorStore(state => state.setField);
  const { mapping, datasetColumns } = design.idCard.bulkWorkflow;
  const activeSide = design.idCard.activeSide;
  const elements = design.idCard[activeSide].elements;

  const [activeTab, setActiveTab] = useState<'headers' | 'layers' | 'frames'>('headers');

  // Hydrate batchImageStore from Zustand on mount (ensures photos survive mode transitions & HMR)
  useEffect(() => {
    const storeImgs = design.idCard.bulkWorkflow.datasetImages || {};
    const storeKeys = Object.keys(storeImgs);
    const batchKeys = getBatchImageKeys();
    if (storeKeys.length > 0 && batchKeys.length === 0) {
      hydrateBatchImageStore(storeImgs);
    }
  }, []);

  const [editingText, setEditingText] = useState<any>(null);
  const [stagePos, setStagePos] = useState({ x: 0, y: 0 });
  const [isDrawingMode, setIsDrawingMode] = useState(false);
  const [isDrawing, setIsDrawing] = useState(false);

  const { width, height } = React.useMemo(() => {
    switch (design.idCard.size) {
      case '100x70': return { width: 283, height: 198 };
      case '70x100': return { width: 198, height: 283 };
      case '54x86': return { width: 153, height: 244 };
      default: return { width: 244, height: 153 }; // 86x54
    }
  }, [design.idCard.size]);

  const padding = 80;
  const stageWidth = 800;
  const stageHeight = 700;

  const baseScale = Math.min(
    (stageWidth - padding) / width,
    (stageHeight - padding) / height
  );
  const scale = baseScale * zoom;
  const cx = (stageWidth - width * scale) / 2;
  const cy = (stageHeight - height * scale) / 2;

  const handleWheel = useCallback((e: any) => {
    e.evt.preventDefault();
    const scaleBy = 1.05;
    const newZoom = e.evt.deltaY < 0 ? zoom * scaleBy : zoom / scaleBy;
    setZoom(Math.min(Math.max(newZoom, 0.1), 5));
  }, [zoom, setZoom]);

  const resetView = useCallback(() => {
    setStagePos({ x: 0, y: 0 });
    setZoom(1);
  }, [setZoom]);

  const addFrame = (shapeType: string) => {
    const newId = `frame-${Date.now()}`;
    const newElement: any = {
      id: newId,
      type: 'frame',
      shapeType,
      x: Math.round(width / 2 - 40),
      y: Math.round(height / 2 - 40),
      width: 80,
      height: 80,
    };
    setField(`idCard.${activeSide}.elements`, [...elements, newElement]);
    setField('idCard.selected', newId);
  };

  const spawnElement = (columnName: string, type: 'text' | 'qr' | 'barcode' | 'image' | 'frame' = 'text') => {
    const newId = `field-${Date.now()}`;
    const textWidth = Math.round(width * 0.85);

    // Check if this column is the photo-matching column
    const isPhotoCol = columnName === design.idCard.bulkWorkflow.imageMatchColumn;

    const newElement: any = {
      id: newId,
      type: type,
      x: type === 'text' ? Math.round((width - textWidth) / 2) : Math.round(width / 2 - (type === 'image' ? 40 : 25)),
      y: type === 'image' ? Math.round(height * 0.15) : height / 2 - 10,
      content: columnName,
    };

    if (type === 'text') {
      newElement.width = textWidth;
      newElement.fontSize = 12;
      newElement.fill = '#1e293b';
      newElement.align = 'center';
      newElement.fontStyle = 'bold';
    } else if (type === 'image') {
      // Larger default for photo elements so they're visible
      newElement.width = isPhotoCol ? 80 : 60;
      newElement.height = isPhotoCol ? 90 : 60;
      newElement.cornerRadius = isPhotoCol ? 6 : 0;
    } else {
      newElement.width = 50;
      newElement.height = 50;
    }

    setField(`idCard.${activeSide}.elements`, [...elements, newElement]);
    setField(`idCard.bulkWorkflow.mapping`, { ...mapping, [newId]: columnName });
    setField('idCard.selected', newId);
  };

  const handleStaticImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const newId = `img-static-${Date.now()}`;
      const newElement: any = {
        id: newId,
        type: 'image',
        x: width / 2 - 25,
        y: height / 2 - 25,
        width: 50,
        height: 50,
        src: event.target?.result as string,
      };
      setField(`idCard.${activeSide}.elements`, [...elements, newElement]);
      setField('idCard.selected', newId);
    };
    reader.readAsDataURL(file);
  };

  const addStaticText = () => {
    const newId = `text-static-${Date.now()}`;
    const textWidth = Math.round(width * 0.85);
    const newElement: any = {
      id: newId,
      type: 'text',
      x: Math.round((width - textWidth) / 2),
      y: height / 2 - 10,
      width: textWidth,
      content: 'Double click to edit',
      fontSize: 12,
      fill: '#1e293b',
      align: 'center',
      fontStyle: 'bold',
    };
    setField(`idCard.${activeSide}.elements`, [...elements, newElement]);
    setField('idCard.selected', newId);
  };

  const handleMouseDown = (e: any) => {
    if (!isDrawingMode) return;

    setIsDrawing(true);
    const stage = e.target.getStage();
    const pos = stage.getPointerPosition();

    // Convert absolute to group-relative
    const group = stage.findOne('#card-group');
    if (!group) return;
    const transform = group.getAbsoluteTransform().copy();
    transform.invert();
    const relativePos = transform.point(pos);

    const newId = `line-${Date.now()}`;
    const newElement: any = {
      id: newId,
      type: 'line',
      points: [relativePos.x, relativePos.y],
      stroke: '#5d5fef',
      strokeWidth: 2,
      tension: 0.5,
      lineCap: 'round',
      lineJoin: 'round',
    };

    setField(`idCard.${activeSide}.elements`, [...elements, newElement]);
    setField('idCard.selected', newId);
  };

  const handleMouseMove = (e: any) => {
    if (!isDrawingMode || !isDrawing) return;

    const stage = e.target.getStage();
    const pos = stage.getPointerPosition();
    const group = stage.findOne('#card-group');
    if (!group) return;
    const transform = group.getAbsoluteTransform().copy();
    transform.invert();
    const relativePos = transform.point(pos);

    const selectedId = design.idCard.selected;
    const els = [...elements];
    const index = els.findIndex(el => el.id === selectedId);
    if (index === -1 || els[index].type !== 'line') return;

    const lastLine = { ...els[index] };
    lastLine.points = [...lastLine.points, relativePos.x, relativePos.y];
    els[index] = lastLine;

    setField(`idCard.${activeSide}.elements`, els);
  };

  const handleMouseUp = () => {
    setIsDrawing(false);
    const selectedId = design.idCard.selected;
    const els = [...elements];
    const index = els.findIndex(el => el.id === selectedId);
    if (index === -1 || els[index].type !== 'line') return;

    const line = { ...els[index] };
    if (line.points.length < 4) {
      // Remove tiny specks
      setField(`idCard.${activeSide}.elements`, els.filter(el => el.id !== selectedId));
      return;
    }

    // Normalize points: make x,y the top-left and shift all points
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    for (let i = 0; i < line.points.length; i += 2) {
      minX = Math.min(minX, line.points[i]);
      minY = Math.min(minY, line.points[i+1]);
      maxX = Math.max(maxX, line.points[i]);
      maxY = Math.max(maxY, line.points[i+1]);
    }

    line.x = minX;
    line.y = minY;
    line.width = maxX - minX;
    line.height = maxY - minY;
    line.points = line.points.map((p: number, i: number) => i % 2 === 0 ? p - minX : p - minY);

    els[index] = line;
    setField(`idCard.${activeSide}.elements`, els);
  };

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden">
      {/* Left Sidebar */}
      <div className="w-72 bg-white border-r border-slate-200 shadow-sm flex flex-col z-10 shrink-0">
        <div className="flex px-4 py-3 border-b border-slate-100 gap-1">
          <button onClick={() => setActiveTab('headers')} className={`flex-1 text-[10px] font-black uppercase py-2 rounded-lg transition-all ${activeTab === 'headers' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-500 hover:bg-slate-50'}`}>Headers</button>
          <button onClick={() => setActiveTab('frames')} className={`flex-1 text-[10px] font-black uppercase py-2 rounded-lg transition-all ${activeTab === 'frames' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-500 hover:bg-slate-50'}`}>Frames</button>
          <button onClick={() => setActiveTab('layers')} className={`flex-1 text-[10px] font-black uppercase py-2 rounded-lg transition-all ${activeTab === 'layers' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-500 hover:bg-slate-50'}`}>Layers</button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
          {activeTab === 'headers' && (
            <div className="space-y-3">
              <div className="text-[11px] font-black uppercase text-slate-400 mb-2">Dataset Columns</div>
              {datasetColumns.map((col: string) => {
                const isMapped = Object.values(mapping).includes(col);
                return (
                  <div key={col} className={`p-3 rounded-xl border-2 transition-all group ${isMapped ? 'border-emerald-100 bg-emerald-50/50' : 'border-slate-100 bg-white hover:border-indigo-200 hover:shadow-md cursor-pointer'}`}>
                    <div className="flex items-center justify-between mb-2">
                       <span className="text-xs font-bold text-slate-700 truncate">{col}</span>
                       {isMapped && <span className="text-[10px] font-bold text-emerald-600 px-1.5 py-0.5 rounded bg-emerald-100">Added</span>}
                    </div>
                    <div className="opacity-0 group-hover:opacity-100 transition-opacity flex gap-1 mt-2">
                      <button onClick={() => spawnElement(col, 'text')} className="flex-1 py-1.5 bg-slate-50 hover:bg-indigo-50 text-slate-600 hover:text-indigo-600 rounded-lg text-[10px] font-bold flex flex-col items-center"><Type size={12}/> Text</button>
                      <button onClick={() => spawnElement(col, 'image')} className="flex-1 py-1.5 bg-slate-50 hover:bg-indigo-50 text-slate-600 hover:text-indigo-600 rounded-lg text-[10px] font-bold flex flex-col items-center"><ImageIcon size={12}/> Image</button>
                      <button onClick={() => spawnElement(col, 'qr')} className="flex-1 py-1.5 bg-slate-50 hover:bg-indigo-50 text-slate-600 hover:text-indigo-600 rounded-lg text-[10px] font-bold flex flex-col items-center"><QrCode size={12}/> QR</button>
                      <button onClick={() => spawnElement(col, 'barcode')} className="flex-1 py-1.5 bg-slate-50 hover:bg-indigo-50 text-slate-600 hover:text-indigo-600 rounded-lg text-[10px] font-bold flex flex-col items-center"><Barcode size={12}/> Bar</button>
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {activeTab === 'frames' && (
            <div className="space-y-4">
              <div className="flex items-center justify-between mb-2">
                <div className="text-[11px] font-black uppercase text-slate-400">Image Frames (Masks)</div>
                <button 
                  onClick={() => setIsDrawingMode(!isDrawingMode)}
                  className={`px-3 py-1 rounded-full text-[10px] font-black uppercase transition-all flex items-center gap-1.5 ${isDrawingMode ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}
                >
                  <div className={`w-1.5 h-1.5 rounded-full ${isDrawingMode ? 'bg-white animate-pulse' : 'bg-slate-400'}`} />
                  {isDrawingMode ? 'Stop Drawing' : 'Draw'}
                </button>
              </div>
              <div className="grid grid-cols-4 gap-2 max-h-[400px] overflow-y-auto pr-1 scrollbar-thin scrollbar-thumb-slate-200">
                {AVAILABLE_FRAMES.map((frame) => (
                  <button
                    key={frame.id}
                    onClick={() => {
                        setIsDrawingMode(false);
                        addFrame(frame.id);
                    }}
                    className="flex flex-col items-center justify-center p-2 bg-slate-50 border border-slate-200 rounded-lg hover:bg-indigo-50 hover:border-indigo-200 hover:shadow-sm transition-all group aspect-square"
                    title={frame.label}
                  >
                    <span className="text-xl text-slate-400 group-hover:text-indigo-400 mb-1 transition-colors">{frame.icon}</span>
                    <span className="text-[8px] font-bold text-slate-400 group-hover:text-indigo-600 truncate w-full text-center px-0.5">{frame.label}</span>
                  </button>
                ))}
              </div>
              <div className="p-3 bg-indigo-50/50 rounded-xl border border-indigo-100">
                <p className="text-[10px] text-indigo-600 font-medium leading-relaxed">
                  <strong>Pro Tip:</strong> Select a frame, then drag an image into it. Or use <strong>"Draw"</strong> to create a custom mask!
                </p>
              </div>
            </div>
          )}

          {activeTab === 'layers' && (
            <div className="space-y-2">
               <div className="flex items-center justify-between mb-3 border-b border-slate-100 pb-2">
                 <button onClick={() => setField('idCard.activeSide', 'front')} className={`text-[11px] font-bold ${activeSide === 'front' ? 'text-indigo-600' : 'text-slate-400'}`}>FRTSIDE</button>
                 <button onClick={() => setField('idCard.activeSide', 'back')} className={`text-[11px] font-bold ${activeSide === 'back' ? 'text-indigo-600' : 'text-slate-400'}`}>BAKSIDE</button>
               </div>
               {[...elements].reverse().map((el, i) => (
                 <div key={el.id} onClick={() => setField('idCard.selected', el.id)} className={`p-2 rounded-lg flex items-center justify-between cursor-pointer border ${design.idCard.selected === el.id ? 'border-indigo-400 bg-indigo-50/50' : 'border-transparent hover:bg-slate-50'}`}>
                   <div className="flex items-center gap-2">
                     {el.type === 'text' ? <Type size={14} className="text-slate-400"/> : el.type === 'qr' ? <QrCode size={14} className="text-slate-400"/> : <ImageIcon size={14} className="text-slate-400"/>}
                     <span className="text-xs font-medium text-slate-700 truncate w-32">{mapping[el.id] || el.type}</span>
                   </div>
                 </div>
               ))}
            </div>
          )}
        </div>
      </div>

      {/* Main Workspace (Canvas) */}
      <div className="flex-1 relative flex items-center justify-center p-8 overflow-hidden">
        {/* Workspace formatting toolbar */}
        <div className="absolute top-4 left-1/2 -translate-x-1/2 z-50 flex items-center gap-1 bg-white/90 backdrop-blur border border-slate-200 shadow-sm p-1 rounded-xl">
          <button onClick={() => setField('idCard.size', '54x86')} className={`px-3 py-1.5 text-xs font-bold rounded-lg ${design.idCard.size === '54x86' ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}>Portrait</button>
          <button onClick={() => setField('idCard.size', '86x54')} className={`px-3 py-1.5 text-xs font-bold rounded-lg ${design.idCard.size === '86x54' ? 'bg-indigo-50 text-indigo-700 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}>Landscape</button>
          <div className="w-px h-5 bg-slate-200 mx-1" />
          <FontBar />
        </div>

        {/* The zooming workspace area — freely draggable */}
        <div className="w-full h-full bg-white rounded-3xl shadow-xl flex items-center justify-center overflow-hidden border border-white/50 relative p-10 mt-10">
          <Stage
            width={stageWidth}
            height={stageHeight}
            ref={stageRef}
            draggable={!isDrawingMode}
            x={stagePos.x}
            y={stagePos.y}
            onDragEnd={(e) => {
              if (e.target === e.target.getStage()) {
                setStagePos({ x: e.target.x(), y: e.target.y() });
              }
            }}
            onWheel={handleWheel}
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            style={{ cursor: isDrawingMode ? 'crosshair' : 'grab' }}
          >
            <Layer>
              <Group id="card-group" x={cx} y={cy} scaleX={scale} scaleY={scale}>
                <IdCardPreview 
                  isReviewStep={false}
                  record={design.idCard.bulkWorkflow.datasetRecords?.[design.idCard.bulkWorkflow.sampleRecordIndex || 0]}
                  mapping={mapping}
                  onSelectElement={(id, sideName) => {
                    setField('idCard.selected', id);
                    if (sideName) setField('idCard.activeSide', sideName);
                  }}
                  onUpdateElement={(id, pos, sideName) => {
                    const side = sideName || activeSide;
                    const els = design.idCard[side].elements;
                    const movedEl = els.find((e: any) => e.id === id);

                    if (movedEl?.type === 'image' && (pos.x !== undefined || pos.y !== undefined)) {
                      const updatedEl = { ...movedEl, ...pos };
                      const centerX = updatedEl.x + (updatedEl.width || 0) / 2;
                      const centerY = updatedEl.y + (updatedEl.height || 0) / 2;

                      const targetFrame = els.find((e: any) => 
                        (e.type === 'frame' || e.type === 'line') && 
                        centerX > e.x && centerX < e.x + (e.width ?? 100) &&
                        centerY > e.y && centerY < e.y + (e.height ?? 100)
                      );

                      if (targetFrame) {
                        // Transfer src and mapping
                        const newEls = els.filter((e: any) => e.id !== id).map((e: any) => {
                          if (e.id === targetFrame.id) {
                            return { ...e, src: movedEl.src };
                          }
                          return e;
                        });

                        // Transfer mapping if exists
                        const imgMapping = mapping[id];
                        if (imgMapping) {
                           const newMapping = { ...mapping };
                           delete newMapping[id];
                           newMapping[targetFrame.id] = imgMapping;
                           setField('idCard.bulkWorkflow.mapping', newMapping);
                        }

                        setField(`idCard.${side}.elements`, newEls);
                        setField('idCard.selected', targetFrame.id);
                        return;
                      }
                    }

                    setField(`idCard.${side}.elements`, els.map((e: any) => e.id === id ? { ...e, ...pos } : e));
                  }}
                onDblClickElement={(id: string, sideName: string, e: any) => {
                  const side = sideName || activeSide;
                  const el = design.idCard[side].elements.find((el: any) => el.id === id);
                  if (!el) return;
                  if (el.type === 'text') {
                    const node = e.target;
                    const textPosition = node.absolutePosition();
                    const absScaleY = node.getAbsoluteScale().y;
                    const absScaleX = node.getAbsoluteScale().x;

                    // Convert Konva's absolute stage coords to Container coords
                    const stageBox = stageRef.current.container().getBoundingClientRect();

                    setEditingText({
                      id, side, value: el.content, fontStyle: el.fontStyle, color: el.fill, align: el.align || 'left',
                      fontFamily: el.fontFamily || 'sans-serif',
                      fontSize: (el.fontSize || 12) * absScaleY, 
                      x: stageBox.left + textPosition.x, 
                      y: stageBox.top + textPosition.y,
                      width: node.width() * absScaleX + 10, 
                      height: node.height() * absScaleY + 10,
                    });
                  }
                }}
              />
              </Group>
            </Layer>
          </Stage>
          {editingText && (
            <textarea
              value={editingText.value}
              onChange={(e) => setEditingText({ ...editingText, value: e.target.value })}
              onBlur={() => {
                const els = design.idCard[editingText.side].elements;
                setField(`idCard.${editingText.side}.elements`, els.map((el: any) => el.id === editingText.id ? { ...el, content: editingText.value } : el));
                setEditingText(null);
              }}
              autoFocus
              style={{
                position: 'fixed',
                top: editingText.y, left: editingText.x, width: editingText.width, height: editingText.height,
                fontSize: editingText.fontSize, fontFamily: editingText.fontFamily || 'sans-serif', fontWeight: editingText.fontStyle?.includes('bold') ? 'bold' : 'normal',
                color: editingText.color, background: 'rgba(255, 255, 255, 0.8)', border: '2px solid #5d5fef', zIndex: 100,
                outline: 'none', resize: 'none'
              }}
            />
          )}
        </div>
      </div>

      {/* Right Sidebar Toolbar */}
      <div className="w-16 bg-white border-l border-slate-200 shadow-sm flex flex-col z-10 shrink-0 items-center py-4 space-y-4">
        {/* Toggle Grid */}
        <button 
          onClick={() => setField('idCard.showGrid', !design.idCard.showGrid)}
          className={`p-2.5 rounded-xl transition-all flex flex-col items-center gap-1 group ${design.idCard.showGrid ? 'bg-indigo-50 text-indigo-600' : 'text-slate-400 hover:bg-slate-50 hover:text-slate-700'}`}
          title="Toggle Grid Lines"
        >
          <Grid3x3 size={20} />
          <span className="text-[9px] font-bold group-hover:block transition-all text-center leading-tight">Grid</span>
        </button>

        {/* Toggle Both Sides */}
        <button 
          onClick={() => setField('idCard.showBothSides', !design.idCard.showBothSides)}
          className={`p-2.5 rounded-xl transition-all flex flex-col items-center gap-1 group ${design.idCard.showBothSides ? 'bg-indigo-50 text-indigo-600' : 'text-slate-400 hover:bg-slate-50 hover:text-slate-700'}`}
          title="Toggle Two-Side Printing View"
        >
          <Columns size={20} />
          <span className="text-[9px] font-bold group-hover:block transition-all text-center leading-tight">2-Side</span>
        </button>

        <div className="w-8 h-[1px] bg-slate-100 my-1"></div>

        {/* Upload Image */}
        <label className="p-2.5 rounded-xl transition-all flex flex-col items-center gap-1 group text-slate-400 hover:bg-indigo-50 hover:text-indigo-600 cursor-pointer" title="Add Static Image">
          <input type="file" accept="image/*" className="hidden" onChange={handleStaticImageUpload} />
          <ImagePlus size={20} />
          <span className="text-[9px] font-bold group-hover:block transition-all text-center leading-tight">Image</span>
        </label>

        {/* Add Text */}
        <button 
          onClick={addStaticText}
          className="p-2.5 rounded-xl transition-all flex flex-col items-center gap-1 group text-slate-400 hover:bg-indigo-50 hover:text-indigo-600"
          title="Add Static Text"
        >
          <Type size={20} />
          <span className="text-[9px] font-bold group-hover:block transition-all text-center leading-tight">Text</span>
        </button>

        <div className="w-8 h-[1px] bg-slate-100 my-1"></div>

        {/* Zoom Controls */}
        <button 
          onClick={() => setZoom(Math.min(zoom + 0.1, 5))}
          className="p-2.5 rounded-xl transition-all flex flex-col items-center gap-1 group text-slate-400 hover:bg-slate-50 hover:text-slate-700"
          title="Zoom In"
        >
          <ZoomIn size={20} />
        </button>
        <span className="text-[10px] font-bold text-slate-500">{Math.round(zoom * 100)}%</span>
        <button 
          onClick={() => setZoom(Math.max(zoom - 0.1, 0.1))}
          className="p-2.5 rounded-xl transition-all flex flex-col items-center gap-1 group text-slate-400 hover:bg-slate-50 hover:text-slate-700"
          title="Zoom Out"
        >
          <ZoomOut size={20} />
        </button>

        <div className="w-8 h-[1px] bg-slate-100 my-1"></div>

        {/* Reset View */}
        <button 
          onClick={resetView}
          className="p-2.5 rounded-xl transition-all flex flex-col items-center gap-1 group text-slate-400 hover:bg-slate-50 hover:text-slate-700"
          title="Reset View"
        >
          <RotateCcw size={20} />
          <span className="text-[9px] font-bold group-hover:block transition-all text-center leading-tight">Reset</span>
        </button>
      </div>

    </div>
  );
}

import React, { useRef, useState } from 'react';
import { useConfiguratorStore } from '../../../store/useConfiguratorStore';
import IdCardPreview from '../IdCardPreview';
import { Stage, Layer } from 'react-konva';
import { Download, Package2, Printer, CheckCircle2, ChevronLeft, ChevronRight, Play, Grid, Columns } from 'lucide-react';
import JSZip from 'jszip';
import { saveAs } from 'file-saver';
import { jsPDF } from 'jspdf';

export default function ExportMode({ stageRef, idCardStageRef }: any) {
  const design = useConfiguratorStore(state => state.design);
  const setField = useConfiguratorStore(state => state.setField);
  const { datasetRecords, sampleRecordIndex, mapping } = design.idCard.bulkWorkflow;
  const totalRecords = datasetRecords?.length || 0;
  const showBothSides = design.idCard.showBothSides;
  const hasBackTemplate = !!design.idCard.back.backgroundImage || design.idCard.back.elements.length > 0;
  const dualSide = showBothSides && hasBackTemplate;

  const [isExporting, setIsExporting] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);
  const [previewSide, setPreviewSide] = useState<'front' | 'back'>('front');

  const { width, height } = React.useMemo(() => {
    switch (design.idCard.size) {
      case '100x70': return { width: 283, height: 198 };
      case '70x100': return { width: 198, height: 283 };
      case '54x86': return { width: 153, height: 244 };
      default: return { width: 244, height: 153 }; // 86x54
    }
  }, [design.idCard.size]);
  const exportStageRef = useRef<any>(null);
  const exportBackStageRef = useRef<any>(null);

  const handleSlider = (e: React.ChangeEvent<HTMLInputElement>) => {
    setField('idCard.bulkWorkflow.sampleRecordIndex', Number(e.target.value));
  };

  const handleExportBatch = async (format: 'pdf' | 'zip' | 'grid') => {
    if (!totalRecords || !exportStageRef.current) return;
    setIsExporting(true);
    setExportProgress(0);

    try {
      const zip = new JSZip();

      const pageW = 297, pageH = 420;

      const [cWStr, cHStr] = design.idCard.size.split('x');
      const cardWmm = parseFloat(cWStr) > 0 ? parseFloat(cWStr) : 86;
      const cardHmm = parseFloat(cHStr) > 0 ? parseFloat(cHStr) : 54;

      // Fixed grid: 5 columns × 4 rows (5 across, 4 down) — no gap between cards in a row
      const maxCols = 5;
      const maxRows = 4;

      // No horizontal gap — cards sit edge-to-edge; center the block on the page
      const gapX = 0;
      const totalGridW = maxCols * cardWmm;
      const marginX = (pageW - totalGridW) / 2;
      // Vertical spacing evenly distributed between rows
      const gapY = (pageH - maxRows * cardHmm) / (maxRows + 1);
      const marginY = gapY;

      const cardsPerPage = maxCols * maxRows; // 20 cards per page (single-side)

      // For dual-side grid: each pair-row = front card + back card (180° rotated) stacked
      // 5 columns × 2 pair-rows = 10 unique cards per page
      const pairRowH = cardHmm * 2; // front + back touching, no gap between them
      const dualMaxPairRows = 2; // 2 pair-rows (each = front + back) to fit A3
      const dualCardsPerPage = maxCols * dualMaxPairRows; // 10 cards per page
      const dualGapX = 0;
      const dualTotalGridW = maxCols * cardWmm;
      const dualMarginX = (pageW - dualTotalGridW) / 2;
      const dualGapY = (pageH - dualMaxPairRows * pairRowH) / (dualMaxPairRows + 1);
      const dualMarginY = dualGapY;

      // Helper: rotate an image data URL by 180 degrees
      const rotateImage180 = (dataUrl: string): Promise<string> => {
        return new Promise((resolve) => {
          const img = new Image();
          img.onload = () => {
            const canvas = document.createElement('canvas');
            canvas.width = img.width;
            canvas.height = img.height;
            const ctx = canvas.getContext('2d')!;
            ctx.translate(canvas.width / 2, canvas.height / 2);
            ctx.rotate(Math.PI);
            ctx.drawImage(img, -img.width / 2, -img.height / 2);
            resolve(canvas.toDataURL('image/png', 1));
          };
          img.src = dataUrl;
        });
      };

      // Helper: draw crop marks around a card position
      const drawCropMarks = (x: number, y: number, w: number, h: number) => {
        pdf.setLineWidth(0.2);
        pdf.setDrawColor('#00ffff');
        const L = 2;
        pdf.line(x - L, y, x, y);
        pdf.line(x, y - L, x, y);
        pdf.line(x + w, y, x + w + L, y);
        pdf.line(x + w, y - L, x + w, y);
        pdf.line(x - L, y + h, x, y + h);
        pdf.line(x, y + h, x, y + h + L);
        pdf.line(x + w, y + h, x + w + L, y + h);
        pdf.line(x + w, y + h, x + w, y + h + L);
      };

      let pdfFormat: [number, number] | string = [width + 20, height + 20];
      if (format === 'grid') pdfFormat = [pageW, pageH];

      const pdf = new jsPDF({
        orientation: (format === 'grid') ? 'p' : (width > height ? 'l' : 'p'),
        unit: (format === 'grid') ? 'mm' : 'px',
        format: pdfFormat 
      });

      const totalSteps = dualSide ? totalRecords * 2 : totalRecords;
      let stepsDone = 0;

      if (format === 'grid' && dualSide && exportBackStageRef.current) {
        // ===== DUAL-SIDE GRID: Front card + Back card (180° rotated) directly below =====
        for (let i = 0; i < totalRecords; i++) {
          setField('idCard.bulkWorkflow.sampleRecordIndex', i);
          await new Promise(r => setTimeout(r, 150));

          const frontDataUrl = exportStageRef.current.toDataURL({ pixelRatio: 3, quality: 1 });
          const backDataUrl = exportBackStageRef.current.toDataURL({ pixelRatio: 3, quality: 1 });
          const backRotated = await rotateImage180(backDataUrl);

          const pageIndex = i % dualCardsPerPage;
          if (pageIndex === 0 && i > 0) {
            pdf.addPage([pageW, pageH], 'p');
          }

          const col = pageIndex % maxCols;
          const logicalRow = Math.floor(pageIndex / maxCols);

          // Front card position
          const frontX = dualMarginX + col * (cardWmm + dualGapX);
          const frontY = dualMarginY + logicalRow * (pairRowH + dualGapY);

          // Back card position (directly below front, touching)
          const backX = frontX;
          const backY = frontY + cardHmm;

          pdf.addImage(frontDataUrl, 'PNG', frontX, frontY, cardWmm, cardHmm);
          drawCropMarks(frontX, frontY, cardWmm, cardHmm);

          pdf.addImage(backRotated, 'PNG', backX, backY, cardWmm, cardHmm);
          drawCropMarks(backX, backY, cardWmm, cardHmm);

          // Draw a thin dashed fold line between front and back
          pdf.setLineWidth(0.1);
          pdf.setDrawColor('#aaaaaa');
          pdf.setLineDashPattern([1, 1], 0);
          const foldY = frontY + cardHmm;
          pdf.line(frontX, foldY, frontX + cardWmm, foldY);
          pdf.setLineDashPattern([], 0);

          stepsDone += 2;
          setExportProgress(Math.round((stepsDone / totalSteps) * 100));
        }
      } else {
        // ===== SINGLE-SIDE GRID or non-grid formats =====
        for (let i = 0; i < totalRecords; i++) {
          setField('idCard.bulkWorkflow.sampleRecordIndex', i);
          await new Promise(r => setTimeout(r, 150));

          const frontDataUrl = exportStageRef.current.toDataURL({ pixelRatio: 3, quality: 1 });

          const record = datasetRecords[i];
          const nameKey = Object.keys(mapping).find(k => mapping[k]?.toLowerCase().includes('name')) || Object.keys(mapping)[0];

          let fileName = `Card_${i + 1}`;
          if (nameKey && record[mapping[nameKey]]) {
            fileName = record[mapping[nameKey]].toString().replace(/[^a-z0-9\s]/gi, '').trim() || fileName;
          }

          if (format === 'zip') {
            const imgData = frontDataUrl.split('base64,')[1];
            zip.file(`${fileName}${dualSide ? '_front' : ''}.png`, imgData, { base64: true });
          } else if (format === 'grid') {
            const pageIndex = i % cardsPerPage;
            if (pageIndex === 0 && i > 0) {
              pdf.addPage([pageW, pageH], 'p');
            }

            const col = pageIndex % maxCols;
            const row = Math.floor(pageIndex / maxCols);
            const x = marginX + col * (cardWmm + gapX);
            const y = marginY + row * (cardHmm + gapY);

            pdf.addImage(frontDataUrl, 'PNG', x, y, cardWmm, cardHmm);
            drawCropMarks(x, y, cardWmm, cardHmm);
          } else {
            if (i > 0) pdf.addPage([width + 20, height + 20]);
            pdf.addImage(frontDataUrl, 'PNG', 10, 10, width, height);
            pdf.setLineWidth(1);
            pdf.setDrawColor('#00ffff');
            pdf.line(5, 10, 5, 20);
            pdf.line(10, 5, 20, 5);
            pdf.line(width + 15, 10, width + 15, 20);
            pdf.line(width, 5, width + 10, 5);
          }

          stepsDone++;
          setExportProgress(Math.round((stepsDone / totalSteps) * 100));

          // --- BACK SIDE for non-grid formats ---
          if (dualSide && exportBackStageRef.current && format !== 'grid') {
            await new Promise(r => setTimeout(r, 100));
            const backDataUrl = exportBackStageRef.current.toDataURL({ pixelRatio: 3, quality: 1 });

            if (format === 'zip') {
              const backImgData = backDataUrl.split('base64,')[1];
              zip.file(`${fileName}_back.png`, backImgData, { base64: true });
            } else if (format === 'pdf') {
              pdf.addPage([width + 20, height + 20]);
              pdf.addImage(backDataUrl, 'PNG', 10, 10, width, height);
              pdf.setLineWidth(1);
              pdf.setDrawColor('#00ffff');
              pdf.line(5, 10, 5, 20);
              pdf.line(10, 5, 20, 5);
              pdf.line(width + 15, 10, width + 15, 20);
              pdf.line(width, 5, width + 10, 5);
            }
            stepsDone++;
            setExportProgress(Math.round((stepsDone / totalSteps) * 100));
          }
        }
      }

      if (format === 'zip') {
        const content = await zip.generateAsync({ type: 'blob' });
        saveAs(content, 'id_cards_batch.zip');
      } else if (format === 'grid') {
        pdf.save('id_cards_A3_press_sheet.pdf');
      } else {
        pdf.save('id_cards_print_ready.pdf');
      }

      try {
        const historyData = JSON.parse(localStorage.getItem('gotek-export-history') || '[]');
        const newRecord = {
            id: Date.now(),
            name: `Project Batch (${format.toUpperCase()}${dualSide ? ' - 2-Sided' : ''})`,
            format: format.toUpperCase(),
            size: format === 'zip' ? 'ZIP Archive' : 'Ready to Print',
            cards: totalRecords,
            status: 'completed',
            createdAt: new Date().toISOString().split('T')[0],
            time: 'Just now'
        };
        historyData.unshift(newRecord);
        localStorage.setItem('gotek-export-history', JSON.stringify(historyData.slice(0, 50)));
      } catch (e) {
        console.error("Could not save history to localStorage", e);
      }

    } catch (e) {
      console.error('Export failed', e);
      alert('Failed to export. Check your templates.');
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className="flex-1 flex flex-col bg-slate-50 relative">
      <div className="flex-1 flex overflow-hidden">
        {/* Review Area */}
        <div className="flex-1 p-10 flex flex-col items-center justify-center relative overflow-hidden">
          <div className="bg-white rounded-[40px] shadow-2xl border border-slate-100 p-8 flex flex-col items-center">
            <h3 className="text-xl font-black text-slate-800 tracking-tight mb-2">Final Review</h3>
            <p className="text-slate-500 text-sm font-medium mb-6 text-center max-w-sm">Use the Data Scrubber to preview the generated ID cards before exporting.</p>

            {/* Side Toggle for Preview (when dual-side) */}
            {dualSide && (
              <div className="flex items-center gap-2 mb-6 bg-slate-50 p-1 rounded-xl border border-slate-100">
                <button
                  onClick={() => setPreviewSide('front')}
                  className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all ${previewSide === 'front' ? 'bg-white shadow text-indigo-600' : 'text-slate-500 hover:bg-slate-100'}`}
                >
                  Front Side
                </button>
                <button
                  onClick={() => setPreviewSide('back')}
                  className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all ${previewSide === 'back' ? 'bg-white shadow text-indigo-600' : 'text-slate-500 hover:bg-slate-100'}`}
                >
                  Back Side
                </button>
              </div>
            )}

            <div className="flex gap-6 items-start">
              {/* Front preview */}
              <div className={`relative shadow-lg ring-1 ring-slate-200/50 rounded-2xl overflow-hidden bg-slate-50 ${dualSide && previewSide !== 'front' ? 'hidden' : ''}`} style={{ width: width, height: height }}>
                <Stage width={width} height={height} scaleX={1} scaleY={1} ref={exportStageRef}>
                  <Layer>
                    <IdCardPreview 
                      isReviewStep={true}
                      record={datasetRecords?.[sampleRecordIndex] || null}
                      mapping={mapping}
                      forceSide="front"
                    />
                  </Layer>
                </Stage>
              </div>

              {/* Back preview (only when dual-side) */}
              {dualSide && (
                <div className={`relative shadow-lg ring-1 ring-slate-200/50 rounded-2xl overflow-hidden bg-slate-50 ${previewSide !== 'back' ? 'hidden' : ''}`} style={{ width: width, height: height }}>
                  <Stage width={width} height={height} scaleX={1} scaleY={1} ref={exportBackStageRef}>
                    <Layer>
                      <IdCardPreview 
                        isReviewStep={true}
                        record={datasetRecords?.[sampleRecordIndex] || null}
                        mapping={mapping}
                        forceSide="back"
                      />
                    </Layer>
                  </Stage>
                </div>
              )}
            </div>

            {dualSide && (
              <div className="mt-4 flex items-center gap-2 text-xs font-bold text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-full">
                <Columns size={14} />
                <span>2-Sided Printing Enabled</span>
              </div>
            )}

            {/* Scrubber Tool */}
            <div className="mt-8 w-full max-w-md bg-white border border-slate-200 shadow-sm rounded-3xl p-6">
              <div className="flex items-center justify-between mb-4">
                <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Record {sampleRecordIndex + 1} of {totalRecords}</span>
                <span className="text-[10px] font-black uppercase text-indigo-500 tracking-widest flex items-center gap-1"><Play size={10}/> Zero-Latency Scrubbing</span>
              </div>
              <div className="flex items-center gap-4">
                <button 
                  onClick={() => setField('idCard.bulkWorkflow.sampleRecordIndex', Math.max(0, sampleRecordIndex - 1))}
                  className="p-2 bg-slate-50 hover:bg-slate-100 rounded-xl text-slate-600 shadow-sm"
                >
                  <ChevronLeft size={18}/>
                </button>
                <input 
                  type="range" 
                  min="0" 
                  max={Math.max(0, totalRecords - 1)} 
                  value={sampleRecordIndex} 
                  onChange={handleSlider}
                  className="flex-1 h-2 bg-slate-200 rounded-lg appearance-none cursor-grab active:cursor-grabbing accent-indigo-600"
                />
                <button 
                  onClick={() => setField('idCard.bulkWorkflow.sampleRecordIndex', Math.min(totalRecords - 1, sampleRecordIndex + 1))}
                  className="p-2 bg-slate-50 hover:bg-slate-100 rounded-xl text-slate-600 shadow-sm"
                >
                  <ChevronRight size={18}/>
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* Export Panel */}
        <div className="w-80 bg-white border-l border-slate-200 shadow-xl flex flex-col relative z-20">
          <div className="p-6 border-b border-slate-100 bg-indigo-50/30">
            <h2 className="text-xl font-black text-slate-800 tracking-tight flex items-center gap-2"><CheckCircle2 size={24} className="text-emerald-500"/> Ready to Export</h2>
            <p className="text-slate-500 text-sm mt-2 font-medium">Your design has been mapped to {totalRecords} records{dualSide ? ' (Front + Back)' : ''} flawlessly.</p>
          </div>

          <div className="flex-1 p-6 flex flex-col gap-4">
            <button 
              onClick={() => handleExportBatch('grid')}
              disabled={isExporting}
              className="w-full bg-slate-900 border border-slate-800 text-white rounded-2xl py-5 px-6 flex items-center gap-4 hover:bg-slate-800 hover:shadow-xl hover:shadow-slate-900/20 hover:-translate-y-0.5 transition-all disabled:opacity-50 disabled:cursor-not-allowed group relative overflow-hidden"
            >
              <div className="w-12 h-12 bg-white/10 rounded-full flex items-center justify-center shrink-0 group-hover:scale-110 transition-transform">
                 <Grid size={24} />
              </div>
              <div className="text-left flex-1 relative z-10">
                <div className="font-bold text-lg leading-tight">A3 PDF</div>
                <div className="text-[11px] text-slate-300 font-medium uppercase tracking-wider mt-1">{dualSide ? 'Front + Back Sheets' : 'Multi-Card A3 Grid'}</div>
              </div>
            </button>
          </div>
        </div>
      </div>

      {isExporting && (
        <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center animate-in fade-in">
          <div className="bg-white rounded-[40px] p-10 max-w-sm w-full text-center shadow-2xl border border-white/20">
            <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-3xl flex items-center justify-center mx-auto mb-6 animate-pulse shadow-inner">
               <Download size={32}/>
            </div>
            <h3 className="text-2xl font-black text-slate-800 mb-2">Generating...</h3>
            <p className="text-slate-500 font-medium mb-8">Processing {totalRecords} high-resolution cards{dualSide ? ' (Front + Back)' : ''}.</p>
            <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden shadow-inner">
              <div className="bg-indigo-600 h-full transition-all duration-300 ease-out" style={{ width: `${exportProgress}%` }} />
            </div>
            <p className="mt-4 font-black text-indigo-600 tracking-tight">{exportProgress}% Complete</p>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useConfiguratorStore } from '../../../store/useConfiguratorStore';
import { AlignLeft, AlignCenter, AlignRight, Bold, Trash2, X, Type, Image as ImageIcon } from 'lucide-react';
import { loadGoogleFont } from '../../../data/googleFonts';

export default function FloatingToolbar({ stageRef }: any) {
  const design = useConfiguratorStore(state => state.design);
  const setField = useConfiguratorStore(state => state.setField);
  const activeSide = design.idCard.activeSide;
  const selectedId = design.idCard.selected;
  const elements = design.idCard[activeSide].elements;
  const mapping = design.idCard.bulkWorkflow.mapping;
  const el = elements.find((e: any) => e.id === selectedId);

  const [position, setPosition] = useState<{ x: number, y: number } | null>(null);

  useEffect(() => {
    if (!selectedId || !stageRef.current) {
      setPosition(null);
      return;
    }

    const updatePosition = () => {
      try {
        const stage = stageRef.current;
        const node = stage.findOne(`#${selectedId}`);
        if (node) {
          const rect = node.getClientRect();
          const stageBox = stage.container().getBoundingClientRect();
          // Position slightly above the element
          setPosition({
            x: stageBox.left + rect.x + (rect.width / 2),
            y: stageBox.top + rect.y - 70
          });
        }
      } catch(e) {}
    };

    updatePosition();
    // In a real deployment, we'd bind to drag events. For now, an interval is a cheap fallback
    // to keep the floating toolbar locked to the element during drag
    const interval = setInterval(updatePosition, 50);
    return () => clearInterval(interval);
  }, [selectedId, stageRef, el?.x, el?.y, el?.width, el?.height]);

  if (!el || !position) return null;

  const updateEl = (changes: any) => {
    setField(`idCard.${activeSide}.elements`, elements.map((e: any) => e.id === selectedId ? { ...e, ...changes } : e));
  };

  const deleteEl = () => {
    setField(`idCard.${activeSide}.elements`, elements.filter((e: any) => e.id !== selectedId));
    setField('idCard.selected', null);

    // Cleanup mapping
    const newMapping = { ...mapping };
    delete newMapping[selectedId];
    setField('idCard.bulkWorkflow.mapping', newMapping);
  };

  return (
    <div 
      className="fixed z-[1000] flex items-center gap-2 bg-white/90 backdrop-blur-md rounded-2xl shadow-xl border border-white p-2 animate-in zoom-in-95 duration-200"
      style={{
        left: position.x,
        top: position.y,
        transform: 'translateX(-50%)',
        boxShadow: '0 20px 40px rgba(0,0,0,0.1)'
      }}
    >
      <div className="px-2 border-r border-slate-200">
        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-0.5">MAPPED TO</span>
        <span className="text-xs font-bold text-indigo-600 truncate max-w-[100px] block">{mapping[selectedId] || 'Manual'}</span>
      </div>

      {el.type === 'text' && (
        <div className="flex items-center gap-1.5 px-2 border-r border-slate-200">
          <label className="flex flex-col items-center">
            <span className="text-[8px] font-bold text-slate-400">Size</span>
            <input 
              type="number" 
              value={Math.round(el.fontSize || 12)} 
              onChange={(e) => updateEl({ fontSize: Number(e.target.value) })}
              className="w-10 h-7 bg-slate-50 border border-slate-200 rounded-lg text-center text-xs font-bold"
            />
          </label>
          <label className="flex flex-col items-center">
            <span className="text-[8px] font-bold text-slate-400">Font</span>
            <input 
              type="text"
              value={el.fontFamily || 'Sans-serif'}
              onChange={(e) => {
                const family = e.target.value;
                loadGoogleFont(family);
                updateEl({ fontFamily: family });
              }}
              list="font-picker-list"
              className="w-24 h-7 bg-slate-50 border border-slate-200 rounded-lg text-center text-[10px] font-bold truncate"
              style={{ fontFamily: el.fontFamily ? `"${el.fontFamily}", sans-serif` : undefined }}
            />
          </label>
          <label className="flex flex-col items-center">
            <span className="text-[8px] font-bold text-slate-400">Width</span>
            <input 
              type="number" 
              value={Math.round(el.width || 100)} 
              onChange={(e) => updateEl({ width: Math.max(20, Number(e.target.value)) })}
              className="w-12 h-7 bg-slate-50 border border-slate-200 rounded-lg text-center text-xs font-bold"
            />
          </label>
          <button 
            onClick={() => updateEl({ fontStyle: el.fontStyle === 'bold' ? 'normal' : 'bold' })}
            className={`p-1.5 rounded-lg transition-colors ${el.fontStyle === 'bold' ? 'bg-indigo-100 text-indigo-700' : 'hover:bg-slate-100 text-slate-600'}`}
          >
            <Bold size={14}/>
          </button>
          <div className="flex items-center bg-slate-50 rounded-lg p-0.5 border border-slate-200">
            <button onClick={() => updateEl({ align: 'left' })} className={`p-1 rounded ${el.align === 'left' ? 'bg-white shadow text-indigo-600' : 'text-slate-400'}`}><AlignLeft size={12}/></button>
            <button onClick={() => updateEl({ align: 'center' })} className={`p-1 rounded ${el.align === 'center' ? 'bg-white shadow text-indigo-600' : 'text-slate-400'}`}><AlignCenter size={12}/></button>
            <button onClick={() => updateEl({ align: 'right' })} className={`p-1 rounded ${el.align === 'right' ? 'bg-white shadow text-indigo-600' : 'text-slate-400'}`}><AlignRight size={12}/></button>
          </div>
          <input 
            type="color" 
            value={el.fill || '#000000'} 
            onChange={(e) => updateEl({ fill: e.target.value })}
            className="w-8 h-8 rounded-lg cursor-pointer border-none bg-transparent"
          />
        </div>
      )}

      {(el.type === 'qr' || el.type === 'barcode' || el.type === 'image' || el.type === 'frame' || el.type === 'line') && (
        <div className="flex items-center gap-2 px-2 border-r border-slate-200">
           {(el.type !== 'line') && (
             <label className="flex flex-col">
               <span className="text-[9px] font-bold text-slate-400 mb-0.5">SIZE (px)</span>
               <input type="number" value={Math.round(el.width || 50)} onChange={(e) => updateEl({ width: Number(e.target.value), height: (el.type === 'frame' ? Number(e.target.value) : Number(e.target.value)) })} className="w-12 h-6 text-xs bg-slate-50 border rounded text-center"/>
             </label>
           )}

           {el.type === 'line' && (
             <>
               <label className="flex flex-col">
                 <span className="text-[9px] font-bold text-slate-400 mb-0.5">WIDTH</span>
                 <input type="number" value={el.strokeWidth || 2} onChange={(e) => updateEl({ strokeWidth: Number(e.target.value) })} className="w-10 h-6 text-xs bg-slate-50 border rounded text-center"/>
               </label>
               <label className="flex flex-col">
                 <span className="text-[9px] font-bold text-slate-400 mb-0.5">COLOR</span>
                 <input type="color" value={el.stroke || '#5d5fef'} onChange={(e) => updateEl({ stroke: e.target.value })} className="w-6 h-6 border-none bg-transparent"/>
               </label>
             </>
           )}

           {el.type === 'image' && (
             <div className="flex flex-col ml-1">
               <span className="text-[9px] font-bold text-slate-400 mb-0.5">SHAPE</span>
               <div className="flex gap-1">
                  <button onClick={() => updateEl({ cornerRadius: 0 })} className={`p-1 rounded text-[10px] font-bold ${!el.cornerRadius ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-50 hover:bg-slate-100 text-slate-500'}`}>Sq</button>
                  <button onClick={() => updateEl({ cornerRadius: 15 })} className={`p-1 rounded text-[10px] font-bold ${el.cornerRadius === 15 ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-50 hover:bg-slate-100 text-slate-500'}`}>Ro</button>
                  <button onClick={() => updateEl({ cornerRadius: (el.width || 50) / 2 })} className={`p-1 rounded text-[10px] font-bold ${(el.cornerRadius as number) >= (el.width || 50) / 2 ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-50 hover:bg-slate-100 text-slate-500'}`}>Ci</button>
               </div>
             </div>
           )}

           {el.type === 'frame' && (
              <div className="flex flex-col ml-1">
                <span className="text-[9px] font-bold text-slate-400 mb-0.5">PHOTO</span>
                <label className="flex items-center gap-1.5 px-2 py-1 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg cursor-pointer transition-colors shadow-sm">
                  <ImageIcon size={12} />
                  <span className="text-[10px] font-bold whitespace-nowrap">Replace</span>
                  <input 
                    type="file" 
                    accept="image/*" 
                    className="hidden" 
                    onChange={(e) => {
                      const file = e.target.files?.[0];
                      if (file) {
                        const reader = new FileReader();
                        reader.onload = (ev) => updateEl({ src: ev.target?.result as string });
                        reader.readAsDataURL(file);
                      }
                    }} 
                  />
                </label>
              </div>
           )}

           {(el.type === 'qr' || el.type === 'barcode') && (
             <label className="flex flex-col">
               <span className="text-[9px] font-bold text-slate-400 mb-0.5">COLOR</span>
               <input type="color" value={el.fill || '#000000'} onChange={(e) => updateEl({ fill: e.target.value })} className="w-6 h-6 border-none bg-transparent"/>
             </label>
           )}
        </div>
      )}

      <div className="px-2 flex gap-1">
        <button onClick={deleteEl} className="p-1.5 text-red-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"><Trash2 size={16}/></button>
        <button onClick={() => setField('idCard.selected', null)} className="p-1.5 text-slate-400 hover:text-slate-600 hover:bg-slate-50 rounded-lg transition-colors"><X size={16}/></button>
      </div>
    </div>
  );
}

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Search, Type, ChevronDown, X } from 'lucide-react';
import { GOOGLE_FONTS, FONT_CATEGORIES, loadGoogleFont, preloadFontBatch, isFontLoaded, FontCategory } from '../../../data/googleFonts';
import { useConfiguratorStore } from '../../../store/useConfiguratorStore';

const VISIBLE_BATCH_SIZE = 40;

export default function FontBar() {
  const design = useConfiguratorStore(state => state.design);
  const setField = useConfiguratorStore(state => state.setField);
  const activeSide = design.idCard.activeSide;
  const selectedId = design.idCard.selected;
  const elements = design.idCard[activeSide].elements;
  const selectedEl = elements.find((e: any) => e.id === selectedId);
  const isTextSelected = selectedEl?.type === 'text';

  const [isOpen, setIsOpen] = useState(false);
  const [search, setSearch] = useState('');
  const [activeCategory, setActiveCategory] = useState<FontCategory | 'all'>('all');
  const [visibleCount, setVisibleCount] = useState(VISIBLE_BATCH_SIZE);
  const searchInputRef = useRef<HTMLInputElement>(null);
  const listRef = useRef<HTMLDivElement>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Close dropdown on outside click
  useEffect(() => {
    const handleClick = (e: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setIsOpen(false);
      }
    };
    if (isOpen) document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, [isOpen]);

  // Preload the first batch of fonts on mount
  useEffect(() => {
    preloadFontBatch(GOOGLE_FONTS.slice(0, 30).map(f => f.family));
  }, []);

  // Focus search input when dropdown opens
  useEffect(() => {
    if (isOpen && searchInputRef.current) {
      searchInputRef.current.focus();
    }
    if (isOpen) {
      setVisibleCount(VISIBLE_BATCH_SIZE);
    }
  }, [isOpen]);

  // Filter fonts
  const filtered = useMemo(() => {
    let result = [...GOOGLE_FONTS];
    if (activeCategory !== 'all') result = result.filter(f => f.category === activeCategory);
    if (search.trim()) {
      const q = search.toLowerCase();
      result = result.filter(f => f.family.toLowerCase().includes(q));
    }
    return result;
  }, [search, activeCategory]);

  const visible = filtered.slice(0, visibleCount);

  // Lazy-load fonts as they appear
  useEffect(() => {
    const families = visible.map(f => f.family).filter(f => !isFontLoaded(f));
    if (families.length > 0) {
      preloadFontBatch(families);
    }
  }, [visible]);

  // Infinite scroll
  const handleScroll = useCallback(() => {
    if (!listRef.current) return;
    const { scrollTop, scrollHeight, clientHeight } = listRef.current;
    if (scrollTop + clientHeight >= scrollHeight - 100) {
      setVisibleCount(prev => Math.min(prev + VISIBLE_BATCH_SIZE, filtered.length));
    }
  }, [filtered.length]);

  const applyFont = (family: string) => {
    if (!selectedId) return;
    loadGoogleFont(family);
    setField(
      `idCard.${activeSide}.elements`,
      elements.map((e: any) => e.id === selectedId ? { ...e, fontFamily: family } : e)
    );
    setIsOpen(false);
  };

  const currentFont = selectedEl?.fontFamily || 'Sans-serif';

  return (
    <div ref={dropdownRef} className="relative">
      {/* Trigger Button */}
      <button
        onClick={() => isTextSelected && setIsOpen(!isOpen)}
        disabled={!isTextSelected}
        className={`flex items-center gap-2 px-3 py-1.5 text-xs font-bold rounded-lg transition-all ${
          isTextSelected
            ? isOpen
              ? 'bg-indigo-50 text-indigo-700 shadow-sm ring-1 ring-indigo-200'
              : 'text-slate-600 hover:bg-slate-50 hover:text-slate-800'
            : 'text-slate-300 cursor-not-allowed'
        }`}
        title={isTextSelected ? 'Change font' : 'Select a text element first'}
      >
        <Type size={14} />
        <span className="max-w-[120px] truncate" style={{ fontFamily: isTextSelected ? `"${currentFont}", sans-serif` : undefined }}>
          {currentFont}
        </span>
        <ChevronDown size={12} className={`transition-transform ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {/* Dropdown Panel */}
      {isOpen && isTextSelected && (
        <div className="absolute top-full left-0 mt-2 w-[380px] bg-white rounded-2xl shadow-2xl border border-slate-200 z-[200] overflow-hidden animate-in zoom-in-95 fade-in duration-200"
          style={{ boxShadow: '0 25px 60px rgba(0,0,0,0.18)' }}
        >
          {/* Header */}
          <div className="p-3 border-b border-slate-100 bg-slate-50/50">
            <div className="relative">
              <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
              <input
                ref={searchInputRef}
                type="text"
                value={search}
                onChange={e => { setSearch(e.target.value); setVisibleCount(VISIBLE_BATCH_SIZE); }}
                placeholder="Search 1000+ fonts..."
                className="w-full pl-9 pr-8 py-2 bg-white border border-slate-200 rounded-xl text-xs focus:outline-none focus:ring-2 focus:ring-indigo-400 focus:border-transparent transition-all"
              />
              {search && (
                <button onClick={() => setSearch('')} className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-300 hover:text-slate-600">
                  <X size={14} />
                </button>
              )}
            </div>

            {/* Category pills */}
            <div className="flex items-center gap-1.5 mt-2 overflow-x-auto pb-0.5 custom-scrollbar">
              <button
                onClick={() => { setActiveCategory('all'); setVisibleCount(VISIBLE_BATCH_SIZE); }}
                className={`px-2.5 py-1 rounded-full text-[10px] font-bold whitespace-nowrap transition-all ${
                  activeCategory === 'all'
                    ? 'bg-indigo-600 text-white shadow-sm'
                    : 'bg-white border border-slate-200 text-slate-500 hover:bg-slate-50'
                }`}
              >
                All ({GOOGLE_FONTS.length})
              </button>
              {FONT_CATEGORIES.map(cat => {
                const count = GOOGLE_FONTS.filter(f => f.category === cat).length;
                return (
                  <button
                    key={cat}
                    onClick={() => { setActiveCategory(cat); setVisibleCount(VISIBLE_BATCH_SIZE); }}
                    className={`px-2.5 py-1 rounded-full text-[10px] font-bold whitespace-nowrap capitalize transition-all ${
                      activeCategory === cat
                        ? 'bg-indigo-600 text-white shadow-sm'
                        : 'bg-white border border-slate-200 text-slate-500 hover:bg-slate-50'
                    }`}
                  >
                    {cat} ({count})
                  </button>
                );
              })}
            </div>
          </div>

          {/* Font List */}
          <div
            ref={listRef}
            onScroll={handleScroll}
            className="max-h-[320px] overflow-y-auto custom-scrollbar"
          >
            {visible.length === 0 ? (
              <div className="p-8 text-center">
                <Type size={28} className="mx-auto text-slate-200 mb-2" />
                <p className="text-xs text-slate-400 font-medium">No fonts found for "{search}"</p>
              </div>
            ) : (
              visible.map((font) => {
                const isActive = currentFont === font.family;
                return (
                  <button
                    key={font.family}
                    onClick={() => applyFont(font.family)}
                    className={`w-full text-left px-4 py-2.5 flex items-center justify-between group transition-all border-b border-slate-50 last:border-0 ${
                      isActive
                        ? 'bg-indigo-50 border-indigo-100'
                        : 'hover:bg-slate-50'
                    }`}
                  >
                    <div className="flex-1 min-w-0">
                      <span
                        className={`text-sm block truncate ${isActive ? 'text-indigo-700 font-bold' : 'text-slate-800'}`}
                        style={{ fontFamily: `"${font.family}", ${font.category}` }}
                      >
                        {font.family}
                      </span>
                      <span
                        className="text-[11px] text-slate-400 block truncate mt-0.5"
                        style={{ fontFamily: `"${font.family}", ${font.category}` }}
                      >
                        The quick brown fox jumps
                      </span>
                    </div>
                    <div className="flex items-center gap-2 shrink-0 ml-3">
                      <span className={`text-[9px] font-bold uppercase px-1.5 py-0.5 rounded-full ${
                        font.category === 'sans-serif' ? 'bg-blue-50 text-blue-500' :
                        font.category === 'serif' ? 'bg-emerald-50 text-emerald-600' :
                        font.category === 'display' ? 'bg-amber-50 text-amber-600' :
                        font.category === 'handwriting' ? 'bg-purple-50 text-purple-600' :
                        'bg-slate-100 text-slate-500'
                      }`}>
                        {font.category}
                      </span>
                      {isActive && (
                        <div className="w-2 h-2 rounded-full bg-indigo-500" />
                      )}
                    </div>
                  </button>
                );
              })
            )}
            {visibleCount < filtered.length && (
              <div className="p-3 text-center">
                <span className="text-[10px] text-slate-400 font-medium">
                  Showing {visible.length} of {filtered.length} fonts • scroll for more
                </span>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useRef } from 'react';
