                    ? 'border-emerald-300 bg-emerald-50 text-emerald-700 hover:bg-emerald-100 cursor-pointer' 
                    : 'border-orange-200 bg-orange-50/50 hover:bg-orange-50 text-orange-600 cursor-pointer'
