  // Flag to suppress saveState during programmatic canvas operations (load/clear)
  const suppressSave = useRef(false);
  const currentPageRef = useRef(1);

  // Initialize Fabric canvas
  useEffect(() => {
    if (!canvasRef.current || fabricRef.current) return;

    fabricRef.current = new Canvas(canvasRef.current, {
      width: 600,
      height: 800,
      backgroundColor: '#f1f5f9',
    });

    // Snapping logic
    const grid = 10;
    fabricRef.current.on('object:moving', (options) => {
      if (options.target) {
        options.target.set({
          left: Math.round(options.target.left! / grid) * grid,
          top: Math.round(options.target.top! / grid) * grid,
        });
      }
    });

    fabricRef.current.on('object:added', () => { if (!suppressSave.current) saveState(); });
    fabricRef.current.on('object:modified', () => { if (!suppressSave.current) saveState(); });
    fabricRef.current.on('object:removed', () => { if (!suppressSave.current) saveState(); });

    // Handle Image Hover — change cursor for replaceable objects
    fabricRef.current.on('mouse:over', (e) => {
      const obj = e.target;
      if (obj && (obj as any).isPDFImage) {
        obj.set('hoverCursor', 'pointer');
      }
    });

    // Handle Object Click for Replacement
    fabricRef.current.on('mouse:down', (e) => {
      const obj = e.target;
      if (obj && (obj as any).isPDFImage) {
        handleReplaceImage(obj);
      }
    });

    return () => {
      fabricRef.current?.dispose();
      fabricRef.current = null;
    };
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const saveState = useCallback(() => {
    if (!fabricRef.current) return;
    const json = JSON.stringify(fabricRef.current.toObject());
    setHistory(prev => [...prev.slice(-49), json]);
    setRedoStack([]);
  }, []);

  const handleUndo = () => {
    if (history.length <= 1 || !fabricRef.current) return;
    const newHistory = [...history];
    const current = newHistory.pop();
    if (!current) return;

    setRedoStack(prev => [...prev, current]);
    setHistory(newHistory);

    const last = newHistory[newHistory.length - 1];
    suppressSave.current = true;
    fabricRef.current.loadFromJSON(JSON.parse(last)).then(() => {
      fabricRef.current?.requestRenderAll();
      suppressSave.current = false;
    });
  };

  const handleRedo = () => {
    if (redoStack.length === 0 || !fabricRef.current) return;
    const newRedo = [...redoStack];
    const next = newRedo.pop();
    if (!next) return;

    setHistory(prev => [...prev, next]);
    setRedoStack(newRedo);

    suppressSave.current = true;
    fabricRef.current.loadFromJSON(JSON.parse(next)).then(() => {
      fabricRef.current?.requestRenderAll();
      suppressSave.current = false;
    });
  };

  // Save current page state before switching — reads from ref to avoid stale closures
  const saveCurrentPageState = useCallback(() => {
    if (!fabricRef.current || !isLoaded) return;

    const json = JSON.stringify(fabricRef.current.toObject());
    const bgImg = fabricRef.current.backgroundImage as any;
    const bgDataUrl = bgImg?.getSrc?.() || '';

    const updated = new Map(pageStatesRef.current);
    updated.set(currentPageRef.current, {
      json,
      bgDataUrl,
      width: fabricRef.current.width!,
      height: fabricRef.current.height!,
    });
    pageStatesRef.current = updated;
    _setPageStates(updated);
  }, [isLoaded]);

  /**
   * Render a single PDF page onto the Fabric canvas.
   * The PDF is rendered as a static background image (no masking).
   * Text items are extracted and placed as editable IText objects on top.
   */
  const renderPageToCanvas = async (
    canvas: Canvas,
    pdfDoc: any,
    file: File,
    pageNum: number
  ) => {
    const page = await pdfDoc.getPage(pageNum);
    const viewport1 = page.getViewport({ scale: 1.0 });

    // Render PDF page as a plain background image (NO masking)
    const dataUrl = await loadPDFPageAsImage(file, pageNum);
    const img = await FabricImage.fromURL(dataUrl);

    const canvasWidth = 600;
    const scale = canvasWidth / img.width!;
    const canvasHeight = img.height! * scale;

    canvas.setDimensions({ width: canvasWidth, height: canvasHeight });
    canvas.clear();

    img.set({ scaleX: scale, scaleY: scale, selectable: false, evented: false });
    canvas.backgroundImage = img;

    // Extract text content for interactive editing
    const textContent = await page.getTextContent();
    const pdfToCanvasScale = canvasWidth / viewport1.width;

    const textItems = textContent.items
      .filter((item: any) => item.str && item.str.trim() && item.transform && item.transform.length >= 6)
      .map((item: any) => {
        const transform = item.transform;
        const fontSize = Math.sqrt(transform[0] * transform[0] + transform[1] * transform[1]);
        return {
          str: item.str,
          x: transform[4],
          y: transform[5],
          width: item.width || 0,
          height: item.height || fontSize,
          fontSize,
          fontName: item.fontName,
        };
      });

    // Add editable text objects
    for (const item of textItems) {
      const text = new IText(item.str, {
        left: item.x * pdfToCanvasScale,
        top: (viewport1.height - item.y - item.fontSize) * pdfToCanvasScale,
        fontSize: item.fontSize * pdfToCanvasScale,
        fontFamily: 'Inter, sans-serif',
        fill: '#000000',
      });
      canvas.add(text);
    }

    // Detect potential image placeholders (heuristic: text ending in .jpg)
    const potentialImages = textItems.filter((t: any) => t.str.toLowerCase().endsWith('.jpg'));
    for (const item of potentialImages) {
      const rect = new Rect({
        left: item.x * pdfToCanvasScale,
        top: (viewport1.height - item.y - 120) * pdfToCanvasScale,
        width: 100 * pdfToCanvasScale,
        height: 120 * pdfToCanvasScale,
        fill: 'rgba(255,255,255,0.5)',
        stroke: '#3b82f6',
        strokeWidth: 1,
        strokeDashArray: [5, 5],
      });
      (rect as any).isPDFImage = true;
      (rect as any).name = 'Replaceable Image';
      canvas.add(rect);
    }

    canvas.requestRenderAll();
  };

  // Load a specific page onto the canvas — uses refs for freshest data
  const loadPageOntoCanvas = useCallback(async (pageNum: number) => {
    if (!fabricRef.current || !pdfFileRef.current) return;

    const canvas = fabricRef.current;
    suppressSave.current = true;

    try {
      // Read from ref (not state) to avoid stale closures
      const savedState = pageStatesRef.current.get(pageNum);

      if (savedState) {
        canvas.setDimensions({ width: savedState.width, height: savedState.height });
        await canvas.loadFromJSON(JSON.parse(savedState.json));

        const img = await FabricImage.fromURL(savedState.bgDataUrl);
        const scale = savedState.width / img.width!;
        img.set({ scaleX: scale, scaleY: scale, selectable: false, evented: false });
        canvas.backgroundImage = img;
        canvas.requestRenderAll();
      } else {
        // Reuse the cached PDF document or load a fresh one
        if (!pdfDocRef.current) {
          const arrayBuffer = await pdfFileRef.current.arrayBuffer();
          pdfDocRef.current = await pdfjsLib.getDocument({ data: new Uint8Array(arrayBuffer) }).promise;
        }
        await renderPageToCanvas(canvas, pdfDocRef.current, pdfFileRef.current, pageNum);
      }

      setHistory([]);
      setRedoStack([]);
    } finally {
      suppressSave.current = false;
      // Capture initial state for undo
      saveState();
    }
  }, [saveState]);

  // Handle PDF upload
  const handlePDFUpload = async (file: File) => {
    try {
      toast.loading('Loading PDF...', { id: 'pdf-load' });
      pdfFileRef.current = file;
      setPdfFile(file);
      pageStatesRef.current = new Map();
      _setPageStates(new Map());

      const arrayBuffer = await file.arrayBuffer();
      const pdf = await pdfjsLib.getDocument({ data: new Uint8Array(arrayBuffer) }).promise;
      pdfDocRef.current = pdf;

      const numPages = pdf.numPages;
      setTotalPages(numPages);
      totalPagesRef.current = numPages;
      setCurrentPage(1);
      currentPageRef.current = 1;
      setIsLoaded(true);

      if (!fabricRef.current) return;

      suppressSave.current = true;

      await renderPageToCanvas(fabricRef.current, pdf, file, 1);

      setHistory([]);
      setRedoStack([]);
      suppressSave.current = false;
      saveState();

      toast.success(`PDF loaded — ${numPages} page${numPages > 1 ? 's' : ''}`, { id: 'pdf-load' });
    } catch (error: any) {
      console.error('PDF upload error:', error);
      suppressSave.current = false;
      toast.error(`Failed to load PDF: ${error?.message || String(error)}`, { id: 'pdf-load' });
    }
  };

  // Handle page change
  const handlePageChange = async (newPage: number) => {
    if (newPage < 1 || newPage > totalPagesRef.current || newPage === currentPageRef.current) return;

    // Save before switching
    saveCurrentPageState();
    currentPageRef.current = newPage;
    setCurrentPage(newPage);
    await loadPageOntoCanvas(newPage);
  };

  // Add text
  const addText = () => {
    if (!fabricRef.current) return;
    const text = new IText('Edit me', {
      left: 100, top: 100,
      fontSize: 20, fontFamily: 'Inter, sans-serif', fill: '#000000',
    });
    (text as any).name = 'Text';
    fabricRef.current.add(text);
    fabricRef.current.setActiveObject(text);
    fabricRef.current.requestRenderAll();
  };

  // Add image
  const addImage = () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = async (e: any) => {
      const file = e.target.files?.[0];
      if (!file || !fabricRef.current) return;

      const reader = new FileReader();
      reader.onload = async (evt) => {
        const dataUrl = evt.target?.result as string;
        const img = await FabricImage.fromURL(dataUrl);
        img.scaleToWidth(150);
        img.set({ left: 100, top: 100 });
        (img as any).name = `Image: ${file.name}`;
        fabricRef.current!.add(img);
        fabricRef.current!.setActiveObject(img);
        fabricRef.current!.requestRenderAll();
      };
      reader.readAsDataURL(file);
    };
    input.click();
  };

  const handleReplaceImage = (targetObj: any) => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = async (e: any) => {
      const file = e.target.files?.[0];
      if (!file || !fabricRef.current) return;

      const reader = new FileReader();
      reader.onload = async (evt) => {
        const dataUrl = evt.target?.result as string;
        const img = await FabricImage.fromURL(dataUrl);

        // Preserve dimensions
        const targetWidth = targetObj.getScaledWidth();
        const targetHeight = targetObj.getScaledHeight();

        img.scaleToWidth(targetWidth);
        if (img.getScaledHeight() > targetHeight) {
            img.scaleToHeight(targetHeight);
        }

        img.set({ 
            left: targetObj.left, 
            top: targetObj.top,
        });

        (img as any).isPDFImage = true;
        (img as any).name = `Replaced: ${file.name}`;

        fabricRef.current!.add(img);
        fabricRef.current!.remove(targetObj);
        fabricRef.current!.setActiveObject(img);
        fabricRef.current!.requestRenderAll();
        toast.success('Image replaced successfully');
      };
      reader.readAsDataURL(file);
    };
    input.click();
  };

  // White-out tool
  const addWhiteOut = () => {
    if (!fabricRef.current) return;
    const rect = new Rect({
      left: 100, top: 100,
      width: 150, height: 30,
      fill: '#ffffff', stroke: '#e2e8f0', strokeWidth: 1,
    });
    (rect as any).name = 'White-out';
    fabricRef.current.add(rect);
    fabricRef.current.setActiveObject(rect);
    fabricRef.current.requestRenderAll();
    toast.info('White-out rectangle added — drag and resize to cover mistakes');
  };

  // Add shape
  const addShape = () => {
    if (!fabricRef.current) return;
    const rect = new Rect({
      left: 100, top: 100,
      width: 120, height: 80,
      fill: 'rgba(59, 130, 246, 0.15)', stroke: '#3b82f6', strokeWidth: 2, rx: 4, ry: 4,
    });
    (rect as any).name = 'Shape';
    fabricRef.current.add(rect);
    fabricRef.current.setActiveObject(rect);
    fabricRef.current.requestRenderAll();
  };

  // Export corrected PDF
  const handleExport = async () => {
    if (!fabricRef.current || !pdfFileRef.current) return;

    try {
      toast.loading('Generating corrected PDF...', { id: 'export' });

      // Flush current page to ref before exporting
      saveCurrentPageState();

      const pages: { dataUrl: string; width: number; height: number }[] = [];
      const totalPgs = totalPagesRef.current;
      const curPage = currentPageRef.current;

      for (let i = 1; i <= totalPgs; i++) {
        const saved = pageStatesRef.current.get(i);

        if (i === curPage) {
          // Current page — export directly from live canvas
          const dataUrl = fabricRef.current.toDataURL({ multiplier: 2 });
          pages.push({
            dataUrl,
            width: fabricRef.current.width! * 2,
            height: fabricRef.current.height! * 2,
          });
        } else if (saved) {
          // Edited page — reconstruct on a temp canvas
          const tempCanvas = document.createElement('canvas');
          const tempFabric = new Canvas(tempCanvas, { width: saved.width, height: saved.height });

          suppressSave.current = true;
          const bgImg = await FabricImage.fromURL(saved.bgDataUrl);
          const scale = saved.width / bgImg.width!;
          bgImg.set({ scaleX: scale, scaleY: scale, selectable: false, evented: false });
          tempFabric.backgroundImage = bgImg;
          await tempFabric.loadFromJSON(JSON.parse(saved.json));
          tempFabric.requestRenderAll();

          const dataUrl = tempFabric.toDataURL({ multiplier: 2 });
          pages.push({ dataUrl, width: saved.width * 2, height: saved.height * 2 });
          tempFabric.dispose();
          suppressSave.current = false;
        } else {
          // Unedited page — render straight from PDF
          const dataUrl = await loadPDFPageAsImage(pdfFileRef.current!, i);
          const img = new Image();
          await new Promise<void>((resolve) => { img.onload = () => resolve(); img.src = dataUrl; });
          pages.push({ dataUrl, width: img.width, height: img.height });
        }
      }

      const filename = pdfFileRef.current!.name.replace(/\.pdf$/i, '_edited.pdf');
      await exportMultiPagePDF(pages, filename);
      toast.success('PDF downloaded successfully!', { id: 'export' });
    } catch (error) {
      console.error(error);
      suppressSave.current = false;
      toast.error('Failed to export PDF', { id: 'export' });
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-220px)] bg-[#f8fafc] rounded-xl border border-slate-200 overflow-hidden">
      <EditorToolbar
        onUploadPDF={handlePDFUpload}
        onAddText={addText}
        onAddImage={addImage}
        onWhiteOut={addWhiteOut}
        onAddShape={addShape}
        onUndo={handleUndo}
        onRedo={handleRedo}
        onExport={handleExport}
        isLoaded={isLoaded}
        currentPage={currentPage}
        totalPages={totalPages}
        onPageChange={handlePageChange}
      />

      <div className="flex flex-1 overflow-hidden p-4 gap-4">
        {/* Canvas area */}
        <div className="flex-1 flex justify-center items-start overflow-auto bg-slate-200/50 rounded-xl border-2 border-dashed border-slate-300 p-6 relative">
          <div className={`flex flex-col items-center w-full justify-center py-20 text-slate-400 ${isLoaded ? 'hidden' : ''}`}>
            <svg className="w-16 h-16 mb-4 text-slate-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5}
                d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
            </svg>
            <p className="text-sm font-medium">Upload a PDF to start editing</p>
            <p className="text-xs mt-1">Supports multi-page ID card PDFs</p>
          </div>
          <Card className={`shadow-2xl overflow-hidden bg-white ${!isLoaded ? 'hidden' : ''}`}>
            <canvas id="editor-canvas" ref={canvasRef} />
          </Card>
        </div>

        {/* Right panel */}
        <PropertiesPanel canvas={fabricRef.current} />
      </div>
    </div>
  );
};

export default PDFEditorTab;

import React, { useState, useEffect, useCallback } from 'react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { 
  Layers, Lock, Unlock, Eye, EyeOff, Trash2,
  AlignLeft, AlignCenter, AlignRight,
  AlignStartVertical, AlignEndVertical, AlignCenterVertical
} from 'lucide-react';
import { Separator } from '@/components/ui/separator';

interface PropertiesPanelProps {
  canvas: any; // fabric.Canvas
}

const PropertiesPanel: React.FC<PropertiesPanelProps> = ({ canvas }) => {
  const [selectedObject, setSelectedObject] = useState<any>(null);
  const [layers, setLayers] = useState<any[]>([]);
  const [properties, setProperties] = useState({
    fontSize: 20,
    fill: '#000000',
    opacity: 1,
    left: 0,
    top: 0,
    width: 0,
    height: 0,
  });

  const updateLayers = useCallback(() => {
    if (!canvas) return;
    const objects = canvas.getObjects().reverse();
    setLayers(
      objects.map((obj: any, index: number) => ({
        id: obj.name || `Layer ${objects.length - index}`,
        type: obj.type,
        locked: !obj.selectable,
        visible: obj.visible !== false,
        ref: obj,
      }))
    );
  }, [canvas]);

  const updateProperties = useCallback(() => {
    if (!canvas) return;
    const active = canvas.getActiveObject();
    if (active) {
      setSelectedObject(active);
      setProperties({
        fontSize: active.fontSize || 20,
        fill: active.fill || '#000000',
        opacity: active.opacity ?? 1,
        left: Math.round(active.left || 0),
        top: Math.round(active.top || 0),
        width: Math.round((active.width || 0) * (active.scaleX || 1)),
        height: Math.round((active.height || 0) * (active.scaleY || 1)),
      });
    } else {
      setSelectedObject(null);
    }
  }, [canvas]);

  useEffect(() => {
    if (!canvas) return;

    const handlers = {
      'object:added': updateLayers,
      'object:removed': updateLayers,
      'object:modified': () => { updateLayers(); updateProperties(); },
      'selection:created': updateProperties,
      'selection:updated': updateProperties,
      'selection:cleared': () => setSelectedObject(null),
    };

    Object.entries(handlers).forEach(([event, handler]) => {
      canvas.on(event, handler);
    });

    updateLayers();

    return () => {
      Object.entries(handlers).forEach(([event, handler]) => {
        canvas.off(event, handler);
      });
    };
  }, [canvas, updateLayers, updateProperties]);

  const handlePropertyChange = (key: string, value: any) => {
    if (!selectedObject || !canvas) return;

    if (key === 'fontSize') {
      selectedObject.set({ fontSize: Number(value) });
    } else if (key === 'fill') {
      selectedObject.set({ fill: value });
    } else if (key === 'opacity') {
      selectedObject.set({ opacity: Number(value) });
    } else if (key === 'left') {
      selectedObject.set({ left: Number(value) });
    } else if (key === 'top') {
      selectedObject.set({ top: Number(value) });
    }

    canvas.requestRenderAll();
    setProperties((prev: typeof properties) => ({ ...prev, [key]: value }));
  };

  const handleDelete = () => {
    if (!selectedObject || !canvas) return;
    canvas.remove(selectedObject);
    canvas.discardActiveObject();
    canvas.requestRenderAll();
    setSelectedObject(null);
  };

  const toggleLock = (layer: any) => {
    layer.ref.set({ selectable: layer.locked, evented: layer.locked });
    canvas?.requestRenderAll();
    updateLayers();
  };

  const toggleVisibility = (layer: any) => {
    layer.ref.set({ visible: !layer.visible });
    canvas?.requestRenderAll();
    updateLayers();
  };

  const alignObject = (type: string) => {
    if (!selectedObject || !canvas) return;

    const canvasWidth = canvas.width!;
    const canvasHeight = canvas.height!;
    const objWidth = selectedObject.getScaledWidth();
    const objHeight = selectedObject.getScaledHeight();

    switch (type) {
      case 'left': selectedObject.set({ left: 0 }); break;
      case 'center': selectedObject.set({ left: (canvasWidth - objWidth) / 2 }); break;
      case 'right': selectedObject.set({ left: canvasWidth - objWidth }); break;
      case 'top': selectedObject.set({ top: 0 }); break;
      case 'middle': selectedObject.set({ top: (canvasHeight - objHeight) / 2 }); break;
      case 'bottom': selectedObject.set({ top: canvasHeight - objHeight }); break;
    }

    canvas.requestRenderAll();
    updateProperties();
  };

  return (
    <div className="w-72 flex flex-col gap-4 overflow-y-auto max-h-full">
      {/* Properties Panel */}
      {selectedObject && (
        <Card className="p-4 bg-white shadow-sm border-slate-200">
          <h3 className="text-xs font-bold text-slate-700 uppercase tracking-wider mb-3 flex items-center justify-between">
            Properties
            <Button
              variant="ghost"
              size="icon"
              className="h-6 w-6 text-red-400 hover:text-red-600 hover:bg-red-50"
              onClick={handleDelete}
              title="Delete selected"
            >
              <Trash2 size={12} />
            </Button>
          </h3>

          <div className="space-y-3">
            {/* Font Size (only for text) */}
            {selectedObject.type === 'i-text' && (
              <div>
                <label className="text-[10px] text-slate-500 font-semibold uppercase tracking-wider">Font Size</label>
                <input
                  type="number"
                  value={properties.fontSize}
                  onChange={(e) => handlePropertyChange('fontSize', e.target.value)}
                  className="w-full mt-1 px-2.5 py-1.5 border border-slate-200 rounded-lg text-xs"
                  min={8}
                  max={200}
                />
              </div>
            )}

            {/* Color */}
            <div>
              <label className="text-[10px] text-slate-500 font-semibold uppercase tracking-wider">Color</label>
              <div className="flex items-center gap-2 mt-1">
                <input
                  type="color"
                  value={typeof properties.fill === 'string' ? properties.fill : '#000000'}
                  onChange={(e) => handlePropertyChange('fill', e.target.value)}
                  className="w-8 h-8 rounded border border-slate-200 cursor-pointer"
                />
                <span className="text-xs text-slate-600 font-mono">
                  {typeof properties.fill === 'string' ? properties.fill : '#000000'}
                </span>
              </div>
            </div>

            {/* Opacity */}
            <div>
              <label className="text-[10px] text-slate-500 font-semibold uppercase tracking-wider">
                Opacity ({Math.round(properties.opacity * 100)}%)
              </label>
              <input
                type="range"
                min={0}
                max={1}
                step={0.05}
                value={properties.opacity}
                onChange={(e) => handlePropertyChange('opacity', e.target.value)}
                className="w-full mt-1"
              />
            </div>

            <Separator />

            {/* Alignment */}
            <div>
              <label className="text-[10px] text-slate-500 font-semibold uppercase tracking-wider mb-2 block">Alignment</label>
              <div className="flex flex-wrap gap-1">
                <Button variant="outline" size="icon" className="h-8 w-8" onClick={() => alignObject('left')} title="Align Left"><AlignLeft size={14}/></Button>
                <Button variant="outline" size="icon" className="h-8 w-8" onClick={() => alignObject('center')} title="Align Center"><AlignCenter size={14}/></Button>
                <Button variant="outline" size="icon" className="h-8 w-8" onClick={() => alignObject('right')} title="Align Right"><AlignRight size={14}/></Button>
                <Separator orientation="vertical" className="h-6 mx-1" />
                <Button variant="outline" size="icon" className="h-8 w-8" onClick={() => alignObject('top')} title="Align Top"><AlignStartVertical size={14}/></Button>
                <Button variant="outline" size="icon" className="h-8 w-8" onClick={() => alignObject('middle')} title="Align Middle"><AlignCenterVertical size={14}/></Button>
                <Button variant="outline" size="icon" className="h-8 w-8" onClick={() => alignObject('bottom')} title="Align Bottom"><AlignEndVertical size={14}/></Button>
              </div>
            </div>

            <Separator />

            {/* Position */}
            <div className="grid grid-cols-2 gap-2">
              <div>
                <label className="text-[10px] text-slate-500 font-semibold uppercase tracking-wider">X</label>
                <input
                  type="number"
                  value={properties.left}
                  onChange={(e) => handlePropertyChange('left', e.target.value)}
                  className="w-full mt-1 px-2.5 py-1.5 border border-slate-200 rounded-lg text-xs"
                />
              </div>
              <div>
                <label className="text-[10px] text-slate-500 font-semibold uppercase tracking-wider">Y</label>
                <input
                  type="number"
                  value={properties.top}
                  onChange={(e) => handlePropertyChange('top', e.target.value)}
                  className="w-full mt-1 px-2.5 py-1.5 border border-slate-200 rounded-lg text-xs"
                />
              </div>
            </div>

            {/* Size (read-only) */}
            <div className="grid grid-cols-2 gap-2">
              <div>
                <label className="text-[10px] text-slate-500 font-semibold uppercase tracking-wider">W</label>
                <div className="mt-1 px-2.5 py-1.5 bg-slate-50 border border-slate-100 rounded-lg text-xs text-slate-500">
                  {properties.width}px
                </div>
              </div>
              <div>
                <label className="text-[10px] text-slate-500 font-semibold uppercase tracking-wider">H</label>
                <div className="mt-1 px-2.5 py-1.5 bg-slate-50 border border-slate-100 rounded-lg text-xs text-slate-500">
                  {properties.height}px
                </div>
              </div>
            </div>
          </div>
        </Card>
      )}

      {/* Layer Manager */}
      <Card className="flex-1 flex flex-col overflow-hidden bg-white shadow-sm border-slate-200">
        <div className="p-3 bg-slate-50 border-b border-slate-200 flex items-center justify-between">
          <h3 className="text-xs font-bold text-slate-700 uppercase tracking-wider flex items-center gap-2">
            <Layers size={14} /> Layers
          </h3>
          <span className="text-[10px] bg-slate-200 text-slate-600 px-1.5 py-0.5 rounded-full font-bold">
            {layers.length}
          </span>
        </div>

        <div className="flex-1 overflow-auto p-2 space-y-1">
          {layers.length === 0 ? (
            <div className="text-[11px] text-slate-400 text-center py-8">No layers yet</div>
          ) : (
            layers.map((layer, index) => (
              <div
                key={index}
                className={`flex items-center justify-between p-2 rounded-lg text-[11px] border transition-all cursor-pointer ${
                  layer.locked
                    ? 'bg-slate-50/50 border-transparent text-slate-400'
                    : 'bg-white border-slate-100 text-slate-700 shadow-sm hover:border-indigo-200'
                }`}
                onClick={() => {
                  if (canvas && !layer.locked) {
                    canvas.setActiveObject(layer.ref);
                    canvas.requestRenderAll();
                  }
                }}
              >
                <div className="flex items-center gap-2">
                  <div className={`w-2 h-2 rounded-full ${layer.locked ? 'bg-slate-300' : 'bg-indigo-400'}`} />
                  <span className="font-semibold capitalize truncate max-w-[120px]">
                    {layer.type === 'i-text'
                      ? layer.ref.text?.substring(0, 15) || 'Text'
                      : layer.id || layer.type}
                  </span>
                </div>

                <div className="flex items-center gap-0.5">
                  <Button
                    variant="ghost"
                    size="icon"
                    className="h-6 w-6 text-slate-400 hover:text-indigo-600"
                    onClick={(e) => { e.stopPropagation(); toggleVisibility(layer); }}
                  >
                    {layer.visible ? <Eye size={12} /> : <EyeOff size={12} />}
                  </Button>
                  <Button
                    variant="ghost"
                    size="icon"
                    className="h-6 w-6 text-slate-400 hover:text-amber-600"
                    onClick={(e) => { e.stopPropagation(); toggleLock(layer); }}
                  >
                    {layer.locked ? <Lock size={12} /> : <Unlock size={12} />}
                  </Button>
                </div>
              </div>
            ))
          )}
        </div>
      </Card>

      {/* Instructions */}
      <Card className="p-3 bg-indigo-50 border-indigo-100">
        <h3 className="text-[10px] font-bold text-indigo-700 uppercase tracking-wider mb-2">Tips</h3>
        <ul className="text-[10px] text-indigo-600 space-y-1.5 list-disc pl-3">
          <li>Upload PDF to automatically make text and images interactive</li>
          <li><b>Click text</b> to highlight and edit content</li>
          <li><b>Hover & Click images</b> (blue dashed boxes) to replace them</li>
          <li><b>Drag and drop</b> items to align; use the alignment buttons for precision</li>
          <li>Toggle layers to lock or hide elements</li>
        </ul>
      </Card>
    </div>
  );
};

