import React, { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { 
  Sparkles, 
  Palette, 
  Type, 
  Layout, 
  RefreshCw,
  Check,
  Zap,
  RotateCcw
} from 'lucide-react';

interface AIAssistantProps {
  selectedElement: any | null;
  onUpdateElement: (id: string, properties: any) => void;
  onApplyTheme: (theme: { primary: string; secondary: string; accent: string; text: string }) => void;
}

const THEMES = [
  {
    name: 'Corporate Blue',
    primary: '#1e3a8a',
    secondary: '#3b82f6',
    accent: '#dbeafe',
    text: '#111827',
  },
  {
    name: 'Modern Dark',
    primary: '#111827',
    secondary: '#374151',
    accent: '#6366f1',
    text: '#f9fafb',
  },
  {
    name: 'Professional Green',
    primary: '#064e3b',
    secondary: '#10b981',
    accent: '#d1fae5',
    text: '#111827',
  },
  {
    name: 'Vibrant Orange',
    primary: '#7c2d12',
    secondary: '#f97316',
    accent: '#ffedd5',
    text: '#111827',
  },
];

export const AIAssistant: React.FC<AIAssistantProps> = ({
  selectedElement,
  onUpdateElement,
  onApplyTheme,
}) => {
  const [isStyleProcessing, setIsStyleProcessing] = useState(false);
  const [isTextProcessing, setIsTextProcessing] = useState(false);
  const [suggestion, setSuggestion] = useState<string | null>(null);

  const handleApplyTheme = (theme: typeof THEMES[0]) => {
    setIsStyleProcessing(true);
    // Simulate AI processing
    setTimeout(() => {
      onApplyTheme({
        primary: theme.primary,
        secondary: theme.secondary,
        accent: theme.accent,
        text: theme.text,
      });
      setIsStyleProcessing(false);
    }, 800);
  };

  const handleEnhanceText = () => {
    if (!selectedElement || selectedElement.type !== 'text') return;

    setIsTextProcessing(true);
    // Simulate AI text enhancement
    setTimeout(() => {
      const currentText = selectedElement.text || '';
      let enhanced = currentText;

      if (currentText.toLowerCase().includes('name')) {
        enhanced = 'Student Full Name';
      } else if (currentText.toLowerCase().includes('school')) {
        enhanced = 'Official Educational Institution';
      } else {
        enhanced = `Professional ${currentText}`;
      }

      onUpdateElement(selectedElement.id, { text: enhanced });
      setIsTextProcessing(false);
      setSuggestion(`Enhanced "${currentText}" to "${enhanced}"`);
    }, 1000);
  };

  const handleAIStyleSuggest = () => {
    setIsStyleProcessing(true);
    // Simulate "Surprise me" AI style
    setTimeout(() => {
      const randomTheme = THEMES[Math.floor(Math.random() * THEMES.length)];
      onApplyTheme(randomTheme);
      setIsStyleProcessing(false);
    }, 1200);
  };

  return (
    <Card className="h-full border-purple-100 shadow-sm">
      <CardHeader className="bg-purple-50/50 pb-4 border-b border-purple-100">
        <CardTitle className="flex items-center gap-2 text-purple-800 text-lg">
          <Sparkles className="w-5 h-5 text-purple-600" />
          AI Studio Assistant
        </CardTitle>
        <CardDescription>
          Use AI to instantly enhance your ID card design
        </CardDescription>
      </CardHeader>
      <CardContent className="p-4 space-y-6">
        {/* Style & Color Suggestions */}
        <div className="space-y-3">
          <Label className="flex items-center gap-2">
            <Palette className="w-4 h-4 text-purple-600" />
            AI Smart Styling
          </Label>
          <div className="grid grid-cols-2 gap-2">
            {THEMES.map((theme) => (
              <Button
                key={theme.name}
                variant="outline"
                size="sm"
                className="h-auto py-2 px-3 justify-start gap-2 hover:border-purple-300 hover:bg-purple-50"
                onClick={() => handleApplyTheme(theme)}
                disabled={isStyleProcessing}
              >
                <div className="flex gap-1">
                  <div className="w-3 h-3 rounded-full" style={{ backgroundColor: theme.primary }} />
                  <div className="w-3 h-3 rounded-full" style={{ backgroundColor: theme.secondary }} />
                </div>
                <span className="text-xs truncate">{theme.name}</span>
              </Button>
            ))}
          </div>
          <Button 
            className="w-full bg-purple-600 hover:bg-purple-700 text-white gap-2"
            onClick={handleAIStyleSuggest}
            disabled={isStyleProcessing}
          >
            {isStyleProcessing ? (
              <RefreshCw className="w-4 h-4 animate-spin" />
            ) : (
              <Zap className="w-4 h-4" />
            )}
            Surprise Me with AI Style
          </Button>
        </div>

        {/* Text Enhancement */}
        <div className="space-y-3 pt-4 border-t">
          <Label className="flex items-center gap-2">
            <Type className="w-4 h-4 text-purple-600" />
            Detail Booster
          </Label>
          {selectedElement?.type === 'text' ? (
            <div className="p-3 bg-muted/30 rounded-lg space-y-3">
              <p className="text-xs text-muted-foreground">
                Selected: <span className="font-medium text-foreground">"{selectedElement.text}"</span>
              </p>
              <Button 
                variant="secondary" 
                size="sm" 
                className="w-full gap-2"
                onClick={handleEnhanceText}
                disabled={isTextProcessing}
              >
                {isTextProcessing ? (
                  <RefreshCw className="w-4 h-4 animate-spin" />
                ) : (
                  <Sparkles className="w-4 h-4" />
                )}
                Professional Text Polish
              </Button>
            </div>
          ) : (
            <div className="p-3 bg-muted/20 border border-dashed rounded-lg text-center">
              <p className="text-xs text-muted-foreground">
                Select a text element to enable AI Polish
              </p>
            </div>
          )}
        </div>

        {/* AI Layout Suggestions */}
        <div className="space-y-3 pt-4 border-t">
          <Label className="flex items-center gap-2">
            <Layout className="w-4 h-4 text-purple-600" />
            AI Layout Fixer
          </Label>
          <div className="grid grid-cols-1 gap-2">
            <Button variant="outline" size="sm" className="justify-start gap-2 text-xs">
              <Check className="w-3 h-3 text-green-500" /> Standard ID Alignment
            </Button>
            <Button variant="outline" size="sm" className="justify-start gap-2 text-xs">
              <Check className="w-3 h-3 text-green-500" /> Optimized Spacing
            </Button>
          </div>
        </div>

        {suggestion && (
          <div className="mt-4 p-2 bg-green-50 border border-green-100 rounded text-[10px] text-green-700 flex items-center gap-2 animate-in fade-in slide-in-from-bottom-1">
            <Check className="w-3 h-3" />
            {suggestion}
            <Button variant="ghost" size="icon" className="h-4 w-4 ml-auto" onClick={() => setSuggestion(null)}>
              <RotateCcw className="w-2 h-2" />
            </Button>
          </div>
        )}
      </CardContent>
    </Card>
  );
};

import React, { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { 
  Database, 
  MapPin, 
  Link, 
  Unlink, 
  Table, 
  User, 
  School, 
  Settings,
  CheckCircle2,
  AlertCircle
} from 'lucide-react';
import { PREDEFINED_FIELDS, getFieldsByCategory } from '@/utils/dynamicFields';

interface DataMappingPanelProps {
  selectedElement: any | null;
  onUpdateElement: (id: string, properties: any) => void;
  mappedFields: Record<string, string>; // elementId -> fieldId
  onMappingChange: (elementId: string, fieldId: string | null) => void;
}

export const DataMappingPanel: React.FC<DataMappingPanelProps> = ({
  selectedElement,
  onUpdateElement,
  mappedFields,
  onMappingChange,
}) => {
  const categories = ['student', 'school', 'system'] as const;

  const handleMapField = (fieldId: string) => {
    if (!selectedElement) return;

    const field = PREDEFINED_FIELDS.find(f => f.id === fieldId);
    if (!field) return;

    onMappingChange(selectedElement.id, fieldId);

    // Also update the element's text if it's a text element
    if (selectedElement.type === 'text') {
      onUpdateElement(selectedElement.id, { text: field.placeholder });
    } else if (selectedElement.type === 'image') {
      onUpdateElement(selectedElement.id, { name: `${selectedElement.name} (${field.name})` });
    }
  };

  const currentMappingId = selectedElement ? mappedFields[selectedElement.id] : null;
  const currentField = currentMappingId ? PREDEFINED_FIELDS.find(f => f.id === currentMappingId) : null;

  return (
    <Card className="h-full border-blue-100 shadow-sm">
      <CardHeader className="bg-blue-50/50 pb-4 border-b border-blue-100">
        <CardTitle className="flex items-center gap-2 text-blue-800 text-lg">
          <Database className="w-5 h-5 text-blue-600" />
          Excel Data Mapping
        </CardTitle>
        <CardDescription>
          Map template elements to Excel data fields for bulk generation
        </CardDescription>
      </CardHeader>
      <CardContent className="p-4 space-y-6">
        {selectedElement ? (
          <div className="space-y-4">
            {/* Current Element Info */}
            <div className="p-3 bg-muted/30 rounded-lg border border-muted-foreground/10">
              <div className="flex items-center justify-between mb-2">
                <Badge variant="outline" className="text-[10px] uppercase">
                  {selectedElement.type} element
                </Badge>
                {currentField ? (
                  <Badge className="bg-green-100 text-green-700 hover:bg-green-100 border-green-200 gap-1">
                    <Link className="w-3 h-3" /> Mapped
                  </Badge>
                ) : (
                  <Badge variant="secondary" className="gap-1">
                    <Unlink className="w-3 h-3" /> Unmapped
                  </Badge>
                )}
              </div>
              <p className="text-sm font-medium truncate">{selectedElement.name || selectedElement.id}</p>
              {currentField && (
                <div className="mt-2 text-xs flex items-center gap-1 text-blue-600 font-semibold">
                  <Table className="w-3 h-3" />
                  Maps to: {currentField.name}
                </div>
              )}
            </div>

            {/* Field Selectors */}
            <div className="space-y-4">
              <Label className="text-sm">Available Fields</Label>
              {categories.map(category => (
                <div key={category} className="space-y-2">
                  <div className="flex items-center gap-2 text-xs text-muted-foreground font-semibold uppercase tracking-wider">
                    {category === 'student' && <User className="w-3 h-3" />}
                    {category === 'school' && <School className="w-3 h-3" />}
                    {category === 'system' && <Settings className="w-3 h-3" />}
                    {category} Data
                  </div>
                  <div className="grid grid-cols-1 gap-1">
                    {getFieldsByCategory(category).map(field => (
                      <Button
                        key={field.id}
                        variant={currentMappingId === field.id ? 'default' : 'outline'}
                        size="sm"
                        className="justify-start h-8 px-3 text-xs"
                        onClick={() => handleMapField(field.id)}
                      >
                        {field.name}
                        {currentMappingId === field.id && <CheckCircle2 className="w-3 h-3 ml-auto text-white" />}
                      </Button>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            {currentField && (
              <Button 
                variant="ghost" 
                size="sm" 
                className="w-full text-red-500 hover:text-red-600 hover:bg-red-50 gap-2"
                onClick={() => onMappingChange(selectedElement.id, null)}
              >
                <Unlink className="w-4 h-4" />
                Remove Mapping
              </Button>
            )}
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center py-12 text-center space-y-4">
            <div className="w-12 h-12 rounded-full bg-blue-100 flex items-center justify-center">
              <MapPin className="w-6 h-6 text-blue-600" />
            </div>
            <div>
              <h4 className="font-semibold text-gray-900">No Element Selected</h4>
              <p className="text-xs text-muted-foreground max-w-[200px] mx-auto mt-1">
                Select an element on the canvas to map it to an Excel data field.
              </p>
            </div>
          </div>
        )}

        {/* Global Bulk Status */}
        <div className="pt-4 border-t space-y-3">
          <Label className="text-sm">Bulk Generation Status</Label>
          <div className="space-y-2">
            <div className="flex items-center justify-between text-xs">
              <span className="text-muted-foreground">Mapped Elements:</span>
              <span className="font-medium">{Object.keys(mappedFields).length}</span>
            </div>
            {Object.keys(mappedFields).length === 0 && (
              <div className="p-3 bg-yellow-50 border border-yellow-200 rounded-lg flex gap-2">
                <AlertCircle className="w-4 h-4 text-yellow-600 flex-shrink-0" />
                <p className="text-[10px] text-yellow-700">
                  No elements mapped yet. Bulk generation will use static content from the template.
                </p>
              </div>
            )}
          </div>
        </div>
      </CardContent>
    </Card>
  );
};

import React, { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Badge } from '@/components/ui/badge';
import { Progress } from '@/components/ui/progress';
import { Checkbox } from '@/components/ui/checkbox';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { 
  Download, 
  FileText, 
  Image as ImageIcon, 
  FileImage,
  Settings,
  CheckCircle,
  AlertCircle,
  Loader2,
  Users,
  FileArchive
} from 'lucide-react';
import { exportTemplate, ExportOptions, TemplateData, bulkExportToZip } from '@/utils/templateExporter';
import { useOrder } from '@/hooks/useOrder';
import { recordService } from '@/services/dataService';
import { toast } from 'sonner';

interface ExportPanelProps {
  templateData: TemplateData | null;
  mappedFields: Record<string, string>;
  onExportStart: () => void;
  onExportComplete: () => void;
  onExportError: (error: string) => void;
}

export const ExportPanel: React.FC<ExportPanelProps> = ({
  templateData,
  mappedFields,
  onExportStart,
  onExportComplete,
  onExportError,
}) => {
  const { currentOrder } = useOrder();
  const [isExporting, setIsExporting] = useState(false);
  const [isBulkExporting, setIsBulkExporting] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);
  const [records, setRecords] = useState<any[]>([]);
  const [isLoadingRecords, setIsLoadingRecords] = useState(false);
  const [exportFormat, setExportFormat] = useState<'json' | 'pdf' | 'eps' | 'png'>('json');
  const [exportOptions, setExportOptions] = useState<ExportOptions>({
    format: 'json',
    dpi: 300,
    includeMetadata: true,
    includeVersionHistory: false,
    compress: false,
    quality: 1.0,
    includeBleed: false,
    bleedSize: 3,
    includeCropMarks: false,
    colorSpace: 'RGB',
  });

  // Update export options when format changes
  React.useEffect(() => {
    setExportOptions(prev => ({
      ...prev,
      format: exportFormat,
    }));
  }, [exportFormat]);

  // Fetch records for current order/project
  React.useEffect(() => {
    const fetchRecords = async () => {
      if (!currentOrder?.projectId) return;

      setIsLoadingRecords(true);
      try {
        const data = await recordService.getAll({ projectId: currentOrder.projectId });
        setRecords(data.records || data || []);
      } catch (error) {
        console.error('Error fetching records:', error);
      } finally {
        setIsLoadingRecords(false);
      }
    };

    fetchRecords();
  }, [currentOrder]);

  const handleBulkExport = async () => {
    if (!templateData) return;
    if (records.length === 0) {
      toast.error('No records found for bulk generation');
      return;
    }

    setIsBulkExporting(true);
    setExportProgress(0);
    onExportStart();

    try {
      await bulkExportToZip(
        templateData,
        mappedFields,
        records,
        (progress) => setExportProgress(progress)
      );

      toast.success(`Successfully generated ${records.length} ID cards`);
      onExportComplete();
    } catch (error) {
      console.error('Bulk export error:', error);
      onExportError('Bulk generation failed');
    } finally {
      setIsBulkExporting(false);
      setExportProgress(0);
    }
  };

  // Handle export
  const handleExport = async () => {
    if (!templateData) {
      onExportError('No template data to export');
      return;
    }

    setIsExporting(true);
    setExportProgress(0);
    onExportStart();

    try {
      // Simulate progress
      const progressInterval = setInterval(() => {
        setExportProgress(prev => {
          if (prev >= 90) {
            clearInterval(progressInterval);
            return prev;
          }
          return prev + 10;
        });
      }, 100);

      await exportTemplate(templateData, exportOptions);

      clearInterval(progressInterval);
      setExportProgress(100);

      setTimeout(() => {
        setIsExporting(false);
        setExportProgress(0);
        onExportComplete();
      }, 500);
    } catch (error) {
      setIsExporting(false);
      setExportProgress(0);
      onExportError(error instanceof Error ? error.message : 'Export failed');
    }
  };

  // Get format icon
  const getFormatIcon = (format: string) => {
    switch (format) {
      case 'json':
        return <FileText className="w-5 h-5 text-blue-500" />;
      case 'pdf':
        return <FileText className="w-5 h-5 text-red-500" />;
      case 'eps':
        return <FileImage className="w-5 h-5 text-purple-500" />;
      case 'png':
        return <ImageIcon className="w-5 h-5 text-green-500" />;
      default:
        return <FileText className="w-5 h-5 text-gray-500" />;
    }
  };

  // Get format description
  const getFormatDescription = (format: string) => {
    switch (format) {
      case 'json':
        return 'Editable template data for further editing';
      case 'pdf':
        return 'High-quality print-ready PDF document';
      case 'eps':
        return 'Vector format for professional printing';
      case 'png':
        return 'Raster image with transparent background';
      default:
        return '';
    }
  };

  // Get file size estimate
  const getFileSizeEstimate = (format: string) => {
    if (!templateData) return 'Unknown';

    const elementCount = templateData.sides 
      ? templateData.sides.front.length + templateData.sides.back.length
      : templateData.elements.length;
    const canvasSize = templateData.canvas.width * templateData.canvas.height;

    switch (format) {
      case 'json':
        return `${Math.round(elementCount * 0.5 + 1)} KB`;
      case 'pdf':
        return `${Math.round(canvasSize * (templateData.sides ? 0.002 : 0.001) + 50)} KB`;
      case 'eps':
        return `${Math.round(canvasSize * 0.002 + 100)} KB`;
      case 'png':
        return `${Math.round(canvasSize * 0.01 + 200)} KB`;
      default:
        return 'Unknown';
    }
  };

  return (
    <Card className="h-full">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Download className="w-5 h-5" />
          Export Template
        </CardTitle>
      </CardHeader>
      <CardContent className="p-0">
        <Tabs defaultValue="format" className="w-full">
          <TabsList className="grid w-full grid-cols-3">
            <TabsTrigger value="format">Single</TabsTrigger>
            <TabsTrigger value="bulk">Bulk (Batch)</TabsTrigger>
            <TabsTrigger value="options">Options</TabsTrigger>
          </TabsList>

          <TabsContent value="format" className="p-4">
            {/* Format selection */}
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-3">
                {(['json', 'pdf', 'eps', 'png'] as const).map((format) => (
                  <div
                    key={format}
                    className={`
                      p-4 border rounded-lg cursor-pointer transition-colors
                      ${exportFormat === format ? 'border-primary bg-primary/5' : 'border-muted-foreground/25 hover:border-primary/50'}
                    `}
                    onClick={() => setExportFormat(format)}
                  >
                    <div className="flex items-center gap-3">
                      {getFormatIcon(format)}
                      <div className="flex-1">
                        <h4 className="font-medium capitalize">{format.toUpperCase()}</h4>
                        <p className="text-sm text-muted-foreground">
                          {getFormatDescription(format)}
                        </p>
                        <p className="text-xs text-muted-foreground mt-1">
                          Est. size: {getFileSizeEstimate(format)}
                        </p>
                      </div>
                    </div>
                  </div>
                ))}
              </div>

              {/* Template info */}
              {templateData && (
                <div className="p-4 bg-muted/50 rounded-lg">
                  <h4 className="font-medium mb-2">Template Information</h4>
                  <div className="grid grid-cols-2 gap-4 text-sm">
                    <div>
                      <span className="text-muted-foreground">Name:</span>
                      <span className="ml-2 font-medium">{templateData.metadata.name}</span>
                    </div>
                    <div>
                      <span className="text-muted-foreground">Elements:</span>
                      <span className="ml-2 font-medium">
                        {templateData.sides 
                          ? `${templateData.sides.front.length + templateData.sides.back.length} (2 sides)` 
                          : templateData.elements.length}
                      </span>
                    </div>
                    <div>
                      <span className="text-muted-foreground">Canvas:</span>
                      <span className="ml-2 font-medium">
                        {templateData.canvas.width} × {templateData.canvas.height}px
                      </span>
                    </div>
                    <div>
                      <span className="text-muted-foreground">Version:</span>
                      <span className="ml-2 font-medium">{templateData.metadata.version}</span>
                    </div>
                  </div>
                </div>
              )}

              {/* Export button */}
              <Button
                onClick={handleExport}
                disabled={!templateData || isExporting}
                className="w-full"
              >
                {isExporting ? (
                  <>
                    <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                    Exporting... {exportProgress}%
                  </>
                ) : (
                  <>
                    <Download className="w-4 h-4 mr-2" />
                    Export {exportFormat.toUpperCase()}
                  </>
                )}
              </Button>

              {isExporting && (
                <div className="w-full">
                  <Progress value={exportProgress} className="mb-2" />
                  <p className="text-xs text-muted-foreground text-center">
                    Preparing export...
                  </p>
                </div>
              )}
            </div>
          </TabsContent>

          <TabsContent value="bulk" className="p-4">
            <div className="space-y-6">
              <div className="p-4 bg-blue-50 border border-blue-100 rounded-lg flex gap-3">
                <Users className="w-5 h-5 text-blue-600 mt-1" />
                <div>
                  <h4 className="font-semibold text-blue-900">Bulk ID Card Generation</h4>
                  <p className="text-sm text-blue-700">
                    Generate unique ID cards for all {records.length} records in this project.
                  </p>
                </div>
              </div>

              <div className="space-y-3">
                <Label className="text-sm font-medium">Mapping Overview</Label>
                <div className="grid grid-cols-2 gap-2 text-xs">
                  <div className="p-2 bg-muted rounded border">
                    <span className="text-muted-foreground block">Mapped Elements</span>
                    <span className="font-bold text-lg">{Object.keys(mappedFields).length}</span>
                  </div>
                  <div className="p-2 bg-muted rounded border">
                    <span className="text-muted-foreground block">Total Records</span>
                    <span className="font-bold text-lg">{records.length}</span>
                  </div>
                </div>

                {Object.keys(mappedFields).length === 0 && (
                  <div className="p-3 bg-yellow-50 border border-yellow-200 rounded-lg flex gap-2">
                    <AlertCircle className="w-4 h-4 text-yellow-600 flex-shrink-0" />
                    <p className="text-xs text-yellow-700">
                      Warning: No elements are mapped to data fields. All cards will be identical.
                    </p>
                  </div>
                )}
              </div>

              <Button
                onClick={handleBulkExport}
                disabled={isBulkExporting || !templateData || isLoadingRecords}
                className="w-full h-12 text-lg font-bold bg-blue-600 hover:bg-blue-700 shadow-md transition-all active:scale-95"
              >
                {isBulkExporting ? (
                  <>
                    <Loader2 className="w-5 h-5 mr-3 animate-spin" />
                    Generating... {exportProgress}%
                  </>
                ) : (
                  <>
                    <Download className="w-5 h-5 mr-3" />
                    Download Bulk ZIP
                  </>
                )}
              </Button>

              {isBulkExporting && (
                <div className="space-y-2">
                  <Progress value={exportProgress} className="h-2" />
                  <p className="text-xs text-center text-muted-foreground animate-pulse">
                    Processing records and generating high-resolution templates...
                  </p>
                </div>
              )}

              <div className="rounded-lg border border-dashed p-4 text-center">
                <p className="text-xs text-muted-foreground">
                  Cards will be exported as 300 DPI PNG images bundled into a single ZIP file named after your project.
                </p>
              </div>
            </div>
          </TabsContent>

          <TabsContent value="options" className="p-4">
            <div className="space-y-6">
              {/* General options */}
              <div className="space-y-4">
                <h4 className="font-medium">General Options</h4>

                <div className="space-y-2">
                  <div className="flex items-center space-x-2">
                    <Checkbox
                      id="includeMetadata"
                      checked={exportOptions.includeMetadata}
                      onCheckedChange={(checked) => 
                        setExportOptions(prev => ({ ...prev, includeMetadata: !!checked }))
                      }
                    />
                    <Label htmlFor="includeMetadata" className="text-sm">
                      Include metadata (name, version, timestamps)
                    </Label>
                  </div>

                  <div className="flex items-center space-x-2">
                    <Checkbox
                      id="includeVersionHistory"
                      checked={exportOptions.includeVersionHistory}
                      onCheckedChange={(checked) => 
                        setExportOptions(prev => ({ ...prev, includeVersionHistory: !!checked }))
                      }
                    />
                    <Label htmlFor="includeVersionHistory" className="text-sm">
                      Include version history
                    </Label>
                  </div>

                  <div className="flex items-center space-x-2">
                    <Checkbox
                      id="compress"
                      checked={exportOptions.compress}
                      onCheckedChange={(checked) => 
                        setExportOptions(prev => ({ ...prev, compress: !!checked }))
                      }
                    />
                    <Label htmlFor="compress" className="text-sm">
                      Compress output (smaller file size)
                    </Label>
                  </div>
                </div>
              </div>

              {/* Image/Print options */}
              {(exportFormat === 'pdf' || exportFormat === 'eps' || exportFormat === 'png') && (
                <div className="space-y-4">
                  <h4 className="font-medium">Image/Print Options</h4>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label htmlFor="dpi">DPI (Resolution)</Label>
                      <Select
                        value={exportOptions.dpi?.toString()}
                        onValueChange={(value) => 
                          setExportOptions(prev => ({ ...prev, dpi: parseInt(value) }))
                        }
                      >
                        <SelectTrigger>
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="72">72 DPI (Screen)</SelectItem>
                          <SelectItem value="150">150 DPI (Draft Print)</SelectItem>
                          <SelectItem value="300">300 DPI (Print Quality)</SelectItem>
                          <SelectItem value="600">600 DPI (High Quality)</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="quality">Quality</Label>
                      <Select
                        value={exportOptions.quality?.toString()}
                        onValueChange={(value) => 
                          setExportOptions(prev => ({ ...prev, quality: parseFloat(value) }))
                        }
                      >
                        <SelectTrigger>
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="0.5">50% (Low)</SelectItem>
                          <SelectItem value="0.75">75% (Medium)</SelectItem>
                          <SelectItem value="1.0">100% (High)</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="colorSpace">Color Space</Label>
                    <Select
                      value={exportOptions.colorSpace}
                      onValueChange={(value: 'RGB' | 'CMYK') => 
                        setExportOptions(prev => ({ ...prev, colorSpace: value }))
                      }
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="RGB">RGB (Screen/Web)</SelectItem>
                        <SelectItem value="CMYK">CMYK (Print)</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>
              )}

              {/* Print-specific options */}
              {(exportFormat === 'pdf' || exportFormat === 'eps') && (
                <div className="space-y-4">
                  <h4 className="font-medium">Print Options</h4>

                  <div className="space-y-2">
                    <div className="flex items-center space-x-2">
                      <Checkbox
                        id="includeBleed"
                        checked={exportOptions.includeBleed}
                        onCheckedChange={(checked) => 
                          setExportOptions(prev => ({ ...prev, includeBleed: !!checked }))
                        }
                      />
                      <Label htmlFor="includeBleed" className="text-sm">
                        Include bleed area
                      </Label>
                    </div>

                    {exportOptions.includeBleed && (
                      <div className="ml-6 space-y-2">
                        <Label htmlFor="bleedSize">Bleed Size (mm)</Label>
                        <Input
                          id="bleedSize"
                          type="number"
                          value={exportOptions.bleedSize}
                          onChange={(e) => 
                            setExportOptions(prev => ({ ...prev, bleedSize: parseInt(e.target.value) || 3 }))
                          }
                          min="1"
                          max="10"
                        />
                      </div>
                    )}
                  </div>

                  <div className="flex items-center space-x-2">
                    <Checkbox
                      id="includeCropMarks"
                      checked={exportOptions.includeCropMarks}
                      onCheckedChange={(checked) => 
                        setExportOptions(prev => ({ ...prev, includeCropMarks: !!checked }))
                      }
                    />
                    <Label htmlFor="includeCropMarks" className="text-sm">
                      Include crop marks
                    </Label>
                  </div>
                </div>
              )}

              {/* Export button */}
              <Button
                onClick={handleExport}
                disabled={!templateData || isExporting}
                className="w-full"
              >
                {isExporting ? (
                  <>
                    <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                    Exporting... {exportProgress}%
                  </>
                ) : (
                  <>
                    <Download className="w-4 h-4 mr-2" />
                    Export with Options
                  </>
                )}
              </Button>
            </div>
          </TabsContent>
        </Tabs>
      </CardContent>
    </Card>
  );
};

import React, { useRef, useEffect, useState, useCallback } from 'react';
import * as fabric from 'fabric';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { 
  Move, 
  Type, 
  Square, 
  Circle as CircleIcon, 
  Image as ImageIcon, 
  RotateCw, 
  Trash2,
  Copy,
  Lock,
  Unlock,
  Eye,
  EyeOff,
  Palette,
  Bold,
  Italic,
  AlignLeft,
  AlignCenter,
  AlignRight
} from 'lucide-react';

export interface FabricElement {
  id: string;
  type: 'text' | 'rect' | 'circle' | 'image' | 'group' | 'path';
  left: number;
  top: number;
  width: number;
  height: number;
  angle: number;
  opacity: number;
  visible: boolean;
  selectable: boolean;
  evented: boolean;
  // Text properties
  text?: string;
  fontSize?: number;
  fontFamily?: string;
  fontWeight?: string;
  fontStyle?: string;
  textAlign?: 'left' | 'center' | 'right';
  fill?: string;
  stroke?: string;
  strokeWidth?: number;
  // Shape properties
  rx?: number;
  ry?: number;
  // Image properties
  src?: string;
  cropX?: number;
  cropY?: number;
  cropWidth?: number;
  cropHeight?: number;
  // Path properties
  path?: string;
  // Group properties
  objects?: FabricElement[];
}

interface FabricCanvasProps {
  width: number;
  height: number;
  elements: FabricElement[];
  selectedElementId?: string;
  onElementSelect: (elementId: string | null) => void;
  onElementUpdate: (elementId: string, updates: Partial<FabricElement>) => void;
  onElementDelete: (elementId: string) => void;
  onElementAdd: (element: Omit<FabricElement, 'id'>) => void;
  onElementDuplicate: (elementId: string) => void;
  onElementLock: (elementId: string, locked: boolean) => void;
  onElementVisibility: (elementId: string, visible: boolean) => void;
  onElementReorder: (elementId: string, newZIndex: number) => void;
  background?: {
    color?: string;
    image?: string;
  };
  gridSize?: number;
  showGrid?: boolean;
  snapToGrid?: boolean;
}

export const FabricCanvas: React.FC<FabricCanvasProps> = ({
  width,
  height,
  elements,
  selectedElementId,
  onElementSelect,
  onElementUpdate,
  onElementDelete,
  onElementAdd,
  onElementDuplicate,
  onElementLock,
  onElementVisibility,
  onElementReorder,
  background,
  gridSize = 10,
  showGrid = false,
  snapToGrid = false,
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fabricCanvasRef = useRef<fabric.Canvas | null>(null);
  const [selectedElement, setSelectedElement] = useState<FabricElement | null>(null);
  const [isInitialized, setIsInitialized] = useState(false);

  // Initialize Fabric canvas
  useEffect(() => {
    if (canvasRef.current && !isInitialized) {
      const canvas = new fabric.Canvas(canvasRef.current, {
        width,
        height,
        backgroundColor: background?.color || '#ffffff',
        selection: true,
        preserveObjectStacking: true,
      });

      fabricCanvasRef.current = canvas;
      setIsInitialized(true);

      // Set up event listeners
      canvas.on('selection:created', handleSelection);
      canvas.on('selection:updated', handleSelection);
      canvas.on('selection:cleared', () => onElementSelect(null));
      canvas.on('object:modified', handleObjectModified);
      canvas.on('object:moving', handleObjectMoving);
      canvas.on('object:scaling', handleObjectScaling);
      canvas.on('object:rotating', handleObjectRotating);

      return () => {
        try {
          canvas.dispose();
        } catch (err) {
          console.warn('Fabric dispose error', err);
        }
        fabricCanvasRef.current = null;
      };
    }
  }, [isInitialized, width, height, background?.color]);

  // Update canvas when elements change
  useEffect(() => {
    if (!canvasRef.current || !fabricCanvasRef.current || !isInitialized) return;

    try {
      const canvas = fabricCanvasRef.current;
      canvas.clear();

      // Add background image if exists
      if (background?.image) {
        fabric.Image.fromURL(background.image).then((img: any) => {
          img.set({
            left: 0,
            top: 0,
            scaleX: width / img.width,
            scaleY: height / img.height,
            selectable: false,
            evented: false,
          });
          canvas.add(img);
          if (typeof (canvas as any).sendToBack === 'function') {
            (canvas as any).sendToBack(img);
          } else if (typeof (canvas as any).sendObjectToBack === 'function') {
            (canvas as any).sendObjectToBack(img);
          }
        }).catch(err => console.error("Error loading fabric background", err));
      }

      // Add elements
      elements.forEach(element => {
        addElementToCanvas(element);
      });

      canvas.renderAll();
    } catch (err) {
      console.warn('Fabric render error', err);
    }
  }, [elements, background, isInitialized, width, height]);

  // Update selection when selectedElementId changes
  useEffect(() => {
    if (fabricCanvasRef.current && selectedElementId) {
      const canvas = fabricCanvasRef.current;
      const element = elements.find(el => el.id === selectedElementId);
      if (element) {
        setSelectedElement(element);
        const fabricObject = canvas.getObjects().find(obj => (obj as any).id === selectedElementId);
        if (fabricObject) {
          canvas.setActiveObject(fabricObject);
          canvas.renderAll();
        }
      }
    } else {
      setSelectedElement(null);
    }
  }, [selectedElementId, elements]);

  // Handle selection events
  const handleSelection = useCallback((e: any) => {
    const activeObject = e.selected?.[0];
    if (activeObject && activeObject.id) {
      onElementSelect(activeObject.id);
    } else {
      onElementSelect(null);
    }
  }, [onElementSelect]);

  // Handle object modification
  const handleObjectModified = useCallback((e: any) => {
    const obj = e.target;
    if (obj && obj.id) {
      onElementUpdate(obj.id, {
        left: obj.left || 0,
        top: obj.top || 0,
        width: obj.width || 0,
        height: obj.height || 0,
        angle: obj.angle || 0,
        opacity: obj.opacity || 1,
      });
    }
  }, [onElementUpdate]);

  // Handle object moving
  const handleObjectMoving = useCallback((e: any) => {
    if (snapToGrid && e.target) {
      const obj = e.target;
      obj.set({
        left: Math.round(obj.left! / gridSize) * gridSize,
        top: Math.round(obj.top! / gridSize) * gridSize,
      });
    }
  }, [snapToGrid, gridSize]);

  // Handle object scaling
  const handleObjectScaling = useCallback((e: any) => {
    const obj = e.target;
    if (obj && obj.id) {
      // Update width and height based on scale
      const scaleX = obj.scaleX || 1;
      const scaleY = obj.scaleY || 1;

      onElementUpdate(obj.id, {
        width: (obj.width || 0) * scaleX,
        height: (obj.height || 0) * scaleY,
      });
    }
  }, [onElementUpdate]);

  // Handle object rotating
  const handleObjectRotating = useCallback((e: any) => {
    const obj = e.target;
    if (obj && obj.id) {
      onElementUpdate(obj.id, {
        angle: obj.angle || 0,
      });
    }
  }, [onElementUpdate]);

  // Add element to canvas
  const addElementToCanvas = (element: FabricElement) => {
    if (!fabricCanvasRef.current) return;

    const canvas = fabricCanvasRef.current;
    let fabricObject: fabric.Object | null = null;

    switch (element.type) {
      case 'text':
        fabricObject = new fabric.Text(element.text || '', {
          id: element.id,
          left: element.left,
          top: element.top,
          fontSize: element.fontSize || 16,
          fontFamily: element.fontFamily || 'Arial',
          fontWeight: element.fontWeight || 'normal',
          fontStyle: element.fontStyle || 'normal',
          textAlign: element.textAlign || 'left',
          fill: element.fill || '#000000',
          stroke: element.stroke,
          strokeWidth: element.strokeWidth || 0,
          opacity: element.opacity || 1,
          selectable: element.selectable !== false,
          evented: element.evented !== false,
        });
        break;

      case 'rect':
        fabricObject = new fabric.Rect({
          id: element.id,
          left: element.left,
          top: element.top,
          width: element.width,
          height: element.height,
          fill: element.fill || '#000000',
          stroke: element.stroke,
          strokeWidth: element.strokeWidth || 0,
          rx: element.rx || 0,
          ry: element.ry || 0,
          opacity: element.opacity || 1,
          selectable: element.selectable !== false,
          evented: element.evented !== false,
        });
        break;

      case 'circle':
        fabricObject = new fabric.Circle({
          id: element.id,
          left: element.left,
          top: element.top,
          radius: Math.min(element.width, element.height) / 2,
          fill: element.fill || '#000000',
          stroke: element.stroke,
          strokeWidth: element.strokeWidth || 0,
          opacity: element.opacity || 1,
          selectable: element.selectable !== false,
          evented: element.evented !== false,
        });
        break;

      case 'image':
        if (element.src) {
          fabric.Image.fromURL(element.src).then((img: any) => {
            img.set({
              id: element.id,
              left: element.left,
              top: element.top,
              scaleX: element.width / img.width,
              scaleY: element.height / img.height,
              opacity: element.opacity || 1,
              selectable: element.selectable !== false,
              evented: element.evented !== false,
            });
            canvas.add(img);
            canvas.renderAll();
          }).catch(err => console.error("Error loading imported fabric image", err));
          return;
        }
        break;

      case 'path':
        if (element.path) {
          fabricObject = new fabric.Path(element.path, {
            id: element.id,
            left: element.left,
            top: element.top,
            fill: element.fill || '#000000',
            stroke: element.stroke,
            strokeWidth: element.strokeWidth || 0,
            opacity: element.opacity || 1,
            selectable: element.selectable !== false,
            evented: element.evented !== false,
          });
        }
        break;
    }

    if (fabricObject) {
      canvas.add(fabricObject);
    }
  };

  // Handle keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (selectedElementId && fabricCanvasRef.current) {
        const canvas = fabricCanvasRef.current;
        const activeObject = canvas.getActiveObject();

        switch (e.key) {
          case 'Delete':
          case 'Backspace':
            if (activeObject) {
              canvas.remove(activeObject);
              onElementDelete(selectedElementId);
            }
            break;
          case 'd':
            if (e.ctrlKey || e.metaKey) {
              e.preventDefault();
              onElementDuplicate(selectedElementId);
            }
            break;
          case 'l':
            if (e.ctrlKey || e.metaKey) {
              e.preventDefault();
              const element = elements.find(el => el.id === selectedElementId);
              if (element) {
                onElementLock(selectedElementId, !element.selectable);
              }
            }
            break;
          case 'h':
            if (e.ctrlKey || e.metaKey) {
              e.preventDefault();
              const element = elements.find(el => el.id === selectedElementId);
              if (element) {
                onElementVisibility(selectedElementId, !element.visible);
              }
            }
            break;
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedElementId, elements, onElementDelete, onElementDuplicate, onElementLock, onElementVisibility]);

  return (
    <div className="relative">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Move className="w-5 h-5" />
            Advanced Canvas Editor
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="border rounded-lg overflow-hidden">
            <canvas ref={canvasRef} />
          </div>
        </CardContent>
      </Card>

      {/* Toolbar */}
      <Card className="mt-4">
        <CardContent className="p-4">
          <div className="flex flex-wrap gap-2">
            <Button
              size="sm"
              variant="outline"
              onClick={() => onElementAdd({
                type: 'text',
                left: 50,
                top: 50,
                width: 200,
                height: 30,
                angle: 0,
                opacity: 1,
                visible: true,
                selectable: true,
                evented: true,
                text: 'New Text',
                fontSize: 16,
                fontFamily: 'Arial',
                fill: '#000000',
              })}
            >
              <Type className="w-4 h-4 mr-1" />
              Add Text
            </Button>

            <Button
              size="sm"
              variant="outline"
              onClick={() => onElementAdd({
                type: 'rect',
                left: 50,
                top: 50,
                width: 100,
                height: 100,
                angle: 0,
                opacity: 1,
                visible: true,
                selectable: true,
                evented: true,
                fill: '#000000',
              })}
            >
              <Square className="w-4 h-4 mr-1" />
              Add Rectangle
            </Button>

            <Button
              size="sm"
              variant="outline"
              onClick={() => onElementAdd({
                type: 'circle',
                left: 50,
                top: 50,
                width: 100,
                height: 100,
                angle: 0,
                opacity: 1,
                visible: true,
                selectable: true,
                evented: true,
                fill: '#000000',
              })}
            >
              <CircleIcon className="w-4 h-4 mr-1" />
              Add Circle
            </Button>

            {selectedElementId && (
              <>
                <Button
                  size="sm"
                  variant="outline"
                  onClick={() => onElementDuplicate(selectedElementId)}
                >
                  <Copy className="w-4 h-4 mr-1" />
                  Duplicate
                </Button>

                <Button
                  size="sm"
                  variant="outline"
                  onClick={() => {
                    const element = elements.find(el => el.id === selectedElementId);
                    if (element) {
                      onElementLock(selectedElementId, !element.selectable);
                    }
                  }}
                >
                  {selectedElement?.selectable ? <Unlock className="w-4 h-4 mr-1" /> : <Lock className="w-4 h-4 mr-1" />}
                  {selectedElement?.selectable ? 'Unlock' : 'Lock'}
                </Button>

                <Button
                  size="sm"
                  variant="outline"
                  onClick={() => {
                    const element = elements.find(el => el.id === selectedElementId);
                    if (element) {
                      onElementVisibility(selectedElementId, !element.visible);
                    }
                  }}
                >
                  {selectedElement?.visible ? <EyeOff className="w-4 h-4 mr-1" /> : <Eye className="w-4 h-4 mr-1" />}
                  {selectedElement?.visible ? 'Hide' : 'Show'}
                </Button>

                <Button
                  size="sm"
                  variant="destructive"
                  onClick={() => onElementDelete(selectedElementId)}
                >
                  <Trash2 className="w-4 h-4 mr-1" />
                  Delete
                </Button>
              </>
            )}
          </div>
        </CardContent>
      </Card>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Badge } from '@/components/ui/badge';
import { Progress } from '@/components/ui/progress';
import { 
  Upload, 
  FileText, 
  Image as ImageIcon, 
  Layers, 
  Download,
  CheckCircle,
  AlertCircle,
  X,
  Eye,
  RotateCcw
} from 'lucide-react';
import { importFile, ImportResult, convertToKonvaFormat, convertToFabricFormat } from '@/utils/templateImporters';

interface ImportPanelProps {
  onImportComplete: (elements: any[], canvas: { width: number; height: number }, background?: { color?: string; image?: string }) => void;
  onImportError: (error: string) => void;
}

export const ImportPanel: React.FC<ImportPanelProps> = ({
  onImportComplete,
  onImportError,
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [importProgress, setImportProgress] = useState(0);
  const [importResult, setImportResult] = useState<ImportResult | null>(null);
  const [selectedFormat, setSelectedFormat] = useState<'konva' | 'fabric'>('konva');
  const [dragCounter, setDragCounter] = useState(0);

  // Handle drag events
  const handleDragEnter = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragCounter(prev => prev + 1);
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragCounter(prev => prev - 1);
    if (dragCounter === 1) {
      setIsDragging(false);
    }
  }, [dragCounter]);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
    setDragCounter(0);

    const files = Array.from(e.dataTransfer.files);
    if (files.length > 0) {
      handleFileImport(files[0]);
    }
  }, []);

  // Handle file input change
  const handleFileInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files && files.length > 0) {
      handleFileImport(files[0]);
    }
  };

  // Handle file import
  const handleFileImport = async (file: File) => {
    setIsImporting(true);
    setImportProgress(0);
    setImportResult(null);

    try {
      // Simulate progress
      const progressInterval = setInterval(() => {
        setImportProgress(prev => {
          if (prev >= 90) {
            clearInterval(progressInterval);
            return prev;
          }
          return prev + 10;
        });
      }, 100);

      const result = await importFile(file);

      clearInterval(progressInterval);
      setImportProgress(100);

      if (result.success) {
        setImportResult(result);
      } else {
        onImportError(result.errors?.[0] || 'Import failed');
      }
    } catch (error) {
      onImportError(error instanceof Error ? error.message : 'Import failed');
    } finally {
      setIsImporting(false);
    }
  };

  // Handle import confirmation
  const handleConfirmImport = () => {
    if (importResult) {
      const elements = selectedFormat === 'konva' 
        ? convertToKonvaFormat(importResult.elements)
        : convertToFabricFormat(importResult.elements);

      onImportComplete(
        elements,
        importResult.canvas,
        importResult.background
      );

      // Reset state
      setImportResult(null);
      setImportProgress(0);
    }
  };

  // Handle import cancellation
  const handleCancelImport = () => {
    setImportResult(null);
    setImportProgress(0);
  };

  // Get file type icon
  const getFileTypeIcon = (fileName: string) => {
    const extension = fileName.split('.').pop()?.toLowerCase();
    switch (extension) {
      case 'docx':
        return <FileText className="w-8 h-8 text-blue-500" />;
      case 'psd':
        return <Layers className="w-8 h-8 text-purple-500" />;
      case 'png':
      case 'jpg':
      case 'jpeg':
      case 'gif':
      case 'bmp':
      case 'webp':
        return <ImageIcon className="w-8 h-8 text-green-500" />;
      case 'pdf':
        return <FileText className="w-8 h-8 text-red-500" />;
      default:
        return <FileText className="w-8 h-8 text-gray-500" />;
    }
  };

  // Get file type name
  const getFileTypeName = (fileName: string) => {
    const extension = fileName.split('.').pop()?.toLowerCase();
    switch (extension) {
      case 'docx':
        return 'Word Document';
      case 'psd':
        return 'Photoshop Document';
      case 'png':
      case 'jpg':
      case 'jpeg':
      case 'gif':
      case 'bmp':
      case 'webp':
        return 'Image File';
      case 'pdf':
        return 'PDF Document';
      default:
        return 'Unknown File';
    }
  };

  return (
    <Card className="h-full">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Upload className="w-5 h-5" />
          Import Template
        </CardTitle>
      </CardHeader>
      <CardContent className="p-0">
        <Tabs defaultValue="upload" className="w-full">
          <TabsList className="grid w-full grid-cols-2">
            <TabsTrigger value="upload">Upload File</TabsTrigger>
            <TabsTrigger value="preview">Preview</TabsTrigger>
          </TabsList>

          <TabsContent value="upload" className="p-4">
            {/* Drag and drop area */}
            <div
              className={`
                border-2 border-dashed rounded-lg p-8 text-center transition-colors
                ${isDragging ? 'border-primary bg-primary/5' : 'border-muted-foreground/25'}
                ${isImporting ? 'pointer-events-none opacity-50' : 'cursor-pointer hover:border-primary/50'}
              `}
              onDragEnter={handleDragEnter}
              onDragLeave={handleDragLeave}
              onDragOver={handleDragOver}
              onDrop={handleDrop}
              onClick={() => document.getElementById('file-input')?.click()}
            >
              <Upload className="w-12 h-12 mx-auto mb-4 text-muted-foreground" />
              <h3 className="text-lg font-semibold mb-2">
                {isImporting ? 'Importing...' : 'Drop files here or click to browse'}
              </h3>
              <p className="text-sm text-muted-foreground mb-4">
                Support for Word (.docx), Photoshop (.psd), PDF (.pdf) and Image files (.png, .jpg, .gif, .bmp, .webp)
              </p>

              {isImporting && (
                <div className="w-full max-w-xs mx-auto">
                  <Progress value={importProgress} className="mb-2" />
                  <p className="text-xs text-muted-foreground">{importProgress}% complete</p>
                </div>
              )}

              <input
                id="file-input"
                type="file"
                accept=".docx,.psd,.pdf,.png,.jpg,.jpeg,.gif,.bmp,.webp"
                onChange={handleFileInputChange}
                className="hidden"
              />
            </div>

            {/* Supported formats */}
            <div className="mt-6">
              <h4 className="text-sm font-medium mb-3">Supported Formats</h4>
              <div className="grid grid-cols-3 gap-2">
                <div className="flex items-center gap-2 p-2 border rounded">
                  <FileText className="w-4 h-4 text-blue-500" />
                  <span className="text-xs">Word (.docx)</span>
                </div>
                <div className="flex items-center gap-2 p-2 border rounded">
                  <Layers className="w-4 h-4 text-purple-500" />
                  <span className="text-xs">Photoshop (.psd)</span>
                </div>
                <div className="flex items-center gap-2 p-2 border rounded">
                  <FileText className="w-4 h-4 text-red-500" />
                  <span className="text-xs">PDF (.pdf)</span>
                </div>
                <div className="flex items-center gap-2 p-2 border rounded">
                  <ImageIcon className="w-4 h-4 text-green-500" />
                  <span className="text-xs">Images (.png, .jpg)</span>
                </div>
              </div>
            </div>
          </TabsContent>

          <TabsContent value="preview" className="p-4">
            {importResult ? (
              <div className="space-y-4">
                {/* Import result header */}
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    {importResult.success ? (
                      <CheckCircle className="w-5 h-5 text-green-500" />
                    ) : (
                      <AlertCircle className="w-5 h-5 text-red-500" />
                    )}
                    <h3 className="font-semibold">
                      {importResult.success ? 'Import Successful' : 'Import Failed'}
                    </h3>
                  </div>
                  <Button
                    size="sm"
                    variant="ghost"
                    onClick={handleCancelImport}
                  >
                    <X className="w-4 h-4" />
                  </Button>
                </div>

                {importResult.success && (
                  <>
                    {/* File info */}
                    <div className="flex items-center gap-3 p-3 border rounded-lg">
                      {getFileTypeIcon('imported-file')}
                      <div className="flex-1">
                        <h4 className="font-medium">Imported File</h4>
                        <p className="text-sm text-muted-foreground">
                          {getFileTypeName('imported-file')} • {importResult.elements.length} elements
                        </p>
                      </div>
                    </div>

                    {/* Canvas info */}
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <Label>Canvas Size</Label>
                        <div className="text-sm text-muted-foreground">
                          {importResult.canvas.width} × {importResult.canvas.height}px
                        </div>
                      </div>
                      <div className="space-y-2">
                        <Label>Elements</Label>
                        <div className="text-sm text-muted-foreground">
                          {importResult.elements.length} elements imported
                        </div>
                      </div>
                    </div>

                    {/* Elements list */}
                    <div className="space-y-2">
                      <Label>Imported Elements</Label>
                      <div className="max-h-32 overflow-y-auto space-y-1">
                        {importResult.elements.map((element, index) => (
                          <div key={index} className="flex items-center gap-2 p-2 border rounded text-sm">
                            <div className="w-2 h-2 rounded-full bg-primary" />
                            <span className="flex-1">{element.type}</span>
                            <Badge variant="outline" className="text-xs">
                              {element.width}×{element.height}
                            </Badge>
                          </div>
                        ))}
                      </div>
                    </div>

                    {/* Format selection */}
                    <div className="space-y-2">
                      <Label>Target Format</Label>
                      <div className="flex gap-2">
                        <Button
                          size="sm"
                          variant={selectedFormat === 'konva' ? 'default' : 'outline'}
                          onClick={() => setSelectedFormat('konva')}
                        >
                          Konva.js
                        </Button>
                        <Button
                          size="sm"
                          variant={selectedFormat === 'fabric' ? 'default' : 'outline'}
                          onClick={() => setSelectedFormat('fabric')}
                        >
                          Fabric.js
                        </Button>
                      </div>
                    </div>

                    {/* Warnings */}
                    {importResult.warnings && importResult.warnings.length > 0 && (
                      <div className="space-y-2">
                        <Label className="text-yellow-600">Warnings</Label>
                        <div className="space-y-1">
                          {importResult.warnings.map((warning, index) => (
                            <div key={index} className="flex items-center gap-2 p-2 bg-yellow-50 border border-yellow-200 rounded text-sm">
                              <AlertCircle className="w-4 h-4 text-yellow-600" />
                              <span>{warning}</span>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}

                    {/* Action buttons */}
                    <div className="flex gap-2 pt-4 border-t">
                      <Button
                        onClick={handleConfirmImport}
                        className="flex-1"
                      >
                        <CheckCircle className="w-4 h-4 mr-2" />
                        Import to Canvas
                      </Button>
                      <Button
                        variant="outline"
                        onClick={handleCancelImport}
                      >
                        Cancel
                      </Button>
                    </div>
                  </>
                )}

                {!importResult.success && (
                  <div className="space-y-4">
                    <div className="p-4 bg-red-50 border border-red-200 rounded-lg">
                      <h4 className="font-medium text-red-800 mb-2">Import Failed</h4>
                      <div className="space-y-1">
                        {importResult.errors?.map((error, index) => (
                          <p key={index} className="text-sm text-red-600">{error}</p>
                        ))}
                      </div>
                    </div>
                    <Button
                      onClick={handleCancelImport}
                      className="w-full"
                    >
                      Try Again
                    </Button>
                  </div>
                )}
              </div>
            ) : (
              <div className="text-center text-muted-foreground py-8">
                <Upload className="w-8 h-8 mx-auto mb-2 opacity-50" />
                <p className="text-sm">No file imported yet</p>
                <p className="text-xs">Upload a file to see preview</p>
              </div>
            )}
          </TabsContent>
        </Tabs>
      </CardContent>
    </Card>
  );
};

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { Stage, Layer, Rect, Circle, Text, Image, Group, Transformer } from 'react-konva';
import Konva from 'konva';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { 
  Move, 
  Type, 
  Square, 
  Circle as CircleIcon, 
  Image as ImageIcon, 
  RotateCw, 
  Trash2,
  Copy,
  Lock,
  Unlock,
  Eye,
  EyeOff
} from 'lucide-react';

export interface KonvaElement {
  id: string;
  type: 'text' | 'rect' | 'circle' | 'image' | 'group';
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number;
  opacity: number;
  visible: boolean;
  locked: boolean;
  zIndex: number;
  // Text properties
  text?: string;
  fontSize?: number;
  fontFamily?: string;
  fontWeight?: string;
  fontStyle?: string;
  textAlign?: 'left' | 'center' | 'right';
  fill?: string;
  stroke?: string;
  strokeWidth?: number;
  // Shape properties
  fillColor?: string;
  strokeColor?: string;
  cornerRadius?: number;
  // Image properties
  src?: string;
  cropX?: number;
  cropY?: number;
  cropWidth?: number;
  cropHeight?: number;
  // Group properties
  children?: KonvaElement[];
}

interface KonvaCanvasProps {
  width: number;
  height: number;
  elements: KonvaElement[];
  selectedElementId?: string;
  onElementSelect: (elementId: string | null) => void;
  onElementUpdate: (elementId: string, updates: Partial<KonvaElement>) => void;
  onElementDelete: (elementId: string) => void;
  onElementAdd: (element: Omit<KonvaElement, 'id'>) => void;
  onElementDuplicate: (elementId: string) => void;
  onElementLock: (elementId: string, locked: boolean) => void;
  onElementVisibility: (elementId: string, visible: boolean) => void;
  onElementReorder: (elementId: string, newZIndex: number) => void;
  background?: {
    color?: string;
    image?: string;
  };
  gridSize?: number;
  showGrid?: boolean;
  snapToGrid?: boolean;
}

export const KonvaCanvas: React.FC<KonvaCanvasProps> = ({
  width,
  height,
  elements,
  selectedElementId,
  onElementSelect,
  onElementUpdate,
  onElementDelete,
  onElementAdd,
  onElementDuplicate,
  onElementLock,
  onElementVisibility,
  onElementReorder,
  background,
  gridSize = 10,
  showGrid = false,
  snapToGrid = false,
}) => {
  const stageRef = useRef<Konva.Stage>(null);
  const transformerRef = useRef<Konva.Transformer>(null);
  const [selectedElement, setSelectedElement] = useState<KonvaElement | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const [editingText, setEditingText] = useState<{ id: string; text: string; x: number; y: number; width: number; height: number; fontSize: number; fontFamily: string; textAlign: string } | null>(null);

  // Update transformer when selection changes
  useEffect(() => {
    if (transformerRef.current && selectedElementId) {
      const element = elements.find(el => el.id === selectedElementId);
      if (element) {
        setSelectedElement(element);
        const stage = stageRef.current;
        if (stage) {
          const selectedNode = stage.findOne(`#${selectedElementId}`);
          if (selectedNode) {
            transformerRef.current.nodes([selectedNode]);
            transformerRef.current.getLayer()?.batchDraw();
          }
        }
      }
    } else {
      transformerRef.current?.nodes([]);
      setSelectedElement(null);
    }
  }, [selectedElementId, elements]);

  // Handle element selection
  const handleElementClick = useCallback((e: Konva.KonvaEventObject<MouseEvent>) => {
    const elementId = e.target.id();
    if (elementId) {
      onElementSelect(elementId);
    } else {
      onElementSelect(null);
    }
  }, [onElementSelect]);

  // Handle element drag start
  const handleDragStart = useCallback((e: Konva.KonvaEventObject<DragEvent>) => {
    setIsDragging(true);
    const pos = e.target.position();
    setDragStart(pos);
  }, []);

  // Handle element drag end
  const handleDragEnd = useCallback((e: Konva.KonvaEventObject<DragEvent>) => {
    setIsDragging(false);
    const elementId = e.target.id();
    const pos = e.target.position();

    if (snapToGrid) {
      pos.x = Math.round(pos.x / gridSize) * gridSize;
      pos.y = Math.round(pos.y / gridSize) * gridSize;
      e.target.position(pos);
    }

    if (elementId) {
      onElementUpdate(elementId, { x: pos.x, y: pos.y });
    }
  }, [snapToGrid, gridSize, onElementUpdate]);

  // Handle element transform
  const handleTransform = useCallback((e: Konva.KonvaEventObject<Event>) => {
    const elementId = e.target.id();
    const node = e.target;

    if (elementId) {
      const scaleX = node.scaleX();
      const scaleY = node.scaleY();
      const rotation = node.rotation();

      // Reset scale and apply to width/height
      node.scaleX(1);
      node.scaleY(1);

      const newWidth = Math.max(5, node.width() * scaleX);
      const newHeight = Math.max(5, node.height() * scaleY);

      onElementUpdate(elementId, {
        width: newWidth,
        height: newHeight,
        rotation: rotation,
      });
    }
  }, [onElementUpdate]);

  // Handle keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (selectedElementId) {
        switch (e.key) {
          case 'Delete':
          case 'Backspace':
            onElementDelete(selectedElementId);
            break;
          case 'd':
            if (e.ctrlKey || e.metaKey) {
              e.preventDefault();
              onElementDuplicate(selectedElementId);
            }
            break;
          case 'l':
            if (e.ctrlKey || e.metaKey) {
              e.preventDefault();
              const element = elements.find(el => el.id === selectedElementId);
              if (element) {
                onElementLock(selectedElementId, !element.locked);
              }
            }
            break;
          case 'h':
            if (e.ctrlKey || e.metaKey) {
              e.preventDefault();
              const element = elements.find(el => el.id === selectedElementId);
              if (element) {
                onElementVisibility(selectedElementId, !element.visible);
              }
            }
            break;
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedElementId, elements, onElementDelete, onElementDuplicate, onElementLock, onElementVisibility]);

  // Render grid
  const renderGrid = () => {
    if (!showGrid) return null;

    const lines = [];
    for (let i = 0; i <= width; i += gridSize) {
      lines.push(
        <Rect
          key={`v-${i}`}
          x={i}
          y={0}
          width={1}
          height={height}
          fill="#e0e0e0"
          opacity={0.5}
        />
      );
    }
    for (let i = 0; i <= height; i += gridSize) {
      lines.push(
        <Rect
          key={`h-${i}`}
          x={0}
          y={i}
          width={width}
          height={1}
          fill="#e0e0e0"
          opacity={0.5}
        />
      );
    }
    return lines;
  };

  // Render background
  const renderBackground = () => {
    if (background?.image) {
      return (
        <Image
          image={new window.Image()}
          x={0}
          y={0}
          width={width}
          height={height}
          fill={background.color}
        />
      );
    }
    if (background?.color) {
      return (
        <Rect
          x={0}
          y={0}
          width={width}
          height={height}
          fill={background.color}
        />
      );
    }
    return null;
  };

  // Render element based on type
  const renderElement = (element: KonvaElement) => {
    const commonProps = {
      id: element.id,
      x: element.x,
      y: element.y,
      width: element.width,
      height: element.height,
      rotation: element.rotation,
      opacity: element.opacity,
      visible: element.visible,
      draggable: !element.locked,
      onClick: handleElementClick,
      onDragStart: handleDragStart,
      onDragEnd: handleDragEnd,
      onTransform: handleTransform,
    };

    switch (element.type) {
      case 'text':
        return (
          <Text
            {...commonProps}
            text={element.text || ''}
            fontSize={element.fontSize || 16}
            fontFamily={element.fontFamily || 'Arial'}
            fontStyle={element.fontStyle || 'normal'}
            fontWeight={element.fontWeight || 'normal'}
            align={element.textAlign || 'left'}
            fill={element.fill || '#000000'}
            stroke={element.stroke}
            strokeWidth={element.strokeWidth || 0}
            verticalAlign="middle"
            onDblClick={(e) => {
              if (element.locked) return;
              e.cancelBubble = true;

              const stage = stageRef.current;
              if (!stage) return;

              const textNode = e.target;
              // get absolute position taking into account scale
              const absPos = textNode.absolutePosition();
              const scale = stage.scaleX() || 1;
              const globalZoom = 1; // Handled by outer div scale

              setEditingText({
                id: element.id,
                text: element.text || '',
                x: absPos.x,
                y: absPos.y,
                width: textNode.width() * textNode.scaleX(),
                height: textNode.height() * textNode.scaleY(),
                fontSize: (element.fontSize || 16) * textNode.scaleX(),
                fontFamily: element.fontFamily || 'Arial',
                textAlign: element.textAlign || 'left',
              });

              // Hide the text node while editing
              textNode.hide();
              transformerRef.current?.nodes([]);
            }}
          />
        );

      case 'rect':
        return (
          <Rect
            {...commonProps}
            fill={element.fillColor || '#000000'}
            stroke={element.strokeColor}
            strokeWidth={element.strokeWidth || 0}
            cornerRadius={element.cornerRadius || 0}
          />
        );

      case 'circle':
        return (
          <Circle
            {...commonProps}
            radius={Math.min(element.width, element.height) / 2}
            fill={element.fillColor || '#000000'}
            stroke={element.strokeColor}
            strokeWidth={element.strokeWidth || 0}
          />
        );

      case 'image':
        return (
          <Image
            {...commonProps}
            image={element.src ? new window.Image() : undefined}
            cropX={element.cropX || 0}
            cropY={element.cropY || 0}
            cropWidth={element.cropWidth || element.width}
            cropHeight={element.cropHeight || element.height}
          />
        );

      case 'group':
        return (
          <Group {...commonProps}>
            {element.children?.map(child => renderElement(child))}
          </Group>
        );

      default:
        return null;
    }
  };

  // Handle drop from tools panel
  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    const type = e.dataTransfer.getData('application/gotek-element');
    const propertiesStr = e.dataTransfer.getData('application/gotek-properties');
    if (!type) return;

    stageRef.current?.setPointersPositions(e.nativeEvent);
    let pos = stageRef.current?.getPointerPosition();
    if (!pos) pos = { x: 50, y: 50 };

    if (snapToGrid && gridSize) {
      pos.x = Math.round(pos.x / gridSize) * gridSize;
      pos.y = Math.round(pos.y / gridSize) * gridSize;
    }

    const properties = propertiesStr ? JSON.parse(propertiesStr) : {};

    onElementAdd({
      type: type as any,
      x: pos.x,
      y: pos.y,
      width: type === 'rect' || type === 'circle' ? 100 : 200,
      height: type === 'text' ? 30 : 100,
      rotation: 0,
      opacity: 1,
      visible: true,
      locked: false,
      zIndex: elements.length,
      text: type === 'text' ? 'New Text' : undefined,
      ...properties
    });
  }, [elements.length, onElementAdd, snapToGrid, gridSize]);

  return (
    <div className="relative">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Move className="w-5 h-5" />
            Canvas Editor
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div 
            className="border rounded-lg overflow-hidden relative"
            onDrop={handleDrop}
            onDragOver={(e) => { e.preventDefault(); e.dataTransfer.dropEffect = 'copy'; }}
          >
            {editingText && (
              <textarea
                value={editingText.text}
                onChange={(e) => setEditingText({ ...editingText, text: e.target.value })}
                onKeyDown={(e) => {
                  if (e.key === 'Escape') {
                    const textNode = stageRef.current?.findOne(`#${editingText.id}`);
                    textNode?.show();
                    setEditingText(null);
                  }
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    e.currentTarget.blur();
                  }
                }}
                onBlur={() => {
                  onElementUpdate(editingText.id, { text: editingText.text });
                  const textNode = stageRef.current?.findOne(`#${editingText.id}`);
                  textNode?.show();
                  setEditingText(null);
                  onElementSelect(editingText.id);
                }}
                autoFocus
                style={{
                  position: 'absolute',
                  top: `${editingText.y}px`,
                  left: `${editingText.x}px`,
                  width: `${editingText.width}px`,
                  height: `${editingText.height}px`,
                  fontSize: `${editingText.fontSize}px`,
                  fontFamily: editingText.fontFamily,
                  textAlign: editingText.textAlign as any,
                  border: 'none',
                  padding: '0px',
                  margin: '0px',
                  overflow: 'hidden',
                  background: 'none',
                  outline: 'none',
                  resize: 'none',
                  lineHeight: 1,
                  color: '#000',
                  transformOrigin: 'left top',
                  zIndex: 1000,
                  whiteSpace: 'pre-wrap'
                }}
              />
            )}
            <Stage
              ref={stageRef}
              width={width}
              height={height}
              onClick={handleElementClick}
            >
              <Layer>
                {renderBackground()}
                {renderGrid()}
                {elements
                  .sort((a, b) => a.zIndex - b.zIndex)
                  .map(element => renderElement(element))}
                <Transformer
                  ref={transformerRef}
                  boundBoxFunc={(oldBox, newBox) => {
                    // Limit resize
                    if (newBox.width < 5 || newBox.height < 5) {
                      return oldBox;
                    }
                    return newBox;
                  }}
                />
              </Layer>
            </Stage>
          </div>
        </CardContent>
      </Card>

      {/* Toolbar */}
      <Card className="mt-4">
        <CardContent className="p-4">
          <div className="flex flex-wrap gap-2">
            <Button
              size="sm"
              variant="outline"
              onClick={() => onElementAdd({
                type: 'text',
                x: 50,
                y: 50,
                width: 200,
                height: 30,
                rotation: 0,
                opacity: 1,
                visible: true,
                locked: false,
                zIndex: elements.length,
                text: 'New Text',
                fontSize: 16,
                fontFamily: 'Arial',
                fill: '#000000',
              })}
            >
              <Type className="w-4 h-4 mr-1" />
              Add Text
            </Button>

            <Button
              size="sm"
              variant="outline"
              onClick={() => onElementAdd({
                type: 'rect',
                x: 50,
                y: 50,
                width: 100,
                height: 100,
                rotation: 0,
                opacity: 1,
                visible: true,
                locked: false,
                zIndex: elements.length,
                fillColor: '#000000',
              })}
            >
              <Square className="w-4 h-4 mr-1" />
              Add Rectangle
            </Button>

            <Button
              size="sm"
              variant="outline"
              onClick={() => onElementAdd({
                type: 'circle',
                x: 50,
                y: 50,
                width: 100,
                height: 100,
                rotation: 0,
                opacity: 1,
                visible: true,
                locked: false,
                zIndex: elements.length,
                fillColor: '#000000',
              })}
            >
              <CircleIcon className="w-4 h-4 mr-1" />
              Add Circle
            </Button>

            {selectedElementId && (
              <>
                <Button
                  size="sm"
                  variant="outline"
                  onClick={() => onElementDuplicate(selectedElementId)}
                >
                  <Copy className="w-4 h-4 mr-1" />
                  Duplicate
                </Button>

                <Button
                  size="sm"
                  variant="outline"
                  onClick={() => {
                    const element = elements.find(el => el.id === selectedElementId);
                    if (element) {
                      onElementLock(selectedElementId, !element.locked);
                    }
                  }}
                >
                  {selectedElement?.locked ? <Unlock className="w-4 h-4 mr-1" /> : <Lock className="w-4 h-4 mr-1" />}
                  {selectedElement?.locked ? 'Unlock' : 'Lock'}
                </Button>

                <Button
                  size="sm"
                  variant="outline"
                  onClick={() => {
                    const element = elements.find(el => el.id === selectedElementId);
                    if (element) {
                      onElementVisibility(selectedElementId, !element.visible);
                    }
                  }}
                >
                  {selectedElement?.visible ? <EyeOff className="w-4 h-4 mr-1" /> : <Eye className="w-4 h-4 mr-1" />}
                  {selectedElement?.visible ? 'Hide' : 'Show'}
                </Button>

                <Button
                  size="sm"
                  variant="destructive"
                  onClick={() => onElementDelete(selectedElementId)}
                >
                  <Trash2 className="w-4 h-4 mr-1" />
                  Delete
                </Button>
              </>
            )}
          </div>
        </CardContent>
      </Card>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Slider } from '@/components/ui/slider';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Badge } from '@/components/ui/badge';
import { 
  Settings, 
  Type, 
  Palette, 
  Move, 
  RotateCw, 
  Square, 
  Circle as CircleIcon,
  Image as ImageIcon,
  Layers,
  Eye,
  Lock,
  AlignLeft,
  AlignCenter,
  AlignRight,
  Bold,
  Italic,
  Underline,
  Copy,
  Trash2
} from 'lucide-react';
import { DynamicField, PREDEFINED_FIELDS } from '@/utils/dynamicFields';

export interface ElementProperties {
  // Common properties
  id: string;
  name: string;
  type: 'text' | 'rect' | 'circle' | 'image' | 'group' | 'background';
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number;
  opacity: number;
  visible: boolean;
  locked: boolean;
  zIndex: number;

  // Text properties
  text?: string;
  fontSize?: number;
  fontFamily?: string;
  fontWeight?: string;
  fontStyle?: string;
  textAlign?: 'left' | 'center' | 'right';
  fill?: string;
  stroke?: string;
  strokeWidth?: number;

  // Shape properties
  fillColor?: string;
  strokeColor?: string;
  cornerRadius?: number;

  // Image properties
  src?: string;
  cropX?: number;
  cropY?: number;
  cropWidth?: number;
  cropHeight?: number;

  // Effects
  shadow?: {
    color: string;
    blur: number;
    offsetX: number;
    offsetY: number;
  };
  filters?: {
    brightness?: number;
    contrast?: number;
    saturation?: number;
    blur?: number;
  };
  blendMode?: string;
}

interface PropertiesPanelProps {
  selectedElement: ElementProperties | null;
  onElementUpdate: (updates: Partial<ElementProperties>) => void;
  onElementDelete: () => void;
  onElementDuplicate: () => void;
  onElementLock: (locked: boolean) => void;
  onElementVisibility: (visible: boolean) => void;
  onElementReorder: (newZIndex: number) => void;
  canvasBackground?: { color?: string; image?: string };
  onCanvasBackgroundChange?: (bg: { color?: string; image?: string }) => void;
}

export const PropertiesPanel: React.FC<PropertiesPanelProps> = ({
  selectedElement,
  onElementUpdate,
  onElementDelete,
  onElementDuplicate,
  onElementLock,
  onElementVisibility,
  onElementReorder,
  canvasBackground,
  onCanvasBackgroundChange,
}) => {
  const [localProperties, setLocalProperties] = useState<Partial<ElementProperties>>({});
  const [showDynamicFields, setShowDynamicFields] = useState(false);

  // Update local properties when selected element changes
  useEffect(() => {
    if (selectedElement) {
      setLocalProperties(selectedElement);
    } else {
      setLocalProperties({});
    }
  }, [selectedElement]);

  // Handle property change
  const handlePropertyChange = (property: keyof ElementProperties, value: any) => {
    const newProperties = { ...localProperties, [property]: value };
    setLocalProperties(newProperties);
    onElementUpdate(newProperties);
  };

  // Handle numeric input with validation
  const handleNumericChange = (property: keyof ElementProperties, value: string) => {
    const numValue = parseFloat(value);
    if (!isNaN(numValue)) {
      handlePropertyChange(property, numValue);
    }
  };

  // Handle color change
  const handleColorChange = (property: keyof ElementProperties, value: string) => {
    handlePropertyChange(property, value);
  };

  // Handle dynamic field insertion
  const handleDynamicFieldInsert = (field: DynamicField) => {
    if (selectedElement?.type === 'text') {
      const currentText = localProperties.text || '';
      const newText = currentText + field.placeholder;
      handlePropertyChange('text', newText);
    }
  };

  const handleBackgroundUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && onCanvasBackgroundChange) {
      const reader = new FileReader();
      reader.onload = (event) => {
        onCanvasBackgroundChange({ ...canvasBackground, image: event.target?.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  if (!selectedElement) {
    return (
      <Card className="h-full">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Settings className="w-5 h-5" />
            Canvas Settings
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-6">
          <div className="space-y-4">
            <div className="space-y-2">
              <Label>Background Color</Label>
              <div className="flex gap-2">
                <Input
                  type="color"
                  value={canvasBackground?.color || '#ffffff'}
                  onChange={(e) => onCanvasBackgroundChange?.({ ...canvasBackground, color: e.target.value })}
                  className="w-12 h-10 p-1 cursor-pointer"
                />
                <Input
                  value={canvasBackground?.color || '#ffffff'}
                  onChange={(e) => onCanvasBackgroundChange?.({ ...canvasBackground, color: e.target.value })}
                  placeholder="#ffffff"
                  className="flex-1"
                />
              </div>
            </div>

            <div className="space-y-2 pb-4">
              <Label>Background Image</Label>
              {canvasBackground?.image ? (
                <div className="relative group rounded-md border overflow-hidden aspect-video bg-gray-50 flex items-center justify-center">
                  <img src={canvasBackground.image} alt="Background" className="max-h-full object-contain" />
                  <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                    <Button 
                      variant="destructive" 
                      size="sm" 
                      onClick={() => onCanvasBackgroundChange?.({ ...canvasBackground, image: undefined })}
                    >
                      Remove
                    </Button>
                  </div>
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center p-6 border-2 border-dashed rounded-md bg-gray-50">
                  <ImageIcon className="w-8 h-8 text-gray-400 mb-2" />
                  <Label className="cursor-pointer bg-white border shadow-sm px-4 py-2 rounded-md hover:bg-gray-50 transition-colors">
                    Upload Image
                    <Input
                      type="file"
                      accept="image/*"
                      className="hidden"
                      onChange={handleBackgroundUpload}
                    />
                  </Label>
                </div>
              )}
            </div>

            <div className="border-t pt-4">
              <p className="text-sm text-muted-foreground text-center">
                Select an element on the canvas to edit its specific properties.
              </p>
            </div>
          </div>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card className="h-full">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Settings className="w-5 h-5" />
          Properties
        </CardTitle>
      </CardHeader>
      <CardContent className="p-0">
        <Tabs defaultValue="general" className="w-full">
          <TabsList className="grid w-full grid-cols-3">
            <TabsTrigger value="general">General</TabsTrigger>
            <TabsTrigger value="appearance">Appearance</TabsTrigger>
            <TabsTrigger value="effects">Effects</TabsTrigger>
          </TabsList>

          <TabsContent value="general" className="p-4 space-y-4">
            {/* Element info */}
            <div className="space-y-2">
              <Label>Element Name</Label>
              <Input
                value={localProperties.name || ''}
                onChange={(e) => handlePropertyChange('name', e.target.value)}
                placeholder="Element name"
              />
            </div>

            {/* Position and size */}
            <div className="grid grid-cols-2 gap-2">
              <div className="space-y-2">
                <Label>X Position</Label>
                <Input
                  type="number"
                  value={localProperties.x || 0}
                  onChange={(e) => handleNumericChange('x', e.target.value)}
                />
              </div>
              <div className="space-y-2">
                <Label>Y Position</Label>
                <Input
                  type="number"
                  value={localProperties.y || 0}
                  onChange={(e) => handleNumericChange('y', e.target.value)}
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <div className="space-y-2">
                <Label>Width</Label>
                <Input
                  type="number"
                  value={localProperties.width || 0}
                  onChange={(e) => handleNumericChange('width', e.target.value)}
                />
              </div>
              <div className="space-y-2">
                <Label>Height</Label>
                <Input
                  type="number"
                  value={localProperties.height || 0}
                  onChange={(e) => handleNumericChange('height', e.target.value)}
                />
              </div>
            </div>

            {/* Rotation */}
            <div className="space-y-2">
              <Label>Rotation: {localProperties.rotation || 0}°</Label>
              <Slider
                value={[localProperties.rotation || 0]}
                onValueChange={([value]) => handlePropertyChange('rotation', value)}
                min={-180}
                max={180}
                step={1}
                className="w-full"
              />
            </div>

            {/* Opacity */}
            <div className="space-y-2">
              <Label>Opacity: {Math.round((localProperties.opacity || 1) * 100)}%</Label>
              <Slider
                value={[(localProperties.opacity || 1) * 100]}
                onValueChange={([value]) => handlePropertyChange('opacity', value / 100)}
                min={0}
                max={100}
                step={1}
                className="w-full"
              />
            </div>

            {/* Z-Index */}
            <div className="space-y-2">
              <Label>Layer Order</Label>
              <Input
                type="number"
                value={localProperties.zIndex || 0}
                onChange={(e) => handleNumericChange('zIndex', e.target.value)}
              />
            </div>

            {/* Visibility and lock */}
            <div className="flex gap-2">
              <Button
                size="sm"
                variant={localProperties.visible ? "default" : "outline"}
                onClick={() => onElementVisibility(!localProperties.visible)}
                className="flex-1"
              >
                <Eye className="w-4 h-4 mr-1" />
                {localProperties.visible ? 'Visible' : 'Hidden'}
              </Button>
              <Button
                size="sm"
                variant={localProperties.locked ? "default" : "outline"}
                onClick={() => onElementLock(!localProperties.locked)}
                className="flex-1"
              >
                <Lock className="w-4 h-4 mr-1" />
                {localProperties.locked ? 'Locked' : 'Unlocked'}
              </Button>
            </div>
          </TabsContent>

          <TabsContent value="appearance" className="p-4 space-y-4">
            {/* Text properties */}
            {selectedElement.type === 'text' && (
              <>
                <div className="space-y-2">
                  <Label>Text Content</Label>
                  <div className="flex gap-2">
                    <Input
                      value={localProperties.text || ''}
                      onChange={(e) => handlePropertyChange('text', e.target.value)}
                      placeholder="Enter text"
                      className="flex-1"
                    />
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => setShowDynamicFields(!showDynamicFields)}
                    >
                      <Type className="w-4 h-4" />
                    </Button>
                  </div>
                </div>

                {showDynamicFields && (
                  <div className="space-y-2">
                    <Label>Dynamic Fields</Label>
                    <div className="max-h-32 overflow-y-auto space-y-1">
                      {PREDEFINED_FIELDS.map(field => (
                        <Button
                          key={field.id}
                          size="sm"
                          variant="outline"
                          className="w-full justify-start text-xs"
                          onClick={() => handleDynamicFieldInsert(field)}
                        >
                          {field.placeholder}
                        </Button>
                      ))}
                    </div>
                  </div>
                )}

                <div className="grid grid-cols-2 gap-2">
                  <div className="space-y-2">
                    <Label>Font Size</Label>
                    <Input
                      type="number"
                      value={localProperties.fontSize || 16}
                      onChange={(e) => handleNumericChange('fontSize', e.target.value)}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label>Font Family</Label>
                    <Select
                      value={localProperties.fontFamily || 'Arial'}
                      onValueChange={(value) => handlePropertyChange('fontFamily', value)}
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="Arial">Arial</SelectItem>
                        <SelectItem value="Helvetica">Helvetica</SelectItem>
                        <SelectItem value="Times New Roman">Times New Roman</SelectItem>
                        <SelectItem value="Georgia">Georgia</SelectItem>
                        <SelectItem value="Verdana">Verdana</SelectItem>
                        <SelectItem value="Courier New">Courier New</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                <div className="flex gap-2">
                  <Button
                    size="sm"
                    variant={localProperties.fontWeight === 'bold' ? "default" : "outline"}
                    onClick={() => handlePropertyChange('fontWeight', 
                      localProperties.fontWeight === 'bold' ? 'normal' : 'bold'
                    )}
                  >
                    <Bold className="w-4 h-4" />
                  </Button>
                  <Button
                    size="sm"
                    variant={localProperties.fontStyle === 'italic' ? "default" : "outline"}
                    onClick={() => handlePropertyChange('fontStyle', 
                      localProperties.fontStyle === 'italic' ? 'normal' : 'italic'
                    )}
                  >
                    <Italic className="w-4 h-4" />
                  </Button>
                  <div className="flex-1">
                    <Select
                      value={localProperties.textAlign || 'left'}
                      onValueChange={(value) => handlePropertyChange('textAlign', value)}
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="left">Left</SelectItem>
                        <SelectItem value="center">Center</SelectItem>
                        <SelectItem value="right">Right</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>
              </>
            )}

            {/* Fill color */}
            <div className="space-y-2">
              <Label>Fill Color</Label>
              <div className="flex gap-2">
                <Input
                  type="color"
                  value={localProperties.fill || localProperties.fillColor || '#000000'}
                  onChange={(e) => handleColorChange('fill', e.target.value)}
                  className="w-12 h-10 p-1"
                />
                <Input
                  value={localProperties.fill || localProperties.fillColor || '#000000'}
                  onChange={(e) => handleColorChange('fill', e.target.value)}
                  placeholder="#000000"
                  className="flex-1"
                />
              </div>
            </div>

            {/* Stroke color */}
            <div className="space-y-2">
              <Label>Stroke Color</Label>
              <div className="flex gap-2">
                <Input
                  type="color"
                  value={localProperties.stroke || localProperties.strokeColor || '#000000'}
                  onChange={(e) => handleColorChange('stroke', e.target.value)}
                  className="w-12 h-10 p-1"
                />
                <Input
                  value={localProperties.stroke || localProperties.strokeColor || '#000000'}
                  onChange={(e) => handleColorChange('stroke', e.target.value)}
                  placeholder="#000000"
                  className="flex-1"
                />
              </div>
            </div>

            {/* Stroke width */}
            <div className="space-y-2">
              <Label>Stroke Width: {localProperties.strokeWidth || 0}px</Label>
              <Slider
                value={[localProperties.strokeWidth || 0]}
                onValueChange={([value]) => handlePropertyChange('strokeWidth', value)}
                min={0}
                max={20}
                step={1}
                className="w-full"
              />
            </div>

            {/* Corner radius for rectangles */}
            {selectedElement.type === 'rect' && (
              <div className="space-y-2">
                <Label>Corner Radius: {localProperties.cornerRadius || 0}px</Label>
                <Slider
                  value={[localProperties.cornerRadius || 0]}
                  onValueChange={([value]) => handlePropertyChange('cornerRadius', value)}
                  min={0}
                  max={50}
                  step={1}
                  className="w-full"
                />
              </div>
            )}
          </TabsContent>

          <TabsContent value="effects" className="p-4 space-y-4">
            {/* Shadow */}
            <div className="space-y-2">
              <Label>Shadow</Label>
              <div className="grid grid-cols-2 gap-2">
                <div className="space-y-2">
                  <Label className="text-xs">Color</Label>
                  <Input
                    type="color"
                    value={localProperties.shadow?.color || '#000000'}
                    onChange={(e) => handlePropertyChange('shadow', {
                      ...localProperties.shadow,
                      color: e.target.value
                    })}
                    className="w-full h-8"
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-xs">Blur</Label>
                  <Input
                    type="number"
                    value={localProperties.shadow?.blur || 0}
                    onChange={(e) => handlePropertyChange('shadow', {
                      ...localProperties.shadow,
                      blur: parseFloat(e.target.value) || 0
                    })}
                  />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-2">
                <div className="space-y-2">
                  <Label className="text-xs">Offset X</Label>
                  <Input
                    type="number"
                    value={localProperties.shadow?.offsetX || 0}
                    onChange={(e) => handlePropertyChange('shadow', {
                      ...localProperties.shadow,
                      offsetX: parseFloat(e.target.value) || 0
                    })}
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-xs">Offset Y</Label>
                  <Input
                    type="number"
                    value={localProperties.shadow?.offsetY || 0}
                    onChange={(e) => handlePropertyChange('shadow', {
                      ...localProperties.shadow,
                      offsetY: parseFloat(e.target.value) || 0
                    })}
                  />
                </div>
              </div>
            </div>

            {/* Filters */}
            <div className="space-y-2">
              <Label>Filters</Label>
              <div className="grid grid-cols-2 gap-2">
                <div className="space-y-2">
                  <Label className="text-xs">Brightness: {localProperties.filters?.brightness || 0}%</Label>
                  <Slider
                    value={[localProperties.filters?.brightness || 0]}
                    onValueChange={([value]) => handlePropertyChange('filters', {
                      ...localProperties.filters,
                      brightness: value
                    })}
                    min={-100}
                    max={100}
                    step={1}
                    className="w-full"
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-xs">Contrast: {localProperties.filters?.contrast || 0}%</Label>
                  <Slider
                    value={[localProperties.filters?.contrast || 0]}
                    onValueChange={([value]) => handlePropertyChange('filters', {
                      ...localProperties.filters,
                      contrast: value
                    })}
                    min={-100}
                    max={100}
                    step={1}
                    className="w-full"
                  />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-2">
                <div className="space-y-2">
                  <Label className="text-xs">Saturation: {localProperties.filters?.saturation || 0}%</Label>
                  <Slider
                    value={[localProperties.filters?.saturation || 0]}
                    onValueChange={([value]) => handlePropertyChange('filters', {
                      ...localProperties.filters,
                      saturation: value
                    })}
                    min={-100}
                    max={100}
                    step={1}
                    className="w-full"
                  />
                </div>
                <div className="space-y-2">
                  <Label className="text-xs">Blur: {localProperties.filters?.blur || 0}px</Label>
                  <Slider
                    value={[localProperties.filters?.blur || 0]}
                    onValueChange={([value]) => handlePropertyChange('filters', {
                      ...localProperties.filters,
                      blur: value
                    })}
                    min={0}
                    max={20}
                    step={1}
                    className="w-full"
                  />
                </div>
              </div>
            </div>

            {/* Blend mode */}
            <div className="space-y-2">
              <Label>Blend Mode</Label>
              <Select
                value={localProperties.blendMode || 'normal'}
                onValueChange={(value) => handlePropertyChange('blendMode', value)}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="normal">Normal</SelectItem>
                  <SelectItem value="multiply">Multiply</SelectItem>
                  <SelectItem value="screen">Screen</SelectItem>
                  <SelectItem value="overlay">Overlay</SelectItem>
                  <SelectItem value="soft-light">Soft Light</SelectItem>
                  <SelectItem value="hard-light">Hard Light</SelectItem>
                  <SelectItem value="color-dodge">Color Dodge</SelectItem>
                  <SelectItem value="color-burn">Color Burn</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </TabsContent>
        </Tabs>

        {/* Action buttons */}
        <div className="p-4 border-t">
          <div className="flex gap-2">
            <Button
              size="sm"
              variant="outline"
              onClick={onElementDuplicate}
              className="flex-1"
            >
              <Copy className="w-4 h-4 mr-1" />
              Duplicate
            </Button>
            <Button
              size="sm"
              variant="destructive"
              onClick={onElementDelete}
              className="flex-1"
            >
              <Trash2 className="w-4 h-4 mr-1" />
              Delete
            </Button>
          </div>
        </div>
      </CardContent>
    </Card>
  );
};

import React, { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Badge } from '@/components/ui/badge';
import { Slider } from '@/components/ui/slider';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { 
  Wrench, 
  Type, 
  Square, 
  Circle as CircleIcon, 
  Image as ImageIcon, 
  Move, 
  RotateCw, 
  ZoomIn, 
  ZoomOut, 
  Grid3X3, 
  Ruler,
  Palette,
  Layers,
  AlignLeft,
  AlignCenter,
  AlignRight,
  AlignJustify,
  Bold,
  Italic,
  Underline,
  Strikethrough,
  List,
  ListOrdered
} from 'lucide-react';

interface ToolsPanelProps {
  selectedTool: string;
  onToolSelect: (tool: string) => void;
  canvasZoom: number;
  onZoomChange: (zoom: number) => void;
  showGrid: boolean;
  onGridToggle: (show: boolean) => void;
  snapToGrid: boolean;
  onSnapToGridToggle: (snap: boolean) => void;
  gridSize: number;
  onGridSizeChange: (size: number) => void;
  onAddElement: (type: string, properties?: any) => void;
  onAlignElements: (alignment: string) => void;
  onDistributeElements: (distribution: string) => void;
  onGroupElements: () => void;
  onUngroupElements: () => void;
  onBringToFront: () => void;
  onSendToBack: () => void;
  onBringForward: () => void;
  onSendBackward: () => void;
}

export const ToolsPanel: React.FC<ToolsPanelProps> = ({
  selectedTool,
  onToolSelect,
  canvasZoom,
  onZoomChange,
  showGrid,
  onGridToggle,
  snapToGrid,
  onSnapToGridToggle,
  gridSize,
  onGridSizeChange,
  onAddElement,
  onAlignElements,
  onDistributeElements,
  onGroupElements,
  onUngroupElements,
  onBringToFront,
  onSendToBack,
  onBringForward,
  onSendBackward,
}) => {
  const [textProperties, setTextProperties] = useState({
    fontSize: 16,
    fontFamily: 'Arial',
    fontWeight: 'normal',
    fontStyle: 'normal',
    textAlign: 'left',
    fill: '#000000',
    stroke: '#000000',
    strokeWidth: 0,
    textDecoration: 'none',
  });

  const [shapeProperties, setShapeProperties] = useState({
    fill: '#000000',
    stroke: '#000000',
    strokeWidth: 0,
    cornerRadius: 0,
  });

  const tools = [
    { id: 'select', name: 'Select', icon: Move, description: 'Select and move elements' },
    { id: 'text', name: 'Text', icon: Type, description: 'Add text elements' },
    { id: 'rect', name: 'Rectangle', icon: Square, description: 'Add rectangle shapes' },
    { id: 'circle', name: 'Circle', icon: CircleIcon, description: 'Add circle shapes' },
    { id: 'image', name: 'Image', icon: ImageIcon, description: 'Add image elements' },
  ];

  const handleToolSelect = (toolId: string) => {
    onToolSelect(toolId);
  };

  const handleAddElement = (type: string) => {
    const properties = type === 'text' ? textProperties : shapeProperties;
    onAddElement(type, properties);
  };

  const handleDragStartItem = (e: React.DragEvent, type: string) => {
    e.dataTransfer.setData('application/gotek-element', type);
    const properties = type === 'text' ? textProperties : shapeProperties;
    e.dataTransfer.setData('application/gotek-properties', JSON.stringify(properties));
    e.dataTransfer.effectAllowed = 'copy';
  };

  const handleTextPropertyChange = (property: string, value: any) => {
    setTextProperties(prev => ({ ...prev, [property]: value }));
  };

  const handleShapePropertyChange = (property: string, value: any) => {
    setShapeProperties(prev => ({ ...prev, [property]: value }));
  };

  return (
    <Card className="h-full">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Wrench className="w-5 h-5" />
          Tools
        </CardTitle>
      </CardHeader>
      <CardContent className="p-0">
        <Tabs defaultValue="tools" className="w-full">
          <TabsList className="grid w-full grid-cols-3">
            <TabsTrigger value="tools">Tools</TabsTrigger>
            <TabsTrigger value="properties">Properties</TabsTrigger>
            <TabsTrigger value="layout">Layout</TabsTrigger>
          </TabsList>

          <TabsContent value="tools" className="p-4">
            <div className="space-y-4">
              {/* Tool selection */}
              <div className="space-y-2">
                <Label>Drawing Tools</Label>
                <div className="grid grid-cols-2 gap-2">
                  {tools.map((tool) => (
                    <Button
                      key={tool.id}
                      variant={selectedTool === tool.id ? 'default' : 'outline'}
                      size="sm"
                      onClick={() => handleToolSelect(tool.id)}
                      className="justify-start"
                    >
                      <tool.icon className="w-4 h-4 mr-2" />
                      {tool.name}
                    </Button>
                  ))}
                </div>
              </div>

              {/* Canvas controls */}
              <div className="space-y-4">
                <div className="space-y-2">
                  <Label>Canvas Zoom: {Math.round(canvasZoom * 100)}%</Label>
                  <div className="flex gap-2">
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => onZoomChange(Math.max(0.1, canvasZoom - 0.1))}
                    >
                      <ZoomOut className="w-4 h-4" />
                    </Button>
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => onZoomChange(1)}
                    >
                      Reset
                    </Button>
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => onZoomChange(Math.min(5, canvasZoom + 0.1))}
                    >
