                                <button 
                                    onClick={handleDeleteProject}
                                    disabled={isDeleting}
                                    className="flex-1 py-2.5 bg-red-600 text-white rounded-xl text-sm font-semibold hover:bg-red-700 disabled:opacity-50 transition-colors flex items-center justify-center gap-2"
