        setNewAdmin({ name: '', email: '', password: '', role: 'super-admin', organization: isSuperAdmin ? '' : (user?.organization || 'GOTEK') });
    };

    const handleCreateAdmin = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsCreating(true);
        try {
            await authService.createAdmin({
                name: newAdmin.name,
                email: newAdmin.email,
                password: newAdmin.password,
                role: newAdmin.role,
                organization: newAdmin.organization || user?.organization || 'GOTEK'
            });
            toast.success('Access created successfully');
            setShowAddDialog(false);
            resetNewAdminForm();
            fetchAdmins();
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to create access');
        } finally {
            setIsCreating(false);
        }
    };

    const handleDeleteUser = async (id: string, name: string) => {
        if (!window.confirm(`Are you sure you want to revoke access for ${name}?`)) return;

        try {
            await authService.deleteUser(id);
            toast.success(`Access for ${name} revoked.`);
            fetchAdmins();
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to revoke access');
        }
    };

    const handleUpdateProfile = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        const formData = new FormData(e.currentTarget);
        const name = formData.get("name") as string;

        if (!name.trim()) {
            toast.error("Name cannot be empty");
            return;
        }

        setIsUpdatingProfile(true);
        try {
            await authService.updateProfile(user!._id, { name });
            updateUser({ name });
