  background?: {
    color?: string;
    image?: string;
  };
  canvas: {
    width: number;
    height: number;
  };
  sides?: {
    front: any[];
    back: any[];
  };
  // Multi-side background support
  backgrounds?: Record<string, { color?: string; image?: string }>;
}

// Export to unified JSON format
export const exportToJSON = (
  templateData: TemplateData,
  options: any
): string => {
  const exportData = {
    metadata: {
      ...templateData.metadata,
      exportedAt: new Date().toISOString(),
      exportVersion: '1.0',
    },
    canvas: templateData.canvas,
    background: templateData.background,
    elements: templateData.elements,
    sides: templateData.sides,
    backgrounds: templateData.backgrounds,
    exportOptions: options,
  };

  if (options.compress) {
    // Simple compression by removing unnecessary whitespace
    return JSON.stringify(exportData, null, 0);
  }

  return JSON.stringify(exportData, null, 2);
};

// Export to PDF
export const exportToPDF = async (
  templateData: TemplateData,
  options: Partial<ExportOptions> = {}
): Promise<void> => {
  const dpi = options.dpi || 300;
  const quality = options.quality || 1.0;
  const includeBleed = options.includeBleed || false;
  const bleedSize = options.bleedSize || 3; // mm

  const mmPerInch = 25.4;
  const widthMM = (templateData.canvas.width / dpi) * mmPerInch;
  const heightMM = (templateData.canvas.height / dpi) * mmPerInch;
  const finalWidth = includeBleed ? widthMM + (bleedSize * 2) : widthMM;
  const finalHeight = includeBleed ? heightMM + (bleedSize * 2) : heightMM;

  const pdf = new jsPDF({
    orientation: templateData.metadata.orientation,
    unit: 'mm',
    format: [finalWidth, finalHeight],
  });

  const sidesToExport = templateData.sides 
    ? [ { elements: templateData.sides.front, bg: templateData.backgrounds?.front || templateData.background },
        { elements: templateData.sides.back, bg: templateData.backgrounds?.back || templateData.background } ]
    : [ { elements: templateData.elements, bg: templateData.background } ];

  for (let i = 0; i < sidesToExport.length; i++) {
    if (i > 0) pdf.addPage([finalWidth, finalHeight], templateData.metadata.orientation);

    const side = sidesToExport[i];
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) continue;

    canvas.width = templateData.canvas.width;
    canvas.height = templateData.canvas.height;

    // Render background
    if (side.bg) {
      if (side.bg.color) {
        ctx.fillStyle = side.bg.color;
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      }
      if (side.bg.image) {
        const img = new Image();
        await new Promise<void>((resolve) => {
          img.onload = () => {
            ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
            resolve();
          };
          img.onerror = () => resolve();
          img.src = side.bg!.image!;
        });
      }
    }

    // Render elements
    for (const element of side.elements) {
      await renderElementToCanvas(ctx, element, canvas.width, canvas.height);
    }

    const imageData = canvas.toDataURL('image/png', quality);
    pdf.addImage(
      imageData,
      'PNG',
      includeBleed ? bleedSize : 0,
      includeBleed ? bleedSize : 0,
      widthMM,
      heightMM
    );
  }

  const fileName = `${templateData.metadata.name.replace(/\s+/g, '_')}_Template.pdf`;
  pdf.save(fileName);
};

// Export to PNG
export const exportToPNG = async (
  templateData: TemplateData,
  options: ExportOptions
): Promise<void> => {
  const quality = options.quality || 1.0;
  const includeBleed = options.includeBleed || false;
  const bleedSize = options.bleedSize || 3; // pixels

  // For multi-side templates, we export the front side by default in PNG
  // unless we're in the editor where it's handled differently.
  const side = templateData.sides 
    ? { elements: templateData.sides.front, bg: templateData.backgrounds?.front || templateData.background }
    : { elements: templateData.elements, bg: templateData.background };

  // Calculate final dimensions
  const finalWidth = includeBleed 
    ? templateData.canvas.width + (bleedSize * 2) 
    : templateData.canvas.width;
  const finalHeight = includeBleed 
    ? templateData.canvas.height + (bleedSize * 2) 
    : templateData.canvas.height;

  const canvas = document.createElement('canvas');
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error('Could not get canvas context');

  canvas.width = finalWidth;
  canvas.height = finalHeight;

  // Render background
  if (side.bg) {
    if (side.bg.color) {
      ctx.fillStyle = side.bg.color;
      ctx.fillRect(0, 0, canvas.width, canvas.height);
    }
    if (side.bg.image) {
      const img = new Image();
      await new Promise<void>((resolve) => {
        img.onload = () => {
          const x = includeBleed ? bleedSize : 0;
          const y = includeBleed ? bleedSize : 0;
          ctx.drawImage(img, x, y, templateData.canvas.width, templateData.canvas.height);
          resolve();
        };
        img.onerror = () => resolve();
        img.src = side.bg!.image!;
      });
    }
  }

  // Render elements
  for (const element of side.elements) {
    const elementX = (element.x || 0) + (includeBleed ? bleedSize : 0);
    const elementY = (element.y || 0) + (includeBleed ? bleedSize : 0);
    await renderElementToCanvas(ctx, element, templateData.canvas.width, templateData.canvas.height, elementX, elementY);
  }

  // Convert to blob and download
  canvas.toBlob((blob) => {
    if (blob) {
      const fileName = `${templateData.metadata.name.replace(/\s+/g, '_')}_Template.png`;
      saveAs(blob, fileName);
    }
  }, 'image/png', quality);
};

// Export to EPS (simplified implementation)
export const exportToEPS = async (
  templateData: TemplateData,
  options: ExportOptions
): Promise<void> => {
  // For now, we'll create a simple EPS file
  // In a production environment, you'd want to use a proper EPS library

  const epsContent = generateEPSContent(templateData);
  const blob = new Blob([epsContent], { type: 'application/postscript' });
  const fileName = `${templateData.metadata.name.replace(/\s+/g, '_')}_Template.eps`;
  saveAs(blob, fileName);
};

// Helper function to render element to canvas
const renderElementToCanvas = async (
  ctx: CanvasRenderingContext2D,
  element: any,
  canvasWidth: number,
  canvasHeight: number,
  offsetX = 0,
  offsetY = 0
): Promise<void> => {
  ctx.save();

  const x = (element.x || element.left || 0) + offsetX;
  const y = (element.y || element.top || 0) + offsetY;
  const width = element.width || 100;
  const height = element.height || 100;
  const rotation = element.rotation || element.angle || 0;
  const opacity = element.opacity || 1;

  ctx.globalAlpha = opacity;

  if (rotation !== 0) {
    ctx.translate(x + width / 2, y + height / 2);
    ctx.rotate((rotation * Math.PI) / 180);
    ctx.translate(-width / 2, -height / 2);
  }

  switch (element.type) {
    case 'text': {
      const fontSize = element.fontSize || 16;
      ctx.font = `${element.fontStyle || 'normal'} ${element.fontWeight || 'normal'} ${fontSize}px ${element.fontFamily || 'Arial'}`;
      ctx.fillStyle = element.fill || '#000000';
      ctx.textAlign = (element.textAlign as CanvasTextAlign) || 'left';

      if (element.text?.includes('\n')) {
        const lines = element.text.split('\n');
        const lineHeight = (element.lineHeight || 1.2) * fontSize;
        lines.forEach((line, i) => {
          ctx.fillText(line, 0, (height / 2) + (i * lineHeight));
        });
      } else {
        ctx.fillText(element.text || '', 0, height / 2);
      }
      break;
    }

    case 'image':
      if (element.src) {
        const img = new Image();
        await new Promise<void>((resolve, reject) => {
          img.onload = () => {
            ctx.drawImage(img, 0, 0, width, height);
            resolve();
          };
          img.onerror = reject;
          img.src = element.src;
        });
      }
      break;

    case 'rect':
    case 'rectangle':
      ctx.fillStyle = element.fill || '#000000';
      if (element.cornerRadius || element.rx) {
        const radius = element.cornerRadius || element.rx || 0;
        drawRoundedRect(ctx, 0, 0, width, height, radius);
        ctx.fill();
      } else {
        ctx.fillRect(0, 0, width, height);
      }
      break;

    case 'circle':
      ctx.beginPath();
      ctx.arc(width / 2, height / 2, Math.min(width, height) / 2, 0, 2 * Math.PI);
      ctx.fillStyle = element.fill || '#000000';
      ctx.fill();
      break;

    default:
      // Generic shape rendering
      ctx.fillStyle = element.fill || '#000000';
      ctx.fillRect(0, 0, width, height);
      break;
  }

  ctx.restore();
};

// Helper function to draw rounded rectangle
const drawRoundedRect = (
  ctx: CanvasRenderingContext2D,
  x: number,
  y: number,
  width: number,
  height: number,
  radius: number
): void => {
  ctx.beginPath();
  ctx.moveTo(x + radius, y);
  ctx.lineTo(x + width - radius, y);
  ctx.quadraticCurveTo(x + width, y, x + width, y + radius);
  ctx.lineTo(x + width, y + height - radius);
  ctx.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
  ctx.lineTo(x + radius, y + height);
  ctx.quadraticCurveTo(x, y + height, x, y + height - radius);
  ctx.lineTo(x, y + radius);
  ctx.quadraticCurveTo(x, y, x + radius, y);
  ctx.closePath();
};

// Helper function to add crop marks to PDF
const addCropMarks = (pdf: jsPDF, width: number, height: number, bleedSize: number): void => {
  const markLength = 5; // mm
  const markThickness = 0.1; // mm

  pdf.setLineWidth(markThickness);
  pdf.setDrawColor(0, 0, 0);

  // Corner marks
  const positions = [
    { x: bleedSize, y: bleedSize }, // Top-left
    { x: width - bleedSize, y: bleedSize }, // Top-right
    { x: bleedSize, y: height - bleedSize }, // Bottom-left
    { x: width - bleedSize, y: height - bleedSize }, // Bottom-right
  ];

  positions.forEach((pos, index) => {
    const isRight = index % 2 === 1;
    const isBottom = index >= 2;

    // Horizontal mark
    pdf.line(
      pos.x - (isRight ? markLength : 0),
      pos.y,
      pos.x + (isRight ? 0 : markLength),
      pos.y
    );

    // Vertical mark
    pdf.line(
      pos.x,
      pos.y - (isBottom ? 0 : markLength),
      pos.x,
      pos.y + (isBottom ? markLength : 0)
    );
  });
};

// Helper function to generate EPS content
const generateEPSContent = (templateData: TemplateData): string => {
  const width = templateData.canvas.width;
  const height = templateData.canvas.height;

  let eps = `%!PS-Adobe-3.0 EPSF-3.0
%%Creator: UniCard Template Builder
%%Title: ${templateData.metadata.name}
%%BoundingBox: 0 0 ${width} ${height}
%%EndComments

%%BeginProlog
%%EndProlog

%%Page: 1 1
gsave
`;

  // Add background
  if (templateData.background?.color) {
    eps += `0 0 ${width} ${height} rectfill\n`;
  }

  // Add elements (simplified)
  for (const element of templateData.elements) {
    if (element.type === 'text') {
      eps += `/${element.fontFamily || 'Arial'} findfont ${element.fontSize || 16} scalefont setfont\n`;
      eps += `${element.x || 0} ${height - (element.y || 0)} moveto\n`;
      eps += `(${element.text || ''}) show\n`;
    }
  }

  eps += `grestore
%%Trailer
%%EOF`;

  return eps;
};

// Main export function
export const exportTemplate = async (
  templateData: TemplateData,
  options: ExportOptions
): Promise<void> => {
  switch (options.format) {
    case 'json': {
      const jsonData = exportToJSON(templateData, options);
      const blob = new Blob([jsonData], { type: 'application/json' });
      const fileName = `${templateData.metadata.name.replace(/\s+/g, '_')}_Template.json`;
      saveAs(blob, fileName);
      break;
    }

    case 'pdf':
      await exportToPDF(templateData, options);
      break;

    case 'png':
      await exportToPNG(templateData, options);
      break;

    case 'eps':
      await exportToEPS(templateData, options);
      break;

    default:
      throw new Error(`Unsupported export format: ${options.format}`);
  }
};

// Bulk export to ZIP
export const bulkExportToZip = async (
  templateData: TemplateData,
  mappedFields: Record<string, string>,
  records: any[],
  onProgress?: (progress: number) => void
): Promise<void> => {
  const zip = new JSZip();
  const total = records.length;

  for (let i = 0; i < total; i++) {
    const record = records[i];
    const recordId = record.id || record.roll_number || `record_${i}`;

    // Create a deep copy of template data for this record
    const recordTemplateData = JSON.parse(JSON.stringify(templateData));

    // Process sides
    const sides = recordTemplateData.sides 
      ? [recordTemplateData.sides.front, recordTemplateData.sides.back] 
      : [recordTemplateData.elements];

    for (const elements of sides) {
      if (!elements) continue;
      for (const element of elements) {
        const fieldId = mappedFields[element.id];
        if (fieldId && record[fieldId]) {
          if (element.type === 'text') {
            element.text = String(record[fieldId]);
          } else if (element.type === 'image') {
            element.src = record[fieldId];
          }
        }

        // Also replace any manual placeholders like {{name}} in text
        if (element.type === 'text' && element.text) {
          element.text = replaceFieldsInText(element.text, record);
        }
      }
    }

    // Render front side
    const frontSide = recordTemplateData.sides 
      ? { elements: recordTemplateData.sides.front, bg: recordTemplateData.backgrounds?.front || recordTemplateData.background }
      : { elements: recordTemplateData.elements, bg: recordTemplateData.background };

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (ctx) {
      canvas.width = templateData.canvas.width;
      canvas.height = templateData.canvas.height;

      // Render BG
      if (frontSide.bg) {
        if (frontSide.bg.color) {
          ctx.fillStyle = frontSide.bg.color;
          ctx.fillRect(0, 0, canvas.width, canvas.height);
        }
        if (frontSide.bg.image) {
          const img = new Image();
          await new Promise<void>((resolve) => {
            img.onload = () => {
              ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
              resolve();
            };
            img.onerror = () => resolve();
            img.src = frontSide.bg!.image!;
          });
        }
      }

      // Render Elements
      for (const element of frontSide.elements) {
        await renderElementToCanvas(ctx, element, canvas.width, canvas.height);
      }

      const blob = await new Promise<Blob | null>(resolve => canvas.toBlob(resolve, 'image/png'));
      if (blob) {
        zip.file(`${recordId}_front.png`, blob);
      }
    }

    // Render back side if exists
    if (recordTemplateData.sides?.back) {
      const backSide = { elements: recordTemplateData.sides.back, bg: recordTemplateData.backgrounds?.back || recordTemplateData.background };
      const backCanvas = document.createElement('canvas');
      const backCtx = backCanvas.getContext('2d');
      if (backCtx) {
        backCanvas.width = templateData.canvas.width;
        backCanvas.height = templateData.canvas.height;

        if (backSide.bg) {
          if (backSide.bg.color) {
            backCtx.fillStyle = backSide.bg.color;
            backCtx.fillRect(0, 0, backCanvas.width, backCanvas.height);
          }
          if (backSide.bg.image) {
            const img = new Image();
            await new Promise<void>((resolve) => {
              img.onload = () => {
                backCtx.drawImage(img, 0, 0, backCanvas.width, backCanvas.height);
                resolve();
              };
              img.onerror = () => resolve();
              img.src = backSide.bg!.image!;
            });
          }
        }

        for (const element of backSide.elements) {
          await renderElementToCanvas(backCtx, element, backCanvas.width, backCanvas.height);
        }

        const backBlob = await new Promise<Blob | null>(resolve => backCanvas.toBlob(resolve, 'image/png'));
        if (backBlob) {
          zip.file(`${recordId}_back.png`, backBlob);
        }
      }
    }

    if (onProgress) onProgress(Math.round(((i + 1) / total) * 100));
  }

  const content = await zip.generateAsync({ type: 'blob' });
  saveAs(content, `${templateData.metadata.name.replace(/\s+/g, '_')}_Bulk.zip`);
};

import mammoth from 'mammoth';
import { DynamicField, PREDEFINED_FIELDS } from './dynamicFields';

// PSD import is handled dynamically to avoid build issues
let PSD: any = null;
try {
  import('psd').then(module => {
    PSD = module.default || module;
  }).catch(() => {
    // PSD library not available
  });
} catch {
  // PSD library init failed
}

export interface ImportedElement {
  id: string;
  type: 'text' | 'image' | 'shape' | 'background';
  x: number;
  y: number;
  width: number;
  height: number;
  rotation?: number;
  opacity?: number;
  visible?: boolean;
  locked?: boolean;
  zIndex?: number;
  properties: {
    // Text properties
    text?: string;
    fontSize?: number;
    fontFamily?: string;
    fontWeight?: string;
    fontStyle?: string;
    textAlign?: 'left' | 'center' | 'right';
    fill?: string;
    stroke?: string;
    strokeWidth?: number;
    // Image properties
    src?: string;
    cropX?: number;
    cropY?: number;
    cropWidth?: number;
    cropHeight?: number;
    // Shape properties
    shape?: 'rect' | 'circle' | 'polygon' | 'line';
    fillColor?: string;
    strokeColor?: string;
    cornerRadius?: number;
    // Effects
    shadow?: {
      color: string;
      blur: number;
      offsetX: number;
      offsetY: number;
    };
    filters?: {
      brightness?: number;
      contrast?: number;
      saturation?: number;
      blur?: number;
    };
    blendMode?: string;
  };
}

export interface ImportResult {
  success: boolean;
  elements: ImportedElement[];
  background?: {
    color?: string;
    image?: string;
  };
  canvas: {
    width: number;
    height: number;
  };
  errors?: string[];
  warnings?: string[];
}

// Word Document Importer
export const importWordDocument = async (file: File): Promise<ImportResult> => {
  try {
    const arrayBuffer = await file.arrayBuffer();
    const result = await mammoth.convertToHtml({ arrayBuffer });

    const elements: ImportedElement[] = [];
    const errors: string[] = [];
    const warnings: string[] = [];

    // Parse HTML content
    const parser = new DOMParser();
    const doc = parser.parseFromString(result.value, 'text/html');

    // Extract text elements
    const textElements = doc.querySelectorAll('p, h1, h2, h3, h4, h5, h6, span, div');
    let yOffset = 50;

    textElements.forEach((element, index) => {
      const text = element.textContent?.trim();
      if (text && text.length > 0) {
        const computedStyle = window.getComputedStyle(element as Element);

        elements.push({
          id: `text_${index}`,
          type: 'text',
          x: 50,
          y: yOffset,
          width: 300,
          height: 30,
          zIndex: index,
          properties: {
            text,
            fontSize: parseInt(computedStyle.fontSize) || 16,
            fontFamily: computedStyle.fontFamily || 'Arial',
            fontWeight: computedStyle.fontWeight || 'normal',
            fontStyle: computedStyle.fontStyle || 'normal',
            textAlign: (computedStyle.textAlign as any) || 'left',
            fill: computedStyle.color || '#000000',
          },
        });

        yOffset += 40;
      }
    });

    // Extract images
    const images = doc.querySelectorAll('img');
    images.forEach((img, index) => {
      const src = img.getAttribute('src');
      if (src) {
        elements.push({
          id: `image_${index}`,
          type: 'image',
          x: 50,
          y: yOffset,
          width: 200,
          height: 150,
          zIndex: textElements.length + index,
          properties: {
            src,
          },
        });
        yOffset += 160;
      }
    });

    return {
      success: true,
      elements,
      canvas: {
        width: 400,
        height: Math.max(yOffset + 50, 600),
      },
      errors: result.messages.filter(m => m.type === 'error').map(m => m.message),
      warnings: result.messages.filter(m => m.type === 'warning').map(m => m.message),
    };
  } catch {
    return {
      success: false,
      elements: [],
      canvas: { width: 400, height: 600 },
      errors: ['Failed to import Word document'],
    };
  }
};

// Photoshop Document Importer
export const importPhotoshopDocument = async (file: File): Promise<ImportResult> => {
  try {
    if (!PSD) {
      return {
        success: false,
        elements: [],
        canvas: { width: 400, height: 600 },
        errors: ['PSD library not available. Please use a different file format.'],
      };
    }

    const arrayBuffer = await file.arrayBuffer();
    const psd = PSD.fromBuffer(Buffer.from(arrayBuffer));
    psd.parse();

    const elements: ImportedElement[] = [];
    const errors: string[] = [];
    const warnings: string[] = [];

    const canvasWidth = psd.tree().get('width') || 400;
    const canvasHeight = psd.tree().get('height') || 600;

    // Extract background
    const background = psd.tree().get('background');
    let backgroundElement: ImportedElement | undefined;

    if (background) {
      const imageData = background.toPng();
      if (imageData) {
        backgroundElement = {
          id: 'background',
          type: 'background',
          x: 0,
          y: 0,
          width: canvasWidth,
          height: canvasHeight,
          zIndex: -1,
          properties: {
            src: imageData,
          },
        };
      }
    }

    // Extract layers
    const extractLayers = (node: any, parentX = 0, parentY = 0, zIndex = 0): void => {
      if (node.children) {
        node.children.forEach((child: any, index: number) => {
          const layerX = (child.get('left') || 0) + parentX;
          const layerY = (child.get('top') || 0) + parentY;
          const layerWidth = child.get('width') || 100;
          const layerHeight = child.get('height') || 100;
          const layerOpacity = (child.get('opacity') || 255) / 255;
          const layerVisible = child.get('visible') !== false;

          if (child.get('type') === 'layer' && layerVisible) {
            const imageData = child.toPng();
            if (imageData) {
              elements.push({
                id: `layer_${zIndex}_${index}`,
                type: 'image',
                x: layerX,
                y: layerY,
                width: layerWidth,
                height: layerHeight,
                opacity: layerOpacity,
                visible: layerVisible,
                zIndex: zIndex + index,
                properties: {
                  src: imageData,
                },
              });
            }
          } else if (child.children) {
            extractLayers(child, layerX, layerY, zIndex + index);
          }
        });
      }
    };

    extractLayers(psd.tree());

    return {
      success: true,
      elements: backgroundElement ? [backgroundElement, ...elements] : elements,
      background: backgroundElement ? { image: backgroundElement.properties.src } : undefined,
      canvas: {
        width: canvasWidth,
        height: canvasHeight,
      },
      errors,
      warnings,
    };
  } catch {
    return {
      success: false,
      elements: [],
      canvas: { width: 400, height: 600 },
      errors: ['Failed to import Photoshop document'],
    };
  }
};

// Image File Importer
export const importImageFile = async (file: File): Promise<ImportResult> => {
  try {
    const imageUrl = URL.createObjectURL(file);

    return new Promise((resolve) => {
      const img = new Image();
      img.onload = () => {
        const elements: ImportedElement[] = [];

        // Determine if this should be a background or element
        const isBackground = img.width > 800 || img.height > 600; // Large images as background

        if (isBackground) {
          elements.push({
            id: 'background_image',
            type: 'background',
            x: 0,
            y: 0,
            width: img.width,
            height: img.height,
            zIndex: -1,
            properties: {
              src: imageUrl,
            },
          });
        } else {
          elements.push({
            id: 'imported_image',
            type: 'image',
            x: 50,
            y: 50,
            width: Math.min(img.width, 300),
            height: Math.min(img.height, 300),
            zIndex: 0,
            properties: {
              src: imageUrl,
            },
          });
        }

        resolve({
          success: true,
          elements,
          background: isBackground ? { image: imageUrl } : undefined,
          canvas: {
            width: isBackground ? img.width : Math.max(img.width, 400),
            height: isBackground ? img.height : Math.max(img.height, 600),
          },
        });
      };

      img.onerror = () => {
        resolve({
          success: false,
          elements: [],
          canvas: { width: 400, height: 600 },
          errors: ['Failed to load image file'],
        });
      };

      img.src = imageUrl;
    });
  } catch {
    return {
      success: false,
      elements: [],
      canvas: { width: 400, height: 600 },
      errors: ['Failed to import image file'],
    };
  }
};

// PDF Document Importer
export const importPDFDocument = async (file: File): Promise<ImportResult> => {
  try {
    // Dynamically import pdfjs-dist to avoid SSR issues if any
    const pdfjsLib = await import('pdfjs-dist');
    pdfjsLib.GlobalWorkerOptions.workerSrc = `https://cdnjs.cloudflare.com/ajax/libs/pdf.js/${pdfjsLib.version}/pdf.worker.min.mjs`;

    const arrayBuffer = await file.arrayBuffer();
    const pdfDoc = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;

    const elements: ImportedElement[] = [];

    // For now, we'll import the first page as a background
    const pageNum = 1;
    const page = await pdfDoc.getPage(pageNum);
    const viewport = page.getViewport({ scale: 2.0 }); // Use 2x scale for better quality

    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');
    canvas.height = viewport.height;
    canvas.width = viewport.width;

    if (!context) {
      throw new Error('Could not get canvas context');
    }

    await page.render({
      canvasContext: context,
      viewport: viewport,
      canvas: canvas
    } as any).promise;

    const imageUrl = canvas.toDataURL('image/png');

    elements.push({
      id: 'pdf_background',
      type: 'background',
      x: 0,
      y: 0,
      width: viewport.width / 2.0,
      height: viewport.height / 2.0,
      zIndex: -1,
      properties: {
        src: imageUrl,
      },
    });

    return {
      success: true,
      elements,
      background: { image: imageUrl },
      canvas: {
        width: viewport.width / 2.0,
        height: viewport.height / 2.0,
      },
    };
  } catch {
    return {
      success: false,
      elements: [],
      canvas: { width: 400, height: 600 },
      errors: ['Failed to import PDF document'],
    };
  }
};

// Generic file importer that detects file type
export const importFile = async (file: File): Promise<ImportResult> => {
  const fileName = file.name.toLowerCase();

  if (fileName.endsWith('.docx')) {
    return importWordDocument(file);
  } else if (fileName.endsWith('.psd')) {
    return importPhotoshopDocument(file);
  } else if (fileName.endsWith('.pdf')) {
    return importPDFDocument(file);
  } else if (fileName.match(/\.(png|jpg|jpeg|gif|bmp|webp)$/)) {
    return importImageFile(file);
  } else {
    return {
      success: false,
      elements: [],
      canvas: { width: 400, height: 600 },
      errors: [`Unsupported file type: ${file.name}`],
    };
  }
};

// Convert imported elements to Konva format
export const convertToKonvaFormat = (elements: ImportedElement[]): any[] => {
  return elements.map(element => {
    const konvaElement: any = {
      id: element.id,
      x: element.x,
      y: element.y,
      width: element.width,
      height: element.height,
      rotation: element.rotation || 0,
      opacity: element.opacity || 1,
      visible: element.visible !== false,
      locked: element.locked || false,
      zIndex: element.zIndex || 0,
    };

    switch (element.type) {
      case 'text':
        return {
          ...konvaElement,
          type: 'text',
          text: element.properties.text || '',
          fontSize: element.properties.fontSize || 16,
          fontFamily: element.properties.fontFamily || 'Arial',
          fontStyle: element.properties.fontStyle || 'normal',
          fontWeight: element.properties.fontWeight || 'normal',
          textAlign: element.properties.textAlign || 'left',
          fill: element.properties.fill || '#000000',
          stroke: element.properties.stroke,
          strokeWidth: element.properties.strokeWidth || 0,
        };

      case 'image':
        return {
          ...konvaElement,
          type: 'image',
          src: element.properties.src,
          cropX: element.properties.cropX || 0,
          cropY: element.properties.cropY || 0,
          cropWidth: element.properties.cropWidth || element.width,
          cropHeight: element.properties.cropHeight || element.height,
        };

      case 'shape':
        return {
          ...konvaElement,
          type: element.properties.shape || 'rect',
          fill: element.properties.fillColor || '#000000',
          stroke: element.properties.strokeColor,
          strokeWidth: element.properties.strokeWidth || 0,
          cornerRadius: element.properties.cornerRadius || 0,
        };

      case 'background':
        return {
          ...konvaElement,
          type: 'background',
          src: element.properties.src,
        };

      default:
        return konvaElement;
    }
  });
};

// Convert imported elements to Fabric format
export const convertToFabricFormat = (elements: ImportedElement[]): any[] => {
  return elements.map(element => {
    const fabricElement: any = {
      id: element.id,
      left: element.x,
      top: element.y,
      width: element.width,
      height: element.height,
      angle: element.rotation || 0,
      opacity: element.opacity || 1,
      visible: element.visible !== false,
      selectable: !element.locked,
      evented: !element.locked,
    };

    switch (element.type) {
      case 'text':
        return {
          ...fabricElement,
          type: 'text',
          text: element.properties.text || '',
          fontSize: element.properties.fontSize || 16,
          fontFamily: element.properties.fontFamily || 'Arial',
          fontStyle: element.properties.fontStyle || 'normal',
          fontWeight: element.properties.fontWeight || 'normal',
          textAlign: element.properties.textAlign || 'left',
          fill: element.properties.fill || '#000000',
          stroke: element.properties.stroke,
          strokeWidth: element.properties.strokeWidth || 0,
        };

      case 'image':
        return {
          ...fabricElement,
          type: 'image',
          src: element.properties.src,
          cropX: element.properties.cropX || 0,
          cropY: element.properties.cropY || 0,
          cropWidth: element.properties.cropWidth || element.width,
          cropHeight: element.properties.cropHeight || element.height,
        };

      case 'shape':
        return {
          ...fabricElement,
          type: element.properties.shape || 'rect',
          fill: element.properties.fillColor || '#000000',
          stroke: element.properties.strokeColor,
          strokeWidth: element.properties.strokeWidth || 0,
          rx: element.properties.cornerRadius || 0,
          ry: element.properties.cornerRadius || 0,
        };

      case 'background':
        return {
          ...fabricElement,
          type: 'background',
          src: element.properties.src,
        };

      default:
        return fabricElement;
    }
  });
};
